def safe_json_response(response):
    """Return JSON or a readable error without exposing credentials."""
    try:
        payload = response.json()
    except Exception:
        payload = {"message": response.text[:500]}

    if response.ok:
        return payload

    message = (
        payload.get("message")
        or payload.get("error_description")
        or payload.get("error")
        or payload.get("errors")
        or f"HTTP {response.status_code}"
    )
    raise RuntimeError(str(message))


def woocommerce_is_configured():
    """Return True when all required WooCommerce secrets are configured."""
    return bool(
        WOOCOMMERCE_STORE_URL
        and WOOCOMMERCE_CONSUMER_KEY
        and WOOCOMMERCE_CONSUMER_SECRET
    )


def woocommerce_api_request(endpoint, params=None):
    """
    Make a read-only WooCommerce REST API request.

    Only GET requests are implemented, so this integration cannot modify,
    cancel, refund, create, or delete WooCommerce orders.
    """
    if not woocommerce_is_configured():
        raise RuntimeError("WooCommerce order access is not configured.")

    clean_endpoint = str(endpoint or "").strip().lstrip("/")
    if not clean_endpoint:
        raise RuntimeError("WooCommerce API endpoint is missing.")

    response = http_session.get(
        f"{WOOCOMMERCE_STORE_URL}/wp-json/wc/v3/{clean_endpoint}",
        params=params or {},
        auth=(
            WOOCOMMERCE_CONSUMER_KEY,
            WOOCOMMERCE_CONSUMER_SECRET,
        ),
        headers={
            "Accept": "application/json",
            "User-Agent": "AutoTecPro-AI/1.0",
        },
        timeout=LIVE_HTTP_TIMEOUT,
    )
    return safe_json_response(response)


def _clean_woocommerce_meta_text(value):
    """Convert WooCommerce metadata labels and values to readable plain text."""
    if value is None:
        return ""

    if isinstance(value, (dict, list, tuple)):
        try:
            value = json.dumps(value, ensure_ascii=False, default=str)
        except Exception:
            value = str(value)

    cleaned = html.unescape(str(value))
    cleaned = re.sub(r"<[^>]+>", " ", cleaned)
    cleaned = re.sub(r"\s+", " ", cleaned).strip()
    return cleaned


def _friendly_woocommerce_meta_label(label):
    """Shorten common product-option questions into support-friendly labels."""
    cleaned = _clean_woocommerce_meta_text(label)
    lowered = cleaned.lower()

    label_rules = [
        (
            ("which year", "year is your truck", "vehicle year", "truck year"),
            "Vehicle Year",
        ),
        (
            ("microsoft sync", "sync version", "original sync"),
            "Original Microsoft SYNC Version",
        ),
        (
            ("climate control", "a/c system", "ac system"),
            "Climate Control",
        ),
        (
            ("left-hand drive", "right-hand drive", "drive side", "steering side"),
            "Drive Side",
        ),
        (
            ("hardware version", "select the hardware", "ram", "storage"),
            "Hardware Version",
        ),
        (
            ("dash camera", "dvr", "usb dash camera"),
            "DVR / Dash Camera",
        ),
        (
            ("dashboard picture", "original dashboard", "picture required"),
            "Original Dashboard Picture",
        ),
    ]

    for keywords, friendly_label in label_rules:
        if any(keyword in lowered for keyword in keywords):
            return friendly_label

    cleaned = cleaned.strip(" :-")
    return cleaned or "Product Option"


def _sanitize_woocommerce_item_metadata(metadata, technical_view=False):
    """
    Return visible customer-selected WooCommerce product options.

    Hidden/internal keys are excluded. Technical Support also excludes
    metadata that appears to contain pricing or payment information.
    """
    clean_metadata = []

    financial_terms = {
        "price", "cost", "subtotal", "total", "tax", "fee",
        "discount", "coupon", "payment", "currency", "refund amount",
    }

    for entry in metadata or []:
        if not isinstance(entry, dict):
            continue

        raw_key = str(entry.get("key") or "").strip()
        if not raw_key or raw_key.startswith("_"):
            continue

        raw_label = entry.get("display_key") or raw_key
        raw_value = (
            entry.get("display_value")
            if entry.get("display_value") not in (None, "")
            else entry.get("value")
        )

        # Preserve the exact visible WooCommerce order-page label.
        label = _clean_woocommerce_meta_text(raw_label).strip(" :-")
        if not label:
            label = "Product Option"
        value = _clean_woocommerce_meta_text(raw_value)

        if not value:
            continue

        if technical_view:
            searchable = f"{raw_key} {label}".lower()
            if any(term in searchable for term in financial_terms):
                continue

        clean_metadata.append({
            "label": label,
            "value": value,
        })

    return clean_metadata


def sanitize_woocommerce_order(order, access_level="sales"):
    """
    Return a WooCommerce order with fields appropriate for the workspace.

    Technical Support receives order, customer, shipping, product, SKU,
    quantity, status, notes, and selected product options, but no financial
    fields. Sales & Marketing keeps the existing full commercial order view.
    """
    if not isinstance(order, dict):
        return {}

    technical_view = str(access_level or "").strip().lower() == "technical"
    billing = order.get("billing") or {}
    shipping = order.get("shipping") or {}

    line_items = []
    for item in order.get("line_items") or []:
        if not isinstance(item, dict):
            continue

        clean_item = {
            "product_id": item.get("product_id"),
            "variation_id": item.get("variation_id"),
            "name": item.get("name"),
            "sku": item.get("sku"),
            "quantity": item.get("quantity"),
            "selected_options": _sanitize_woocommerce_item_metadata(
                item.get("meta_data") or [],
                technical_view=technical_view,
            ),
        }

        if not technical_view:
            clean_item.update({
                "subtotal": item.get("subtotal"),
                "total": item.get("total"),
                "tax": item.get("total_tax"),
            })

        line_items.append(clean_item)

    shipping_lines = []
    for item in order.get("shipping_lines") or []:
        if not isinstance(item, dict):
            continue

        clean_shipping = {
            "method_title": item.get("method_title"),
            "method_id": item.get("method_id"),
        }

        if not technical_view:
            clean_shipping["total"] = item.get("total")

        shipping_lines.append(clean_shipping)

    refunds = []
    for item in order.get("refunds") or []:
        if not isinstance(item, dict):
            continue

        clean_refund = {
            "id": item.get("id"),
            "reason": item.get("reason"),
        }

        if not technical_view:
            clean_refund["total"] = item.get("total")

        refunds.append(clean_refund)

    clean_order = {
        "id": order.get("id"),
        "number": order.get("number"),
        "status": order.get("status"),
        "date_created": order.get("date_created"),
        "date_modified": order.get("date_modified"),
        "date_paid": order.get("date_paid"),
        "date_completed": order.get("date_completed"),
        "customer_id": order.get("customer_id"),
        "customer_note": order.get("customer_note"),
        "billing": {
            "first_name": billing.get("first_name"),
            "last_name": billing.get("last_name"),
            "company": billing.get("company"),
            "address_1": billing.get("address_1"),
            "address_2": billing.get("address_2"),
            "city": billing.get("city"),
            "state": billing.get("state"),
            "postcode": billing.get("postcode"),
            "country": billing.get("country"),
            "email": billing.get("email"),
            "phone": billing.get("phone"),
        },
        "shipping": {
            "first_name": shipping.get("first_name"),
            "last_name": shipping.get("last_name"),
            "company": shipping.get("company"),
            "address_1": shipping.get("address_1"),
            "address_2": shipping.get("address_2"),
            "city": shipping.get("city"),
            "state": shipping.get("state"),
            "postcode": shipping.get("postcode"),
            "country": shipping.get("country"),
            "phone": shipping.get("phone"),
        },
        "line_items": line_items,
        "shipping_lines": shipping_lines,
        "refunds": refunds,
        "refund_status": (
            "refunded"
            if str(order.get("status") or "").lower() == "refunded"
            else ("partial_or_recorded" if refunds else "none")
        ),
    }

    if not technical_view:
        clean_order.update({
            "currency": order.get("currency"),
            "payment_method_title": order.get("payment_method_title"),
            "shipping_total": order.get("shipping_total"),
            "discount_total": order.get("discount_total"),
            "total_tax": order.get("total_tax"),
            "total": order.get("total"),
            "prices_include_tax": order.get("prices_include_tax"),
            "coupon_lines": order.get("coupon_lines") or [],
        })

    return clean_order


def get_woocommerce_order_by_id(order_id, access_level="sales"):
    """Retrieve one WooCommerce order using its numeric internal ID."""
    clean_order_id = str(order_id or "").strip()
    if not re.fullmatch(r"\d{1,12}", clean_order_id):
        raise RuntimeError("Invalid WooCommerce order ID.")

    order = woocommerce_api_request(f"orders/{clean_order_id}")
    return {
        "configured": True,
        "source": "WooCommerce REST API",
        "query_type": "order_id",
        "access_level": access_level,
        "order": sanitize_woocommerce_order(order, access_level),
    }


def search_woocommerce_order_number(order_number, access_level="sales"):
    """Find an order by internal ID or displayed WooCommerce order number."""
    clean_number = re.sub(r"[^0-9]", "", str(order_number or ""))
    if not clean_number:
        raise RuntimeError("A valid order number was not provided.")

    try:
        direct_result = get_woocommerce_order_by_id(
            clean_number,
            access_level=access_level,
        )
        order = direct_result.get("order") or {}
        if str(order.get("number") or order.get("id") or "") == clean_number:
            return direct_result
    except Exception:
        pass

    orders = woocommerce_api_request(
        "orders",
        params={
            "search": clean_number,
            "per_page": 20,
            "orderby": "date",
            "order": "desc",
        },
    )

    matches = []
    for order in orders if isinstance(orders, list) else []:
        displayed_number = str(order.get("number") or "")
        internal_id = str(order.get("id") or "")
        if clean_number in {displayed_number, internal_id}:
            matches.append(
                sanitize_woocommerce_order(order, access_level)
            )

    return {
        "configured": True,
        "source": "WooCommerce REST API",
        "query_type": "order_number",
        "access_level": access_level,
        "searched_order_number": clean_number,
        "count": len(matches),
        "orders": matches,
    }


def search_multiple_woocommerce_orders(order_numbers, access_level="sales"):
    """
    Retrieve up to 10 unique WooCommerce orders in the supplied order.

    Each order is looked up independently. One missing or invalid order does not
    prevent the remaining valid orders from being returned.
    """
    clean_numbers = []
    seen = set()

    for raw_number in order_numbers or []:
        clean_number = re.sub(r"[^0-9]", "", str(raw_number or ""))
        if not re.fullmatch(r"\d{4,12}", clean_number):
            continue
        if clean_number in seen:
            continue
        seen.add(clean_number)
        clean_numbers.append(clean_number)
        if len(clean_numbers) >= 10:
            break

    if not clean_numbers:
        raise RuntimeError("No valid WooCommerce order numbers were provided.")

    combined_orders = []
    results = []
    not_found = []
    errors = []

    for clean_number in clean_numbers:
        try:
            result = search_woocommerce_order_number(
                clean_number,
                access_level=access_level,
            )
            result_orders = _woocommerce_orders_from_live_data(result)

            if result_orders:
                combined_orders.extend(result_orders)
                results.append({
                    "order_number": clean_number,
                    "found": True,
                    "count": len(result_orders),
                })
            else:
                not_found.append(clean_number)
                results.append({
                    "order_number": clean_number,
                    "found": False,
                    "count": 0,
                })
        except Exception as error:
            errors.append({
                "order_number": clean_number,
                "error": str(error),
            })
            results.append({
                "order_number": clean_number,
                "found": False,
                "count": 0,
                "error": str(error),
            })

    return {
        "configured": True,
        "source": "WooCommerce REST API",
        "query_type": "multiple_orders",
        "access_level": access_level,
        "searched_order_numbers": clean_numbers,
        "requested_count": len(clean_numbers),
        "found_count": len(combined_orders),
        "count": len(combined_orders),
        "orders": combined_orders,
        "results": results,
        "not_found": not_found,
        "errors": errors,
        "read_only": True,
    }


def search_woocommerce_orders_by_email(email_address, access_level="sales"):
    """Search recent orders by exact billing email address."""
    email_value = str(email_address or "").strip().lower()
    if not re.fullmatch(r"[^@\s]+@[^@\s]+\.[^@\s]+", email_value):
        raise RuntimeError("A valid customer email address is required.")

    orders = woocommerce_api_request(
        "orders",
        params={
            "search": email_value,
            "per_page": 20,
            "orderby": "date",
            "order": "desc",
        },
    )

    matches = []
    for order in orders if isinstance(orders, list) else []:
        order_email = str(
            (order.get("billing") or {}).get("email") or ""
        ).strip().lower()
        if order_email == email_value:
            matches.append(
                sanitize_woocommerce_order(order, access_level)
            )

    return {
        "configured": True,
        "source": "WooCommerce REST API",
        "query_type": "customer_email",
        "access_level": access_level,
        "searched_email": email_value,
        "count": len(matches),
        "orders": matches,
    }


def get_recent_woocommerce_orders(limit=10, status="any", access_level="sales"):
    """Retrieve a small list of recent WooCommerce orders."""
    try:
        clean_limit = int(limit)
    except (TypeError, ValueError):
        clean_limit = 10
    clean_limit = max(1, min(clean_limit, 20))

    allowed_statuses = {
        "any", "pending", "processing", "on-hold", "completed",
        "cancelled", "refunded", "failed", "trash",
    }
    clean_status = str(status or "any").strip().lower()
    if clean_status not in allowed_statuses:
        clean_status = "any"

    params = {
        "per_page": clean_limit,
        "orderby": "date",
        "order": "desc",
    }
    if clean_status != "any":
        params["status"] = clean_status

    orders = woocommerce_api_request("orders", params=params)
    clean_orders = [
        sanitize_woocommerce_order(order, access_level)
        for order in orders if isinstance(order, dict)
    ] if isinstance(orders, list) else []

    return {
        "configured": True,
        "source": "WooCommerce REST API",
        "query_type": "recent_orders",
        "access_level": access_level,
        "status_filter": clean_status,
        "count": len(clean_orders),
        "orders": clean_orders,
    }


def get_woocommerce_order_notes(order_id):
    """Retrieve notes associated with one WooCommerce order."""
    clean_order_id = str(order_id or "").strip()
    if not re.fullmatch(r"\d{1,12}", clean_order_id):
        raise RuntimeError("Invalid WooCommerce order ID.")

    notes = woocommerce_api_request(
        f"orders/{clean_order_id}/notes",
        params={"per_page": 50},
    )

    clean_notes = []
    for note in notes if isinstance(notes, list) else []:
        if not isinstance(note, dict):
            continue
        clean_notes.append({
            "id": note.get("id"),
            "date_created": note.get("date_created"),
            "note": note.get("note"),
            "customer_note": note.get("customer_note"),
            "added_by_user": note.get("added_by_user"),
        })

    return {
        "configured": True,
        "source": "WooCommerce REST API",
        "query_type": "order_notes",
        "order_id": clean_order_id,
        "count": len(clean_notes),
        "notes": clean_notes,
    }



WOOCOMMERCE_ANALYTICS_INCLUDED_STATUSES = {
    "processing",
    "on-hold",
    "completed",
}


def _safe_decimal(value):
    """Convert WooCommerce numeric text to float without raising."""
    try:
        return float(str(value or "0").replace(",", "").strip())
    except (TypeError, ValueError):
        return 0.0


def _toronto_timezone():
    """Return the business timezone used for WooCommerce analytics."""
    try:
        return ZoneInfo("America/Toronto")
    except Exception:
        return timezone.utc


def _local_day_range_utc(year, month, day):
    """Return one Toronto calendar day as an exclusive UTC range."""
    tz = _toronto_timezone()
    start_local = datetime(int(year), int(month), int(day), tzinfo=tz)
    end_local = start_local + timedelta(days=1)
    return start_local.astimezone(timezone.utc), end_local.astimezone(timezone.utc)


def _local_month_range_utc(year, month):
    """Return one Toronto calendar month as an exclusive UTC range."""
    tz = _toronto_timezone()
    start_local = datetime(int(year), int(month), 1, tzinfo=tz)
    if int(month) == 12:
        end_local = datetime(int(year) + 1, 1, 1, tzinfo=tz)
    else:
        end_local = datetime(int(year), int(month) + 1, 1, tzinfo=tz)
    return start_local.astimezone(timezone.utc), end_local.astimezone(timezone.utc)


def _local_year_range_utc(year):
    """Return one Toronto calendar year as an exclusive UTC range."""
    tz = _toronto_timezone()
    start_local = datetime(int(year), 1, 1, tzinfo=tz)
    end_local = datetime(int(year) + 1, 1, 1, tzinfo=tz)
    return start_local.astimezone(timezone.utc), end_local.astimezone(timezone.utc)


def _safe_calendar_date(year, month, day):
    try:
        return datetime(int(year), int(month), int(day)).date()
    except (TypeError, ValueError):
        return None


def _resolve_analytics_date_range(prompt):
    """
    Resolve exact dates, relative dates, ranges, months, and years.

    Calendar boundaries use America/Toronto and are converted to UTC because
    WooCommerce analytics requests use dates_are_gmt=true.
    """
    value = re.sub(r"\s+", " ", str(prompt or "")).strip()
    lower = value.lower()
    tz = _toronto_timezone()
    now_local = datetime.now(tz)

    month_names = {
        "january": 1, "jan": 1,
        "february": 2, "feb": 2,
        "march": 3, "mar": 3,
        "april": 4, "apr": 4,
        "may": 5,
        "june": 6, "jun": 6,
        "july": 7, "jul": 7,
        "august": 8, "aug": 8,
        "september": 9, "sep": 9, "sept": 9,
        "october": 10, "oct": 10,
        "november": 11, "nov": 11,
        "december": 12, "dec": 12,
    }
    month_pattern = "|".join(sorted(month_names, key=len, reverse=True))

    if re.search(r"\btoday\b", lower):
        d = now_local.date()
        start, end = _local_day_range_utc(d.year, d.month, d.day)
        return start, end, d.strftime("%B %-d, %Y") if os.name != "nt" else d.strftime("%B %#d, %Y")

    if re.search(r"\byesterday\b", lower):
        d = now_local.date() - timedelta(days=1)
        start, end = _local_day_range_utc(d.year, d.month, d.day)
        return start, end, d.strftime("%B %-d, %Y") if os.name != "nt" else d.strftime("%B %#d, %Y")

    # ISO or slash date range.
    range_match = re.search(
        r"\b(20\d{2})[-/](\d{1,2})[-/](\d{1,2})\s+(?:to|through|until|-)\s+"
        r"(20\d{2})[-/](\d{1,2})[-/](\d{1,2})\b",
        lower,
    )
    if range_match:
        d1 = _safe_calendar_date(*range_match.groups()[:3])
        d2 = _safe_calendar_date(*range_match.groups()[3:])
        if d1 and d2:
            if d2 < d1:
                d1, d2 = d2, d1
            start, _ = _local_day_range_utc(d1.year, d1.month, d1.day)
            _, end = _local_day_range_utc(d2.year, d2.month, d2.day)
            return start, end, f"{d1.isoformat()} to {d2.isoformat()}"

    # Named-date range, e.g. July 1, 2026 to July 19, 2026.
    named_range = re.search(
        rf"\b({month_pattern})\s+(\d{{1,2}})(?:st|nd|rd|th)?(?:,)?\s+(20\d{{2}})"
        rf"\s+(?:to|through|until|-)\s+({month_pattern})\s+(\d{{1,2}})(?:st|nd|rd|th)?(?:,)?\s+(20\d{{2}})\b",
        lower,
    )
    if named_range:
        d1 = _safe_calendar_date(named_range.group(3), month_names[named_range.group(1)], named_range.group(2))
        d2 = _safe_calendar_date(named_range.group(6), month_names[named_range.group(4)], named_range.group(5))
        if d1 and d2:
            if d2 < d1:
                d1, d2 = d2, d1
            start, _ = _local_day_range_utc(d1.year, d1.month, d1.day)
            _, end = _local_day_range_utc(d2.year, d2.month, d2.day)
            return start, end, f"{d1.isoformat()} to {d2.isoformat()}"

    # One ISO/slash date.
    iso_single = re.search(r"\b(20\d{2})[-/](\d{1,2})[-/](\d{1,2})\b", lower)
    if iso_single:
        d = _safe_calendar_date(*iso_single.groups())
        if d:
            start, end = _local_day_range_utc(d.year, d.month, d.day)
            return start, end, d.strftime("%B %-d, %Y") if os.name != "nt" else d.strftime("%B %#d, %Y")

    # US numeric date, e.g. 07/19/2026.
    numeric_single = re.search(r"(?<!\d)(\d{1,2})/(\d{1,2})/(20\d{2})(?!\d)", lower)
    if numeric_single:
        d = _safe_calendar_date(numeric_single.group(3), numeric_single.group(1), numeric_single.group(2))
        if d:
            start, end = _local_day_range_utc(d.year, d.month, d.day)
            return start, end, d.strftime("%B %-d, %Y") if os.name != "nt" else d.strftime("%B %#d, %Y")

    # Named single day. A missing year uses the current Toronto year, or the
    # previous year when the requested day is still in the future.
    named_single = re.search(
        rf"\b({month_pattern})\s+(\d{{1,2}})(?:st|nd|rd|th)?(?:,)?(?:\s+(20\d{{2}}))?\b",
        lower,
    )
    if named_single:
        month = month_names[named_single.group(1)]
        day = int(named_single.group(2))
        year = int(named_single.group(3)) if named_single.group(3) else now_local.year
        d = _safe_calendar_date(year, month, day)
        if d and not named_single.group(3) and d > now_local.date():
            d = _safe_calendar_date(year - 1, month, day)
        if d:
            start, end = _local_day_range_utc(d.year, d.month, d.day)
            return start, end, d.strftime("%B %-d, %Y") if os.name != "nt" else d.strftime("%B %#d, %Y")

    if "this month" in lower:
        start, end = _local_month_range_utc(now_local.year, now_local.month)
        return start, end, now_local.strftime("%B %Y")

    if "last month" in lower or "previous month" in lower:
        year, month = (now_local.year - 1, 12) if now_local.month == 1 else (now_local.year, now_local.month - 1)
        start, end = _local_month_range_utc(year, month)
        return start, end, datetime(year, month, 1).strftime("%B %Y")

    month_match = re.search(rf"\b({month_pattern})\b(?:\s+(20\d{{2}}))?", lower)
    if month_match:
        month = month_names[month_match.group(1)]
        year = int(month_match.group(2)) if month_match.group(2) else now_local.year
        if not month_match.group(2) and month > now_local.month:
            year -= 1
        start, end = _local_month_range_utc(year, month)
        return start, end, datetime(year, month, 1).strftime("%B %Y")

    year_match = re.search(r"\b(20\d{2})\b", lower)
    if year_match:
        year = int(year_match.group(1))
        start, end = _local_year_range_utc(year)
        return start, end, str(year)

    start, end = _local_month_range_utc(now_local.year, now_local.month)
    return start, end, now_local.strftime("%B %Y")


def _extract_analytics_product_query(prompt):
    """Extract a real product filter without confusing dates or WooCommerce wording."""
    value = re.sub(r"\s+", " ", str(prompt or "")).strip()
    lower = value.lower()

    # Explicitly labelled product references are always respected.
    labelled = re.search(
        r"\b(?:product|sku|model|item)\s*(?:id|number|#)?\s*[:#-]?\s*"
        r"([a-z0-9][a-z0-9._/-]{1,40})\b",
        lower,
    )
    if labelled:
        candidate = labelled.group(1).strip()
        if candidate not in {"sales", "order", "orders", "revenue", "woocommerce"}:
            return candidate

    # General order/revenue questions must aggregate every line item.
    generic_phrases = (
        "what's the sales", "what is the sales", "how much sales",
        "total sales", "sales today", "sales yesterday",
        "how many orders", "orders did we receive", "orders received",
        "order count", "total orders", "revenue today", "revenue yesterday",
        "woocommerce sales", "sales for woocommerce", "sales from woocommerce",
        "woocommerce revenue", "revenue for woocommerce",
    )
    if any(phrase in lower for phrase in generic_phrases):
        return ""

    patterns = [
        r"\bhow many\s+(.+?)\s+(?:units?\s+)?(?:sold|were sold|did we sell)\b",
        r"\b(?:sales|revenue|orders?)\s+(?:for|of)\s+(.+?)\s+"
        r"(?:in|during|on|this month|last month|today|yesterday|$)",
        r"\bshow\s+(?:me\s+)?(?:all\s+)?(?:sales|orders?)\s+"
        r"(?:for|containing)\s+(.+?)\s+(?:in|during|on|$)",
    ]
    for pattern in patterns:
        match = re.search(pattern, lower, flags=re.IGNORECASE)
        if not match:
            continue
        candidate = match.group(1).strip(" ?.,")
        candidate = re.sub(
            r"\b(?:today|yesterday|this month|last month|previous month|woocommerce)\b.*$",
            "",
            candidate,
        ).strip(" ?.,")
        if candidate and candidate not in {"woocommerce", "all", "all products", "orders", "sales", "revenue"}:
            return candidate

    # Numeric shorthand is accepted only when it is clearly attached to a
    # product/SKU context, preventing July 17 from becoming product 17.
    numeric = re.search(
        r"\b(?:product|sku|model|item)\s*(?:id|number|#)?\s*[:#-]?\s*(\d{2,10})\b",
        lower,
    )
    return numeric.group(1) if numeric else ""

def _woocommerce_analytics_allowed(selected_assistant=None):
    """Allow analytics only in Sales and Marketing workspaces."""
    active = (
        selected_assistant
        or st.session_state.get("current_assistant")
        or ""
    )
    normalized = re.sub(r"\s+", " ", str(active)).strip().lower()
    normalized = re.sub(r"^[^a-z0-9]+", "", normalized).strip()
    return normalized in {
        "sales",
        "marketing",
        "sales & marketing",
        "sales and marketing",
    }


def _normalize_analytics_product_text(value):
    """Normalize product names/SKUs so hyphens, spaces, and punctuation are equivalent."""
    cleaned = html.unescape(str(value or "")).casefold()
    cleaned = re.sub(r"[^a-z0-9]+", " ", cleaned)
    spaced = re.sub(r"\s+", " ", cleaned).strip()
    compact = re.sub(r"[^a-z0-9]+", "", spaced)
    return spaced, compact


def _analytics_item_search_values(item):
    """Collect searchable WooCommerce line-item values, including variations/options."""
    values = [
        item.get("product_id"),
        item.get("variation_id"),
        item.get("sku"),
        item.get("name"),
    ]

    # Many AutoTecPro model numbers are stored as variation attributes or visible
    # checkout options instead of in the parent product title/SKU. Include both
    # metadata labels and values so queries such as 732, 836, and 836-Pro match
    # the exact model selected by the customer.
    for entry in item.get("meta_data") or []:
        if not isinstance(entry, dict):
            continue
        key = entry.get("display_key") or entry.get("key")
        value = (
            entry.get("display_value")
            if entry.get("display_value") not in (None, "")
            else entry.get("value")
        )
        if key not in (None, ""):
            values.append(key)
        if value not in (None, ""):
            if isinstance(value, (dict, list, tuple)):
                try:
                    value = json.dumps(value, ensure_ascii=False, default=str)
                except Exception:
                    value = str(value)
            values.append(value)

    return values


def _analytics_item_matches(item, product_query):
    """Match a natural model/SKU query across product and variation metadata."""
    query = str(product_query or "").strip()
    if not query:
        return True

    query_spaced, query_compact = _normalize_analytics_product_text(query)
    if not query_compact:
        return True

    normalized_fields = [
        _normalize_analytics_product_text(value)
        for value in _analytics_item_search_values(item)
        if value not in (None, "")
    ]

    if any(
        query_spaced == field_spaced or query_compact == field_compact
        for field_spaced, field_compact in normalized_fields
    ):
        return True

    # Match model codes regardless of punctuation: 836-Pro, 836 Pro, and 836PRO.
    if any(
        query_compact in field_compact
        for _, field_compact in normalized_fields
        if field_compact
    ):
        return True

    haystack_spaced = " ".join(
        field_spaced for field_spaced, _ in normalized_fields if field_spaced
    )
    haystack_compact = " ".join(
        field_compact for _, field_compact in normalized_fields if field_compact
    )
    query_tokens = [
        token for token in query_spaced.split()
        if token not in {"the", "product", "model", "item", "sku"}
    ]
    return bool(query_tokens) and all(
        token in haystack_spaced or token in haystack_compact
        for token in query_tokens
    )


@st.cache_data(ttl=300, max_entries=64, show_spinner=False)
def _fetch_woocommerce_orders_for_analytics(
    after_iso,
    before_iso,
    max_pages=100,
):
    """
    Retrieve all orders for one date range using WooCommerce pagination.

    This function remains read-only and calls only woocommerce_api_request(),
    whose WooCommerce implementation uses http_session.get().
    """
    orders = []
    page = 1
    max_pages = max(1, min(int(max_pages or 100), 100))

    while page <= max_pages:
        batch = woocommerce_api_request(
            "orders",
            params={
                "after": after_iso,
                "before": before_iso,
                "dates_are_gmt": "true",
                "per_page": 100,
                "page": page,
                "orderby": "date",
                "order": "asc",
                "status": "any",
            },
        )
        if not isinstance(batch, list):
            break

        orders.extend(order for order in batch if isinstance(order, dict))
        if len(batch) < 100:
            break
        page += 1

    return orders


def analyze_woocommerce_sales(
    product_query,
    start_iso,
    end_iso,
    period_label,
    include_top_products=False,
    top_limit=10,
):
    """Aggregate units, orders, and gross line-item revenue from live orders."""
    orders = _fetch_woocommerce_orders_for_analytics(start_iso, end_iso)

    matched_units = 0
    matched_order_ids = set()
    matched_revenue = 0.0
    currencies = set()
    product_breakdown = {}

    included_orders = 0
    excluded_status_counts = {}

    for order in orders:
        status = str(order.get("status") or "").strip().lower()
        if status not in WOOCOMMERCE_ANALYTICS_INCLUDED_STATUSES:
            excluded_status_counts[status or "unknown"] = (
                excluded_status_counts.get(status or "unknown", 0) + 1
            )
            continue

        included_orders += 1
        currency = str(order.get("currency") or "").strip().upper()
        if currency:
            currencies.add(currency)

        order_matched = False
        for item in order.get("line_items") or []:
            if not isinstance(item, dict):
                continue

            if not _analytics_item_matches(item, product_query):
                continue

            quantity = int(item.get("quantity") or 0)
            line_total = _safe_decimal(item.get("total"))
            matched_units += quantity
            matched_revenue += line_total
            order_matched = True

            key = (
                str(item.get("sku") or "").strip()
                or str(item.get("product_id") or "").strip()
                or str(item.get("name") or "Unknown product").strip()
            )
            record = product_breakdown.setdefault(
                key,
                {
                    "name": item.get("name"),
                    "sku": item.get("sku"),
                    "product_id": item.get("product_id"),
                    "variation_id": item.get("variation_id"),
                    "units": 0,
                    "orders": set(),
                    "revenue": 0.0,
                },
            )
            record["units"] += quantity
            record["orders"].add(str(order.get("id") or order.get("number")))
            record["revenue"] += line_total

        if order_matched:
            matched_order_ids.add(str(order.get("id") or order.get("number")))

    ranked_products = []
    for record in product_breakdown.values():
        ranked_products.append({
            "name": record["name"],
            "sku": record["sku"],
            "product_id": record["product_id"],
            "variation_id": record["variation_id"],
            "units": record["units"],
            "order_count": len(record["orders"]),
            "revenue": round(record["revenue"], 2),
        })
    ranked_products.sort(
        key=lambda record: (record["units"], record["revenue"]),
        reverse=True,
    )

    try:
        clean_top_limit = max(1, min(int(top_limit or 10), 25))
    except (TypeError, ValueError):
        clean_top_limit = 10

    return {
        "configured": True,
        "source": "WooCommerce REST API",
        "query_type": "sales_analytics",
        "read_only": True,
        "period": period_label,
        "after": start_iso,
        "before": end_iso,
        "product_query": product_query or "all products",
        "included_statuses": sorted(WOOCOMMERCE_ANALYTICS_INCLUDED_STATUSES),
        "orders_retrieved": len(orders),
        "orders_included": included_orders,
        "excluded_status_counts": excluded_status_counts,
        "matched_order_count": len(matched_order_ids),
        "units_sold": matched_units,
        "gross_line_item_revenue": round(matched_revenue, 2),
        "currencies": sorted(currencies),
        "top_products": (
            ranked_products[:clean_top_limit]
            if include_top_products or not product_query
            else ranked_products[:10]
        ),
        "calculation_note": (
            "Counts processing, on-hold, and completed orders. "
            "Cancelled, failed, pending, trashed, and fully refunded orders are "
            "excluded. Revenue is based on WooCommerce line-item totals and is "
            "not a net-profit calculation."
        ),
    }


def geocode_open_meteo(location):
    """
    Resolve weather locations reliably through Open-Meteo.

    The geocoder may reject combined strings such as "Toronto, Ontario" while
    accepting "Toronto". Try the exact request first, then simpler city forms,
    and prefer Canadian results for common Canadian location wording.
    """
    original_location = re.sub(
        r"\s+",
        " ",
        str(location or ""),
    ).strip(" ,.?")
    if not original_location:
        raise RuntimeError("A weather location is required.")

    candidates = [original_location]

    comma_parts = [
        part.strip()
        for part in original_location.split(",")
        if part.strip()
    ]
    if comma_parts:
        candidates.append(comma_parts[0])

    simplified = re.sub(
        r"\b(?:ontario|on|canada|ca)\b",
        " ",
        original_location,
        flags=re.IGNORECASE,
    )
    simplified = re.sub(r"[,/]+", " ", simplified)
    simplified = re.sub(r"\s+", " ", simplified).strip(" ,.?")
    if simplified:
        candidates.append(simplified)

    unique_candidates = []
    seen_candidates = set()
    for candidate in candidates:
        candidate_key = candidate.casefold()
        if candidate and candidate_key not in seen_candidates:
            seen_candidates.add(candidate_key)
            unique_candidates.append(candidate)

    prefer_canada = (
        any(
            token in original_location.casefold()
            for token in ("ontario", " canada", ", ca", ", on")
        )
        or original_location.casefold()
        in {
            "toronto", "ottawa", "markham", "vancouver", "calgary",
            "montreal", "mississauga", "brampton", "richmond hill",
        }
    )

    for candidate in unique_candidates:
        response = http_session.get(
            "https://geocoding-api.open-meteo.com/v1/search",
            params={
                "name": candidate,
                "count": 10,
                "language": "en",
                "format": "json",
            },
            timeout=LIVE_HTTP_TIMEOUT,
        )
        data = safe_json_response(response)
        results = data.get("results") or []
        if not results:
            continue

        if prefer_canada:
            for result in results:
                country_code = str(
                    result.get("country_code") or ""
                ).strip().upper()
                if country_code == "CA":
                    return result

        return results[0]

    raise RuntimeError(f"Location not found: {original_location}")


def get_live_weather(location):
    place = geocode_open_meteo(location)
    response = http_session.get(
        "https://api.open-meteo.com/v1/forecast",
        params={
            "latitude": place["latitude"],
            "longitude": place["longitude"],
            "current": (
                "temperature_2m,apparent_temperature,relative_humidity_2m,"
                "precipitation,weather_code,wind_speed_10m"
            ),
            "daily": (
                "weather_code,temperature_2m_max,temperature_2m_min,"
                "precipitation_probability_max"
            ),
            "temperature_unit": "celsius",
            "wind_speed_unit": "kmh",
            "timezone": "auto",
            "forecast_days": 5,
        },
        timeout=LIVE_HTTP_TIMEOUT,
    )
    data = safe_json_response(response)

    return {
        "source": "Open-Meteo",
        "location": {
            "name": place.get("name"),
            "admin1": place.get("admin1"),
            "country": place.get("country"),
            "timezone": data.get("timezone"),
        },
        "current": data.get("current", {}),
        "current_units": data.get("current_units", {}),
        "daily": data.get("daily", {}),
        "daily_units": data.get("daily_units", {}),
    }





def get_live_exchange_rate(base_currency, quote_currency):
    """Fetch the latest available reference exchange rate without an API key."""
    base = str(base_currency or "").strip().upper()
    quote_currency = str(quote_currency or "").strip().upper()

    if not re.fullmatch(r"[A-Z]{3}", base):
        raise RuntimeError("Invalid base currency code.")
    if not re.fullmatch(r"[A-Z]{3}", quote_currency):
        raise RuntimeError("Invalid quote currency code.")
    if base == quote_currency:
        return {
            "source": "Frankfurter",
            "base": base,
            "quote": quote_currency,
            "rate": 1.0,
            "date": datetime.now(timezone.utc).date().isoformat(),
            "note": "The currencies are identical.",
        }

    response = http_session.get(
        f"https://api.frankfurter.dev/v2/rate/{base}/{quote_currency}",
        timeout=LIVE_HTTP_TIMEOUT,
    )
    data = safe_json_response(response)

    rate = data.get("rate")
    if rate is None:
        raise RuntimeError(
            f"No exchange rate was returned for {base}/{quote_currency}."
        )

    return {
        "source": "Frankfurter",
        "base": data.get("base", base),
        "quote": data.get("quote", quote_currency),
        "rate": rate,
        "date": data.get("date"),
        "provider": data.get("provider"),
        "note": (
            "Latest available central-bank reference rate. "
            "This may not equal a bank, card, or cash-conversion rate."
        ),
    }



def cached_oauth_token(cache_key, token_url, client_id, client_secret, *,
                       data=None, headers=None, auth=None):
    if not client_id or not client_secret:
        raise RuntimeError("API credentials are not configured.")

    token_record = st.session_state.get(cache_key) or {}
    if (
        token_record.get("access_token")
        and float(token_record.get("expires_at", 0)) > time.time() + 60
    ):
        return token_record["access_token"]

    request_data = dict(data or {})
    request_headers = dict(headers or {})

    response = http_session.post(
        token_url,
        data=request_data,
        headers=request_headers,
        auth=auth,
        timeout=LIVE_HTTP_TIMEOUT,
    )
    payload = safe_json_response(response)
    token = payload.get("access_token")
    if not token:
        raise RuntimeError("OAuth response did not include an access token.")

    expires_in = int(payload.get("expires_in", 3300))
    st.session_state[cache_key] = {
        "access_token": token,
        "expires_at": time.time() + max(expires_in, 300),
    }
    return token


def get_ups_access_token():
    print("[UPS OAUTH] Requesting or reusing UPS OAuth token.", flush=True)
    token = cached_oauth_token(
        "ups_oauth_token",
        "https://onlinetools.ups.com/security/v1/oauth/token",
        UPS_CLIENT_ID,
        UPS_CLIENT_SECRET,
        data={"grant_type": "client_credentials"},
        headers={
            "Content-Type": "application/x-www-form-urlencoded",
            "Accept": "application/json",
        },
        auth=(UPS_CLIENT_ID, UPS_CLIENT_SECRET),
    )
    print("[UPS OAUTH] Token available.", flush=True)
    return token


def track_ups(tracking_number):
    if not UPS_CLIENT_ID or not UPS_CLIENT_SECRET:
        return {
            "configured": False,
            "carrier": "UPS",
            "message": "UPS credentials are not configured."
        }

    # Never send surrounding words or punctuation to UPS.
    normalized_tracking = re.sub(
        r"[^A-Z0-9]",
        "",
        str(tracking_number or "").upper(),
    )

    if not re.fullmatch(r"1Z[A-Z0-9]{16}", normalized_tracking):
        raise RuntimeError(
            "Invalid UPS tracking-number format. "
            "A standard UPS 1Z tracking number must contain exactly 18 characters."
        )

    print(
        f"[UPS ROUTER] Calling UPS Tracking API for {normalized_tracking}.",
        flush=True,
    )
    token = get_ups_access_token()
    response = http_session.get(
        (
            "https://onlinetools.ups.com/api/track/v1/details/"
            f"{quote(normalized_tracking, safe='')}"
        ),
        params={
            "locale": "en_US",
            "returnSignature": "false",
        },
        headers={
            "Authorization": f"Bearer {token}",
            "transId": f"atp-{int(time.time() * 1000)}",
            "transactionSrc": "AutoTecProAI",
            "Accept": "application/json",
        },
        timeout=LIVE_HTTP_TIMEOUT,
    )

    print(
        f"[UPS TRACKING] HTTP {response.status_code} for {normalized_tracking}.",
        flush=True,
    )

    try:
        data = safe_json_response(response)
    except Exception as error:
        # Log only non-secret diagnostic information to Streamlit Cloud logs.
        safe_body = response.text[:1000].replace("\n", " ").replace("\r", " ")
        print(
            "[UPS TRACKING ERROR] "
            f"status={response.status_code} "
            f"tracking={normalized_tracking} "
            f"response={safe_body}",
            flush=True,
        )
        raise RuntimeError(f"UPS Tracking API error: {error}") from error

    return {
        "configured": True,
        "carrier": "UPS",
        "tracking_number": normalized_tracking,
        "source": "UPS Tracking API",
        "data": data,
    }






def xml_to_dict(element):
    result = {}
    for child in list(element):
        tag = child.tag.split("}")[-1]
        value = xml_to_dict(child) if list(child) else (child.text or "").strip()
        if tag in result:
            if not isinstance(result[tag], list):
                result[tag] = [result[tag]]
            result[tag].append(value)
        else:
            result[tag] = value
    return result


def track_canada_post(tracking_number):
    if not CANADA_POST_USERNAME or not CANADA_POST_PASSWORD:
        return {
            "configured": False,
            "carrier": "Canada Post",
            "message": "Canada Post credentials are not configured."
        }

    response = http_session.get(
        (
            "https://soa-gw.canadapost.ca/vis/track/pin/"
            f"{quote(tracking_number.strip())}/detail"
        ),
        auth=(CANADA_POST_USERNAME, CANADA_POST_PASSWORD),
        headers={
            "Accept": "application/vnd.cpc.track+xml",
            "Accept-language": "en-CA",
        },
        timeout=LIVE_HTTP_TIMEOUT,
    )
    if not response.ok:
        safe_json_response(response)

    root = ET.fromstring(response.content)
    return {
        "configured": True,
        "carrier": "Canada Post",
        "tracking_number": tracking_number,
        "source": "Canada Post Tracking Web Service",
        "data": xml_to_dict(root),
    }


def extract_tracking_number(prompt):
    """
    Extract a carrier tracking number without accidentally appending words
    such as UPS, tracking, package, or shipment.

    UPS 1Z numbers are always exactly 18 characters:
    "1Z" + 16 letters/digits.
    """
    value = str(prompt or "").upper()

    # UPS standard tracking number: exactly 18 alphanumeric characters.
    ups_match = re.search(r"(?<![A-Z0-9])(1Z[A-Z0-9]{16})(?![A-Z0-9])", value)
    if ups_match:
        return ups_match.group(1)

    # Canada Post domestic tracking numbers are commonly 16 digits.
    canada_post_numeric = re.search(r"(?<!\d)(\d{16})(?!\d)", value)
    if canada_post_numeric:
        return canada_post_numeric.group(1)

    # Canada Post international format, for example AB123456789CA.
    canada_post_international = re.search(
        r"(?<![A-Z0-9])([A-Z]{2}\d{9}CA)(?![A-Z0-9])",
        value,
    )
    if canada_post_international:
        return canada_post_international.group(1)

    # Conservative fallback for other explicitly labelled tracking requests.
    labelled_match = re.search(
        r"(?:TRACK(?:ING)?(?:\s+NUMBER)?|PACKAGE|PARCEL|SHIPMENT)"
        r"\s*[:#-]?\s*([A-Z0-9][A-Z0-9-]{7,33})",
        value,
    )
    if labelled_match:
        compact = re.sub(r"[^A-Z0-9]", "", labelled_match.group(1))
        if 8 <= len(compact) <= 34 and any(char.isdigit() for char in compact):
            return compact

    return ""



def _normalized_workspace_name(selected_assistant=None):
    """Return a clean current or legacy workspace label."""
    active_value = (
        selected_assistant
        or st.session_state.get("current_assistant")
        or ""
    )
    normalized = re.sub(
        r"\s+",
        " ",
        str(active_value),
    ).strip().lower()
    return re.sub(r"^[^a-z0-9]+", "", normalized).strip()


def is_sales_workspace(selected_assistant=None):
    """
    Return True for the current Sales workspace.

    The combined legacy label is accepted only so old saved conversations still
    open correctly after Sales and Marketing were separated.
    """
    return _normalized_workspace_name(selected_assistant) in {
        "sales",
        "sales & marketing",
        "sales and marketing",
    }


def is_marketing_workspace(selected_assistant=None):
    """Return True only for the current Marketing workspace."""
    return _normalized_workspace_name(selected_assistant) == "marketing"



def _woocommerce_access_level_for_assistant(selected_assistant=None):
    """
    Resolve WooCommerce access from the active workspace defensively.

    This intentionally does not rely on an exact emoji-prefixed label because
    Streamlit session state or restored conversations may contain a plain label.
    """
    if not user_can_use_feature("woocommerce"):
        return ""

    normalized = _normalized_workspace_name(
        selected_assistant
    )

    if normalized == "technical support":
        # Technical Support gets the restricted support view with financial
        # fields removed where possible.
        return "technical"

    if (
        is_sales_workspace(selected_assistant)
        or is_marketing_workspace(selected_assistant)
    ):
        # Sales and Marketing are separate current workspaces. Both retain the
        # full commercial, read-only WooCommerce view.
        return "sales"

    return ""


@st.cache_data(ttl=300, max_entries=1024, show_spinner=False)
def detect_technical_support_tool(
    prompt,
    selected_assistant=None,
    has_images=False,
):
    """
    Route Technical Support prompts to one specialized workflow.

    This is deterministic, local, and performs no network, database, or OpenAI
    request. Only one specialized workflow is selected for each prompt.
    """
    active = re.sub(
        r"\s+",
        " ",
        str(
            selected_assistant
            or st.session_state.get("current_assistant")
            or ""
        ),
    ).strip().lower()
    active = re.sub(r"^[^a-z0-9]+", "", active).strip()

    if active != "technical support":
        return {"type": "none"}

    value = re.sub(r"\s+", " ", str(prompt or "")).strip()
    lower = value.lower()
    if not lower:
        return {"type": "none"}

    photo_diagnosis_terms = (
        "analyze this photo", "analyse this photo", "analyze this image",
        "analyse this image", "diagnose this photo", "diagnose this image",
        "what is wrong", "what's wrong", "what do you see",
        "check this installation", "check this wiring", "check this connector",
        "identify this connector", "identify this harness", "identify this unit",
        "is this connected correctly", "is this installed correctly",
        "damage", "cracked", "broken", "burnt", "burned",
    )
    if bool(has_images) and any(term in lower for term in photo_diagnosis_terms):
        return {
            "type": "technical_photo_diagnosis",
            "label": "AI Photo Diagnosis",
        }

    wiring_terms = (
        "wiring diagram", "wire diagram", "wiring", "pinout", "pin out",
        "connector pin", "connector diagram", "schematic", "can high",
        "can low", "can-h", "can-l", "lvds", "aux wire", "reverse wire",
        "camera wire", "amp wire", "acc wire", "power wire", "ground wire",
        "harness diagram", "harness pin", "which pin", "pin number",
    )
    if any(term in lower for term in wiring_terms):
        return {
            "type": "technical_wiring_diagram",
            "label": "AI Wiring Diagram Finder",
        }

    compatibility_terms = (
        "compatible", "compatibility", "will it fit", "does it fit",
        "fit my", "fitment", "work with my", "works with my",
        "which model", "which screen", "which unit", "which harness",
        "what harness", "retain factory", "retain my", "supported vehicle",
        "bose compatible", "sony compatible", "jbl compatible",
        "360 camera compatible", "factory camera compatible",
    )
    if any(term in lower for term in compatibility_terms):
        return {
            "type": "technical_compatibility",
            "label": "AI Compatibility Checker",
        }

    troubleshooting_terms = (
        "not working", "doesn't work", "does not work", "problem",
        "issue", "troubleshoot", "diagnose", "no sound", "no audio",
        "black screen", "blank screen", "no power", "won't turn on",
        "will not turn on", "boot loop", "restarting", "freezing",
        "frozen", "no signal", "camera not", "carplay not",
        "android auto not", "bluetooth not", "touch not", "mic not",
        "microphone not", "steering wheel control", "swc not",
        "flicker", "static noise", "echo", "low volume",
    )
    if any(term in lower for term in troubleshooting_terms):
        return {
            "type": "technical_troubleshooter",
            "label": "AI Installation Troubleshooter",
        }

    return {"type": "none"}


def build_technical_tool_context(prompt, routing=None):
    """Build a grounded instruction block for one Technical Support tool."""
    routing = (
        routing
        if isinstance(routing, dict)
        else detect_technical_support_tool(prompt, assistant)
    )
    tool_type = str(routing.get("type") or "none").strip().lower()
    if tool_type == "none":
        return ""

    common = """
TECHNICAL TOOL ROUTING — generated by the AutoTecPro application:
- Use the Technical Support Vector Store as the primary source of truth.
- Never invent compatibility, wiring, connector pins, harnesses, retained
  functions, firmware, specifications, or troubleshooting results.
- Separate verified facts from assumptions and missing information.
- Do not quote prices or commercial values.
"""

    if tool_type == "technical_wiring_diagram":
        return common + """
ACTIVE TOOL: AI Wiring Diagram Finder

Required behavior:
1. Search the Technical Support Vector Store for the closest matching vehicle,
   year range, trim, factory audio system, factory screen, camera system,
   AutoTecPro product, harness, connector, and requested circuit.
2. State the exact matched document name and page/section only when retrieval
   provides that information. Never guess a page number or filename.
3. Explain the connector, pin, wire purpose, test condition, and expected
   reading only when verified by AutoTecPro documentation.
4. If an uploaded photo or diagram is present, analyze it and refer to visible
   connector positions clearly.
5. The chat can display images supplied to the current conversation. Vector
   search may return document text without renderable page-image bytes. If the
   exact diagram image is not available to display, say so clearly and provide
   the verified source document/page or request that staff upload/export that
   page. Never claim that an image is displayed when it is not.
6. If vehicle or factory-system details are missing, ask only for the minimum
   details needed to select the correct diagram.

Preferred response:
- Matched vehicle/system
- Diagram or source located
- Connector/pin details
- Verification steps
- Missing information or limitation
"""

    if tool_type == "technical_photo_diagnosis":
        return common + """
ACTIVE TOOL: AI Photo Diagnosis

Required behavior:
1. Analyze only what is actually visible in the uploaded image or images.
2. Separate VISIBLE OBSERVATIONS from DIAGNOSIS and from UNVERIFIED ASSUMPTIONS.
3. Use the Technical Support Vector Store to verify connectors, harnesses,
   wiring, product models, vehicle configurations, installation procedures,
   known issues, and expected behavior.
4. Never identify a connector, pin, wire, harness, vehicle trim, audio system,
   camera system, product model, firmware, or defect unless the image or
   retrieved AutoTecPro documentation supports it.
5. State confidence as HIGH, MEDIUM, or LOW and explain what limits confidence.
6. Ask for a clearer close-up, wider dashboard photo, connector-label photo,
   wiring photo, settings screen, order number, or vehicle details when needed.
7. Do not recommend replacement until installation, connections, settings,
   documented procedures, and known issues have been reasonably checked.
8. Customer photos must not be treated as reusable knowledge by themselves.

Preferred response:
- Visible observations
- Detected vehicle/product, if verified
- Confidence
- Most likely diagnosis
- Alternative possibilities
- Recommended checks
- Additional photo or information required
- Escalation recommendation
"""

    if tool_type == "technical_compatibility":
        return common + """
ACTIVE TOOL: AI Compatibility Checker

Required behavior:
1. Verify year, make, model, trim, original screen/radio, factory audio system,
   camera configuration, climate-control type, steering side, and requested
   AutoTecPro product whenever relevant.
2. Return exactly one compatibility status:
   VERIFIED COMPATIBLE, CONDITIONALLY COMPATIBLE, NOT COMPATIBLE, or
   INSUFFICIENT INFORMATION.
3. List the verified product/model, required harnesses or adapters, retained
   factory features, known limitations, and installation conditions.
4. Do not infer compatibility from similar vehicles or nearby year ranges.
5. Ask concise follow-up questions when required details are missing.

Preferred response:
- Compatibility status
- Vehicle configuration
- Recommended AutoTecPro product
- Required parts
- Retained features
- Known limitations
- Information still required
"""

    return common + """
ACTIVE TOOL: AI Installation Troubleshooter

Required behavior:
1. Identify the symptom and installation stage before recommending replacement.
2. Use a guided diagnostic sequence. Start with the safest and most likely
   checks, then advance only when earlier checks are confirmed.
3. Distinguish among power, CAN, LVDS/video, factory-radio audio path, amplifier,
   AUX, USB, camera, microphone, Bluetooth, CarPlay/Android Auto, firmware, and
   configuration issues.
4. For each step, explain what to check, the expected result, and what the
   result means.
5. Ask focused follow-up questions instead of presenting unrelated procedures.
6. Do not recommend replacement until installation, settings, connections, and
   documented known issues have been reasonably checked.
7. Clearly identify when a video call, photo, wiring diagram, firmware check,
   or escalation is required.

Preferred response:
- Symptom summary
- Most likely cause
- Step 1
- Expected result
- Next action based on the result
- Information/photo needed
"""


