class ManagedUploadedFile(io.BytesIO):
    """Reusable in-memory upload object with Streamlit-compatible metadata."""

    def __init__(self, data, name, mime_type="application/octet-stream"):
        file_bytes = bytes(data or b"")
        super().__init__(file_bytes)
        self.name = str(name or "upload")
        self.type = str(mime_type or "application/octet-stream")
        self.size = len(file_bytes)

    def getvalue(self):
        """Return the complete file bytes without changing the current position."""
        return super().getvalue()


def _normalized_upload_mime_type(file_name, reported_type=""):
    """Return a stable MIME type for browser uploads, especially Office files."""
    extension = Path(str(file_name or "")).suffix.lower()
    mime_by_extension = {
        ".jpg": "image/jpeg",
        ".jpeg": "image/jpeg",
        ".png": "image/png",
        ".pdf": "application/pdf",
        ".txt": "text/plain",
        ".doc": "application/msword",
        ".docx": (
            "application/vnd.openxmlformats-officedocument."
            "wordprocessingml.document"
        ),
        ".xls": "application/vnd.ms-excel",
        ".xlsx": (
            "application/vnd.openxmlformats-officedocument."
            "spreadsheetml.sheet"
        ),
        ".xlsm": "application/vnd.ms-excel.sheet.macroEnabled.12",
        ".xlsb": "application/vnd.ms-excel.sheet.binary.macroEnabled.12",
        ".csv": "text/csv",
        ".ppt": "application/vnd.ms-powerpoint",
        ".pptx": (
            "application/vnd.openxmlformats-officedocument."
            "presentationml.presentation"
        ),
    }

    expected_type = mime_by_extension.get(extension)
    clean_reported_type = str(reported_type or "").strip()

    if expected_type:
        return expected_type
    return clean_reported_type or "application/octet-stream"


def _managed_upload_record(uploaded_file):
    data = uploaded_file.getvalue()
    digest = hashlib.sha256(data).hexdigest()
    file_name = str(getattr(uploaded_file, "name", "upload"))
    return {
        "id": digest,
        "name": file_name,
        "type": _normalized_upload_mime_type(
            file_name,
            getattr(uploaded_file, "type", ""),
        ),
        "size": len(data),
        "data": data,
    }


def _managed_upload_objects(records):
    return [
        ManagedUploadedFile(
            record["data"],
            record["name"],
            record.get("type") or "application/octet-stream",
        )
        for record in (records or [])
    ]


def clear_managed_uploads(storage_key, generation_key):
    st.session_state[storage_key] = []
    st.session_state[generation_key] = (
        int(st.session_state.get(generation_key, 0)) + 1
    )


