# ============================================================
# Helpers
# ============================================================

@st.cache_data(show_spinner=False)
def get_logo_base64():
    """Read and encode the static application logo once."""
    if LOGO_FILE.exists():
        with open(LOGO_FILE, "rb") as file_handle:
            return base64.b64encode(file_handle.read()).decode()
    return None

def now_iso():
    return datetime.now(timezone.utc).isoformat()


@st.cache_resource(show_spinner=False)
def get_supabase_admin_client():
    """
    Return the reusable privileged Supabase client for server-side admin tasks.

    The client is created lazily so missing credentials do not affect normal app
    startup. It is used only for operations that must bypass Supabase RLS, such
    as private Storage uploads, signed URLs, and permanent deletion.
    """
    if create_supabase_client is None:
        raise RuntimeError(
            "The Supabase client package could not create an admin connection."
        )

    supabase_url = st.secrets.get("SUPABASE_URL")
    admin_key = (
        st.secrets.get("SUPABASE_SECRET_KEY")
        or st.secrets.get("SUPABASE_SERVICE_ROLE_KEY")
    )

    if not supabase_url:
        raise RuntimeError("SUPABASE_URL is missing from Streamlit Secrets.")

    if not admin_key:
        raise RuntimeError(
            "SUPABASE_SECRET_KEY or SUPABASE_SERVICE_ROLE_KEY is missing "
            "from Streamlit Secrets."
        )

    return create_supabase_client(
        str(supabase_url),
        str(admin_key),
    )


# ============================================================
# Supabase Schema Safety Helpers
# ============================================================

@st.cache_data(ttl=1800, max_entries=32, show_spinner=False)
def get_table_columns(table_name):
    """
    Return actual Supabase table columns.

    IMPORTANT:
    Do not guess columns from fallback when a table is empty. That causes PGRST204
    missing-column errors. The RPC below reads information_schema directly.
    """
    try:
        result = supabase.rpc("get_table_columns", {"input_table_name": table_name}).execute()
        if result.data:
            return [row["column_name"] for row in result.data if row.get("column_name")]
    except Exception:
        pass

    # Safe minimum fallback only. These are columns used by the original app and are
    # usually present even in older schemas. Optional learning fields are filtered out
    # unless Supabase confirms they exist.
    fallback = {
        "learned_knowledge": [
            "id", "question", "approved_answer", "keywords",
            "source_conversation_id", "openai_file_id", "vector_store_id",
            "synced", "created_at"
        ],
        "ai_analytics": [
            "id", "username", "assistant", "vehicle", "issue", "product",
            "keywords", "question", "answer", "created_at"
        ],
        "conversations": [
            "id", "username", "assistant", "title", "archived", "pinned",
            "created_at", "updated_at"
        ],
        "messages": [
            "id", "conversation_id", "role", "content", "created_at"
        ],
        "login_sessions": [
            "id", "username", "role", "active", "created_at"
        ],
        "users": [
            "id", "username", "password", "role", "active"
        ]
    }
    return fallback.get(table_name, [])


def refresh_schema_cache():
    """Clear cached schema after SQL migration or Streamlit reboot."""
    try:
        get_table_columns.clear()
    except Exception:
        pass


def filter_payload_for_table(table_name, payload):
    """Remove fields that do not exist in Supabase table to prevent PGRST204 errors."""
    columns = set(get_table_columns(table_name))
    if not columns:
        return payload
    return {k: v for k, v in payload.items() if k in columns}


def safe_select_rows(table_name, order_columns=None, limit=500):
    """Select rows with fallback ordering for mixed database versions."""
    order_columns = order_columns or ["updated_at", "created_at"]
    last_error = None
    for order_col in order_columns:
        try:
            return (
                supabase
                .table(table_name)
                .select("*")
                .order(order_col, desc=True)
                .limit(limit)
                .execute()
                .data
            ) or []
        except Exception as e:
            last_error = e
    try:
        return (
            supabase
            .table(table_name)
            .select("*")
            .limit(limit)
            .execute()
            .data
        ) or []
    except Exception:
        if last_error:
            raise last_error
        raise


def safe_insert_row(table_name, payload):
    clean_payload = filter_payload_for_table(table_name, payload)
    return supabase.table(table_name).insert(clean_payload).execute()


def safe_update_row(table_name, payload, row_id):
    clean_payload = filter_payload_for_table(table_name, payload)
    return supabase.table(table_name).update(clean_payload).eq("id", row_id).execute()

def inline_format(text):
    """Escape text and support simple markdown bold inside custom HTML bubbles."""
    safe = html.escape(str(text or ""))
    parts = safe.split("**")
    if len(parts) > 1:
        rebuilt = ""
        for i, part in enumerate(parts):
            rebuilt += f"<strong>{part}</strong>" if i % 2 else part
        safe = rebuilt
    return safe


def is_markdown_table_separator(line):
    """Return True for markdown separator rows like |---|---|."""
    stripped = line.strip()
    if "|" not in stripped:
        return False
    cells = [cell.strip() for cell in stripped.strip("|").split("|")]
    if not cells:
        return False
    return all(cell and set(cell) <= set("-: ") for cell in cells)


def split_markdown_table_row(line):
    return [cell.strip() for cell in line.strip().strip("|").split("|")]


def table_to_html(table_lines):
    """Convert a basic markdown table to HTML."""
    if len(table_lines) < 2:
        return ""

    headers = split_markdown_table_row(table_lines[0])
    body_lines = table_lines[2:] if is_markdown_table_separator(table_lines[1]) else table_lines[1:]

    html_rows = ["<table>"]
    html_rows.append("<thead><tr>")
    for header in headers:
        html_rows.append(f"<th>{inline_format(header)}</th>")
    html_rows.append("</tr></thead>")

    html_rows.append("<tbody>")
    for row_line in body_lines:
        cells = split_markdown_table_row(row_line)
        if len(cells) < len(headers):
            cells += [""] * (len(headers) - len(cells))
        html_rows.append("<tr>")
        for cell in cells[:len(headers)]:
            html_rows.append(f"<td>{inline_format(cell)}</td>")
        html_rows.append("</tr>")
    html_rows.append("</tbody></table>")
    return "\n".join(html_rows)


def normalize_assistant_markdown(text):
    """Repair common AI Markdown layout issues without changing response facts.

    This display-only normalizer separates compressed bullets/checkmarks/warnings,
    repairs and renumbers inline numbered lists, creates scan-friendly tables in
    structured sections, and preserves the original factual wording.
    """
    value = str(text or "").replace("\r\n", "\n").replace("\r", "\n")
    normalized_lines = []

    for raw_line in value.split("\n"):
        line = raw_line.rstrip()
        stripped = line.strip()

        if not stripped or stripped.startswith(("#", "```", "> ", "|")):
            normalized_lines.append(line)
            continue

        # Split compressed visual list walls. This includes ordinary bullets,
        # checklist marks, and warning marks used by Technical Support replies.
        visual_marker_pattern = r"(?:[•●▪◦✓✔☑]|(?<!\S)-(?!-)(?=\s+\S)|(?:(?<=^)|(?<=\s))[!⚠](?=\s*\S))"
        visual_matches = list(re.finditer(visual_marker_pattern, stripped))
        if len(visual_matches) >= 2:
            prefix = stripped[:visual_matches[0].start()].strip()
            if prefix:
                normalized_lines.append(prefix)
            for idx, marker in enumerate(visual_matches):
                item_start = marker.end()
                item_end = visual_matches[idx + 1].start() if idx + 1 < len(visual_matches) else len(stripped)
                item = stripped[item_start:item_end].strip(" \t-;•●▪◦✓✔☑!⚠")
                if not item:
                    continue
                raw_marker = marker.group(0)
                if raw_marker in {"!", "⚠"}:
                    normalized_lines.append(f"• {item}")
                else:
                    normalized_lines.append(f"• {item}")
            continue

        # Split compressed numbered walls even when the model skips or repeats a
        # number. The Information Still Required section is renumbered later.
        number_markers = list(re.finditer(r"(?<!\d)(\d{1,2})[.)]\s*", stripped))
        if len(number_markers) >= 2:
            prefix = stripped[:number_markers[0].start()].strip()
            if prefix:
                normalized_lines.append(prefix)
            for idx, marker in enumerate(number_markers):
                item_start = marker.end()
                item_end = number_markers[idx + 1].start() if idx + 1 < len(number_markers) else len(stripped)
                item = stripped[item_start:item_end].strip(" -;•")
                if item:
                    normalized_lines.append(f"{marker.group(1)}. {item}")
            continue

        normalized_lines.append(line)

    table_sections = {
        "vehicle configuration", "vehicle identification", "vehicle details",
        "vehicle information", "recommended autotecpro product",
        "recommended product", "compatibility", "compatibility result",
        "product comparison", "product comparisons", "comparison", "comparisons",
        "specification", "specifications", "product options",
        "configuration options", "options", "installation summary",
        "autotecpro model match", "kvn part number match",
        "product specifications",
    }
    product_sections = {
        "recommended autotecpro product", "recommended product",
        "product comparison", "product comparisons",
    }
    numbered_sections = {
        "information still required", "information required",
        "details still required", "confirmation required",
        "installation steps",
    }

    def heading_name(line):
        match = re.match(r"^#{1,6}\s+(.+?)\s*$", line.strip())
        if match:
            return match.group(1).strip().rstrip(":").casefold()
        bold = re.fullmatch(r"\*\*(.{1,100}?)\*\*: ?", line.strip())
        return bold.group(1).strip().rstrip(":").casefold() if bold else ""

    def label_value(line):
        clean = re.sub(r"^[•*\-✓✔☑!⚠]\s*", "", line.strip())
        clean = re.sub(r"^\*\*(.+?)\*\*\s*:\s*", r"\1: ", clean)
        match = re.match(r"^([^:|]{2,70}):\s*(.+)$", clean)
        if not match:
            return None
        label = match.group(1).strip().strip("*")
        val = match.group(2).strip()
        return (label, val) if label and val else None

    output = []
    i = 0
    active_heading = ""
    info_counter = 0

    while i < len(normalized_lines):
        line = normalized_lines[i]
        heading = heading_name(line)
        if heading:
            active_heading = heading
            info_counter = 0
            output.append(line)
            i += 1
            continue

        if active_heading in numbered_sections:
            stripped = line.strip()
            if re.match(r"^[•*\-✓✔☑]\s*", stripped):
                info_counter += 1
                item = re.sub(r"^[•*\-✓✔☑]\s*", "", stripped).strip()
                if item:
                    output.append(f"{info_counter}. {item}")
                i += 1
                continue
            existing = re.match(r"^(\d+)[.)]\s+(.+)$", stripped)
            if existing:
                info_counter += 1
                output.append(f"{info_counter}. {existing.group(2).strip()}")
                i += 1
                continue

        if active_heading in table_sections:
            group = []
            j = i
            while j < len(normalized_lines):
                candidate = normalized_lines[j]
                if not candidate.strip() or heading_name(candidate):
                    break
                parsed = label_value(candidate)
                if not parsed:
                    break
                group.append(parsed)
                j += 1
            minimum = 2 if active_heading in product_sections else 3
            if len(group) >= minimum:
                if active_heading in product_sections:
                    output.extend(["", "| Option | Model / Details |", "|---|---|"])
                else:
                    output.extend(["", "| Item | Finding |", "|---|---|"])
                output.extend(f"| {label} | {val} |" for label, val in group)
                output.append("")
                i = j
                continue

        output.append(line)
        i += 1

    repaired = "\n".join(output)
    repaired = re.sub(r"\n{4,}", "\n\n\n", repaired)
    return repaired


@st.cache_data(ttl=900, max_entries=512, show_spinner=False)
def html_from_text(text, assistant_mode=False):
    """Render safe markdown-like chat HTML with richer assistant spacing."""
    if text is None:
        return ""

    text = clean_visible_chat_text(text)
    if assistant_mode:
        text = normalize_assistant_markdown(text)
    lines = str(text).splitlines()
    html_lines = []
    in_ul = False
    in_ol = False
    in_customer_reply = False
    customer_reply_box_open = False
    active_section = ""
    i = 0

    def close_lists():
        nonlocal in_ul, in_ol
        if in_ul:
            html_lines.append("</ul>")
            in_ul = False
        if in_ol:
            html_lines.append("</ol>")
            in_ol = False

    def close_customer_reply_box():
        nonlocal customer_reply_box_open
        if customer_reply_box_open:
            html_lines.append("</blockquote>")
            customer_reply_box_open = False

    while i < len(lines):
        line = lines[i].rstrip()
        stripped = line.strip()

        # Final defensive cleanup: never render HTML artifact lines.
        # This catches old saved messages and AI replies that include raw/escaped tags.
        artifact_check = stripped.replace("`", "").strip()
        artifact_check = re.sub(r"&lt;/?\s*(div|p|span|section|article|main|body|html)\b[^&]*&gt;", "", artifact_check, flags=re.IGNORECASE)
        artifact_check = re.sub(r"</?\s*(div|p|span|section|article|main|body|html)\b[^>]*>", "", artifact_check, flags=re.IGNORECASE).strip()

        if stripped in ("```", "```html", "```HTML"):
            i += 1
            continue

        if not artifact_check and (
            "<" in stripped or ">" in stripped or "&lt;" in stripped.lower() or "&gt;" in stripped.lower()
        ):
            i += 1
            continue

        # Remove inline HTML tags from otherwise valid lines.
        line = re.sub(r"&lt;/?\s*(div|p|span|section|article|main|body|html)\b[^&]*&gt;", "", line, flags=re.IGNORECASE)
        line = re.sub(r"</?\s*(div|p|span|section|article|main|body|html)\b[^>]*>", "", line, flags=re.IGNORECASE)
        stripped = line.strip()

        if not stripped:
            close_lists()
            next_nonempty = ""
            lookahead = i + 1
            while lookahead < len(lines):
                next_nonempty = lines[lookahead].strip()
                if next_nonempty:
                    break
                lookahead += 1
            previous_is_heading = bool(
                html_lines and re.match(r"^<h[1-3]>", html_lines[-1])
            )
            next_is_heading = bool(
                next_nonempty.startswith(("# ", "## ", "### "))
                or re.fullmatch(r"\*\*(.{1,80}?)\*\*: ?", next_nonempty)
            )
            if not previous_is_heading and not next_is_heading:
                html_lines.append("<br>")
            i += 1
            continue

        compatibility_match = re.match(
            r"^(?:\*\*)?Compatibility Status(?:\*\*)?\s*:\s*(.+)$",
            stripped,
            flags=re.IGNORECASE,
        )
        if assistant_mode and compatibility_match:
            close_lists()
            close_customer_reply_box()
            status_text = compatibility_match.group(1).strip().strip("*")
            status_key = status_text.casefold()
            if "not compatible" in status_key or "incompatible" in status_key:
                status_class = "atp-status-incompatible"
                status_icon = "●"
            elif "conditional" in status_key:
                status_class = "atp-status-conditional"
                status_icon = "●"
            elif "compatible" in status_key:
                status_class = "atp-status-compatible"
                status_icon = "●"
            else:
                status_class = ""
                status_icon = "●"
            html_lines.append(
                f'<div class="atp-compatibility-badge {status_class}">'
                f'{status_icon} Compatibility Status: {inline_format(status_text)}'
                '</div>'
            )
            i += 1
            continue

        # Markdown table support:
        # | Header | Header |
        # |---|---|
        # | Cell | Cell |
        if (
            "|" in stripped
            and i + 1 < len(lines)
            and is_markdown_table_separator(lines[i + 1])
        ):
            close_lists()
            close_customer_reply_box()
            table_lines = [line, lines[i + 1]]
            i += 2
            while i < len(lines) and "|" in lines[i].strip() and lines[i].strip():
                table_lines.append(lines[i])
                i += 1
            html_lines.append(table_to_html(table_lines))
            continue

        bold_heading = re.fullmatch(r"\*\*(.{1,80}?)\*\*:?", stripped)
        numbered_item = re.match(r"^(\d+)[.)]\s+(.+)$", stripped)

        if stripped.startswith("### "):
            close_lists()
            close_customer_reply_box()
            heading_text = stripped[4:].strip()
            active_section = heading_text.rstrip(":").casefold()
            in_customer_reply = active_section in {
                "customer reply", "customer reply draft", "reply to customer"
            }
            html_lines.append(f"<h3>{inline_format(heading_text)}</h3>")
        elif stripped.startswith("## "):
            close_lists()
            close_customer_reply_box()
            heading_text = stripped[3:].strip()
            active_section = heading_text.rstrip(":").casefold()
            in_customer_reply = active_section in {
                "customer reply", "customer reply draft", "reply to customer"
            }
            html_lines.append(f"<h2>{inline_format(heading_text)}</h2>")
        elif stripped.startswith("# "):
            close_lists()
            close_customer_reply_box()
            heading_text = stripped[2:].strip()
            active_section = heading_text.rstrip(":").casefold()
            in_customer_reply = active_section in {
                "customer reply", "customer reply draft", "reply to customer"
            }
            html_lines.append(f"<h1>{inline_format(heading_text)}</h1>")
        elif assistant_mode and bold_heading:
            close_lists()
            close_customer_reply_box()
            heading_text = bold_heading.group(1).rstrip(":").strip()
            active_section = heading_text.casefold()
            in_customer_reply = active_section in {
                "customer reply", "customer reply draft", "reply to customer"
            }
            html_lines.append(f"<h3>{inline_format(heading_text)}</h3>")
        elif stripped.startswith("- ") or stripped.startswith("• "):
            close_lists()
            item_text = stripped[2:].strip()
            section_class = ""
            marker = "•"
            if active_section == "required parts":
                section_class = " atp-section-list-item atp-required-item"
                marker = "✓"
            elif active_section == "retained features":
                section_class = " atp-section-list-item atp-retained-item"
                marker = "✓"
            elif active_section == "known limitations":
                section_class = " atp-section-list-item atp-warning-item"
                marker = "!"
            html_lines.append(
                f'<div class="atp-copy-list-item atp-copy-bullet{section_class}">'
                f'{marker} {inline_format(item_text)}'
                '</div>'
            )
        elif assistant_mode and numbered_item:
            close_lists()
            list_number = html.escape(numbered_item.group(1))
            section_class = ""
            if active_section in {
                "information still required", "information required",
                "details still required", "confirmation required"
            }:
                section_class = " atp-section-list-item atp-info-item"
            html_lines.append(
                f'<div class="atp-copy-list-item atp-copy-numbered{section_class}">'
                f'{list_number}. {inline_format(numbered_item.group(2))}'
                '</div>'
            )
        else:
            close_lists()
            if assistant_mode and in_customer_reply:
                if not customer_reply_box_open:
                    html_lines.append('<blockquote class="atp-customer-reply-box">')
                    customer_reply_box_open = True
                reply_text = re.sub(r"^>\s?", "", stripped).strip()
                if reply_text:
                    html_lines.append(
                        f'<div class="atp-customer-reply-line">{inline_format(reply_text)}</div>'
                    )
            elif assistant_mode:
                html_lines.append(
                    f'<p class="atp-chat-paragraph">{inline_format(stripped)}</p>'
                )
            else:
                html_lines.append(f"<div>{inline_format(stripped)}</div>")

        i += 1

    close_lists()
    close_customer_reply_box()
    rendered = "\n".join(html_lines)

    # Final safety sweep after rendering.
    rendered = re.sub(r"&lt;/?\s*(div|p|span|section|article|main|body|html)\b[^&]*&gt;", "", rendered, flags=re.IGNORECASE)
    rendered = re.sub(r"</?\s*(div|p|span|section|article|main|body|html)\b[^>]*>", "", rendered, flags=re.IGNORECASE)
    rendered = re.sub(r"<div>\s*</div>", "", rendered, flags=re.IGNORECASE)
    rendered = re.sub(r"(?:<br>\s*)+$", "", rendered, flags=re.IGNORECASE)
    return rendered


def render_chat_message(
    role,
    content,
    images=None,
    message_index=None,
    show_generated_actions=True,
):
    content_without_documents, stored_documents = (
        extract_documents_from_message_content(content)
    )
    visible_content, stored_images = extract_images_from_message_content(
        content_without_documents
    )
    visible_content = clean_visible_chat_text(visible_content)
    if role != "user":
        visible_content = format_learning_record_for_display(visible_content)
    final_images = images if images is not None else stored_images
    product_library_final_images = [
        image for image in (final_images or [])
        if isinstance(image, dict)
        and str(image.get("source") or "").strip().lower() == "product_library"
    ]
    regular_final_images = [
        image for image in (final_images or [])
        if not (
            isinstance(image, dict)
            and str(image.get("source") or "").strip().lower()
            == "product_library"
        )
    ]

    if role == "user":
        icon_html = "👤"
        icon_class = "user-icon"
        bubble_class = "user-bubble"
    else:
        logo_base64 = get_logo_base64()
        if logo_base64:
            icon_html = f'<img src="data:image/png;base64,{logo_base64}" alt="AutoTecPro AI">'
        else:
            icon_html = "AI"
        icon_class = "assistant-icon"
        bubble_class = "assistant-bubble"

    # IMPORTANT:
    # Keep this HTML compact and unindented. Indented closing tags can be parsed
    # by Markdown as a code block, which is what caused visible </div> bars.
    chat_html = (
        f'<div class="chat-row">'
        f'<div class="chat-icon {icon_class}">{icon_html}</div>'
        f'<div class="chat-bubble {bubble_class}">'
        f'{html_from_text(visible_content, assistant_mode=(role != "user"))}'
        f'{render_image_previews(regular_final_images)}'
        f'</div>'
        f'</div>'
    )

    st.markdown(chat_html, unsafe_allow_html=True)

    if role != "user" and stored_documents:
        render_chat_document_cards(
            stored_documents,
            message_index=message_index,
        )

    if role != "user" and product_library_final_images:
        render_product_library_chat_gallery(
            product_library_final_images,
            message_key=(
                message_index
                if message_index is not None
                else f"history_{abs(hash(str(visible_content))) % 1000000}"
            ),
        )

    if (
        role != "user"
        and show_generated_actions
        and regular_final_images
    ):
        render_generated_image_actions(
            regular_final_images,
            message_index=message_index,
        )

REMEMBER_CREDENTIAL_COOKIE = "atp_saved_login_v1"
REMEMBER_CREDENTIAL_DAYS = 30


def get_saved_login_credentials():
    """
    Read manually remembered login credentials from this browser.

    Returns:
        {"remember": bool, "username": str, "password": str}

    No authentication occurs here. The user must still click Login.
    """
    try:
        # CookieController already reads the browser cookies when the Streamlit
        # session starts. Avoid calling refresh() here because it mounts a
        # second temporary component and delays the login form rendering.
        raw_value = auth_cookie_controller.get(
            REMEMBER_CREDENTIAL_COOKIE
        )

        if not raw_value:
            return {
                "remember": False,
                "username": "",
                "password": "",
            }

        if isinstance(raw_value, dict):
            profile = raw_value
        else:
            profile = json.loads(str(raw_value))

        if (
            not isinstance(profile, dict)
            or profile.get("version") != 1
            or profile.get("remember") is not True
            or not isinstance(profile.get("username"), str)
            or not isinstance(profile.get("password"), str)
        ):
            remove_saved_login_credentials()
            return {
                "remember": False,
                "username": "",
                "password": "",
            }

        return {
            "remember": True,
            "username": profile.get("username", ""),
            "password": profile.get("password", ""),
        }

    except Exception:
        return {
            "remember": False,
            "username": "",
            "password": "",
        }


def save_login_credentials(username, password):
    """
    Save credentials only after a successful login with Remember me checked.

    The saved values are used only to prefill the next login page. They never
    authenticate the user automatically.
    """
    profile = {
        "version": 1,
        "remember": True,
        "username": str(username or "").strip(),
        "password": str(password or ""),
        "saved_at": now_iso(),
    }

    expires_at = datetime.now(timezone.utc) + timedelta(
        days=REMEMBER_CREDENTIAL_DAYS
    )

    auth_cookie_controller.set(
        REMEMBER_CREDENTIAL_COOKIE,
        json.dumps(profile),
        path="/",
        expires=expires_at,
        max_age=REMEMBER_CREDENTIAL_DAYS * 24 * 60 * 60,
        secure=True,
        same_site="strict",
    )


def remove_saved_login_credentials():
    """Remove all app-saved login credentials from this browser."""
    try:
        auth_cookie_controller.remove(
            REMEMBER_CREDENTIAL_COOKIE,
            path="/",
            secure=True,
            same_site="strict",
        )
    except Exception:
        pass


def clear_legacy_browser_login_data():
    """
    Remove storage values left by earlier experimental Remember Me versions.
    """
    components.html(
        """
        <script>
        (() => {
          try {
            const storage = window.parent.localStorage;
            storage.removeItem("atp_remembered_credentials_v1");
            storage.removeItem("atp_login_profile");
            storage.removeItem("atp_remember_session");
            storage.removeItem("atp_remember_username");
            storage.removeItem("atp_remember_enabled");
          } catch (error) {}
        })();
        </script>
        """,
        height=0,
        width=0,
    )


def clear_browser_login_profile():
    """
    Clear credentials only when Remember me is unchecked or login is invalid.
    """
    remove_saved_login_credentials()
    clear_legacy_browser_login_data()


def queue_login_cookie_action(action, username="", password="", remember=False):
    """
    Queue a browser-cookie change for the next authenticated render.

    Supported actions:
    - "save": save username/password/checked state
    - "clear": remove saved login credentials
    """
    st.session_state["_atp_pending_login_cookie_action"] = {
        "action": str(action or "").strip().lower(),
        "username": str(username or "").strip(),
        "password": str(password or ""),
        "remember": bool(remember),
    }


def process_pending_login_cookie_action():
    """
    Execute a queued cookie action without immediately rerunning.

    This lets the CookieController frontend component finish writing/removing
    the cookie before the page is closed or refreshed.
    """
    pending = st.session_state.pop(
        "_atp_pending_login_cookie_action",
        None,
    )

    if not isinstance(pending, dict):
        return

    action = str(pending.get("action") or "").strip().lower()

    if action == "save":
        username = str(pending.get("username") or "").strip()
        password = str(pending.get("password") or "")

        if username and password:
            save_login_credentials(username, password)
            save_authenticated_session(username, remember=True)
            clear_legacy_browser_login_data()

    elif action == "session":
        username = str(pending.get("username") or "").strip()
        if username:
            save_authenticated_session(
                username,
                remember=bool(pending.get("remember")),
            )

    elif action == "clear":
        clear_browser_login_profile()
        username = str(pending.get("username") or "").strip()
        if username:
            save_authenticated_session(username, remember=False)


def install_login_autofill_support():
    """
    Disable competing browser autofill behavior.

    The login fields are prefilled by Python from the saved cookie, so no
    browser-side redirect, auto-login, st.stop(), or checkbox manipulation is
    needed.
    """
    components.html(
        """
        <script>
        (() => {
          const root = window.parent;
          const doc = root.document;
          const KEY = "__atpManualCredentialLoginV1";

          try { root[KEY]?.cleanup?.(); } catch (error) {}

          let stopped = false;
          let timerId = null;
          let attempts = 0;

          function configure() {
            if (stopped) return;

            const forms = Array.from(
              doc.querySelectorAll(
                'form[data-testid="stForm"], div[data-testid="stForm"]'
              )
            );

            for (const form of forms) {
              const inputs = Array.from(form.querySelectorAll("input"));
              const usernameInput = inputs.find(
                (input) => input.type === "text"
              );
              const passwordInput = inputs.find(
                (input) => input.type === "password"
              );

              if (usernameInput && passwordInput) {
                form.setAttribute("autocomplete", "off");
                usernameInput.setAttribute("autocomplete", "off");
                usernameInput.setAttribute("autocapitalize", "none");
                usernameInput.setAttribute("spellcheck", "false");
                passwordInput.setAttribute(
                  "autocomplete",
                  "new-password"
                );
                return;
              }
            }

            attempts += 1;
            if (attempts < 50) {
              timerId = root.setTimeout(configure, 100);
            }
          }

          configure();

          function cleanup() {
            stopped = true;
            if (timerId) {
              try { root.clearTimeout(timerId); } catch (error) {}
            }
          }

          root[KEY] = { cleanup };
          window.addEventListener(
            "beforeunload",
            cleanup,
            { once: true }
          );
        })();
        </script>
        """,
        height=0,
        width=0,
    )


AUTH_SESSION_COOKIE = "atp_authenticated_session_v1"
AUTH_SESSION_HOURS = 12


def _auth_session_signing_key():
    """Return a stable server-only key used to sign browser auth sessions."""
    configured = get_optional_secret("AUTH_SESSION_SECRET")
    if configured:
        return configured.encode("utf-8")

    # Backward-compatible fallback so the fix works without requiring a new
    # Streamlit secret immediately. OPENAI_API_KEY remains server-side only.
    return hashlib.sha256(str(api_key).encode("utf-8")).digest()


def _sign_auth_session_payload(payload_text):
    return hmac.new(
        _auth_session_signing_key(),
        str(payload_text).encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()


def save_authenticated_session(username, remember=False):
    """
    Save a signed browser session so Streamlit websocket/session resets do not
    unexpectedly return an authenticated user to the login page.

    Unchecked Remember Me creates a browser-session cookie. Checked Remember Me
    creates a persistent cookie matching the 30-day remembered-login period.
    """
    username = str(username or "").strip()
    if not username:
        return

    issued_at = int(time.time())
    lifetime_seconds = (
        REMEMBER_CREDENTIAL_DAYS * 24 * 60 * 60
        if remember
        else AUTH_SESSION_HOURS * 60 * 60
    )
    payload = {
        "version": 1,
        "username": username,
        "issued_at": issued_at,
        "expires_at": issued_at + lifetime_seconds,
        "remember": bool(remember),
    }
    payload_text = json.dumps(payload, separators=(",", ":"), sort_keys=True)
    envelope = {
        "payload": payload,
        "signature": _sign_auth_session_payload(payload_text),
    }

    cookie_kwargs = {
        "path": "/",
        "secure": True,
        "same_site": "strict",
    }
    if remember:
        expires_at = datetime.now(timezone.utc) + timedelta(
            days=REMEMBER_CREDENTIAL_DAYS
        )
        cookie_kwargs.update({
            "expires": expires_at,
            "max_age": REMEMBER_CREDENTIAL_DAYS * 24 * 60 * 60,
        })

    auth_cookie_controller.set(
        AUTH_SESSION_COOKIE,
        json.dumps(envelope),
        **cookie_kwargs,
    )


def remove_authenticated_session():
    try:
        auth_cookie_controller.remove(
            AUTH_SESSION_COOKIE,
            path="/",
            secure=True,
            same_site="strict",
        )
    except Exception:
        pass


def _load_authenticated_user(username):
    """Load one active user and restore permission state."""
    result = (
        supabase
        .table("users")
        .select("*")
        .eq("username", str(username or "").strip())
        .eq("active", True)
        .limit(1)
        .execute()
    )
    if not result.data:
        return False

    user = result.data[0]
    st.session_state.logged_in = True
    st.session_state.username = user["username"]
    st.session_state.role = str(user.get("role") or "staff").lower()
    st.session_state.workspace_permissions = effective_workspace_permissions(
        st.session_state.role,
        user.get("workspace_permissions"),
    )
    st.session_state.feature_permissions = effective_feature_permissions(
        st.session_state.role,
        user.get("feature_permissions"),
    )
    st.session_state.setdefault("messages", [])
    st.session_state.setdefault("conversation_id", None)
    return True


def restore_login_session():
    """
    Restore a valid signed login after Streamlit creates a new Python session.

    This specifically protects mobile Safari and long uploads, where a websocket
    reconnect can otherwise clear session_state and incorrectly show Login.
    """
    try:
        raw_value = auth_cookie_controller.get(AUTH_SESSION_COOKIE)
        if not raw_value:
            return False

        envelope = raw_value if isinstance(raw_value, dict) else json.loads(str(raw_value))
        if not isinstance(envelope, dict):
            raise ValueError("Invalid auth-session envelope")

        payload = envelope.get("payload")
        signature = str(envelope.get("signature") or "")
        if not isinstance(payload, dict) or not signature:
            raise ValueError("Incomplete auth-session envelope")

        payload_text = json.dumps(payload, separators=(",", ":"), sort_keys=True)
        expected = _sign_auth_session_payload(payload_text)
        if not hmac.compare_digest(signature, expected):
            raise ValueError("Invalid auth-session signature")

        if payload.get("version") != 1:
            raise ValueError("Unsupported auth-session version")
        if int(payload.get("expires_at") or 0) <= int(time.time()):
            raise ValueError("Expired auth session")

        username = str(payload.get("username") or "").strip()
        if not username or not _load_authenticated_user(username):
            raise ValueError("User is inactive or missing")

        st.session_state["_atp_session_remembered"] = bool(payload.get("remember"))
        diagnostic_log("login_session_restored", username=username)
        return True
    except Exception as error:
        diagnostic_log("login_session_restore_failed", error=str(error))
        remove_authenticated_session()
        return False


def logout_user():
    """
    Log out of the current Streamlit session.

    Saved credentials are intentionally kept so a user who previously checked
    Remember me can return to a prefilled login page and manually sign in.
    """
    try:
        st.query_params.clear()
    except Exception:
        pass

    diagnostic_log(
        "logout_requested",
        username=st.session_state.get("username"),
        conversation_id=st.session_state.get("conversation_id"),
    )
    remove_authenticated_session()
    st.session_state.logged_in = False
    st.session_state.messages = []
    st.session_state.conversation_id = None


