all_workspace_items = [
    ("technical", "🔧", "Technical Support"),
    ("sales", "📈", "Sales"),
    ("marketing", "📣", "Marketing"),
    ("graphic", "🎨", "Graphic Marketing"),
    ("knowledge", "🧠", "Knowledge Submission"),
    ("product_library", "📦", "Product Library"),
    ("admin", "⚙️", "Admin Panel"),
]

workspace_items = [
    item
    for item in all_workspace_items
    if user_can_access_workspace(item[0])
]

# Defensive fallback; effective permissions normally guarantee one workspace.
if not workspace_items:
    workspace_items = [("technical", "🔧", "Technical Support")]

valid_assistants = [
    f"{icon} {label}"
    for _, icon, label in workspace_items
]

if (
    "current_assistant" not in st.session_state
    or st.session_state.current_assistant not in valid_assistants
):
    st.session_state.current_assistant = valid_assistants[0]

st.sidebar.markdown(
    '<div class="workspace-title">AutoTecPro AI</div>',
    unsafe_allow_html=True,
)


def switch_workspace(assistant_name):
    """
    Update workspace state before Streamlit's normal button rerun.

    Using a callback avoids the extra explicit rerun that previously caused a
    second full page refresh and made navigation feel less smooth.
    """
    if st.session_state.get("current_assistant") == assistant_name:
        return

    # Preserve authentication explicitly before changing workspace state.
    # This is especially important on iOS Safari, where a navigation rerun can
    # coincide with a websocket reconnect.
    username = str(st.session_state.get("username") or "").strip()
    if username:
        try:
            save_authenticated_session(
                username,
                remember=bool(st.session_state.get("_atp_session_remembered")),
            )
        except Exception as error:
            diagnostic_log("workspace_auth_refresh_failed", error=str(error))

    st.session_state.messages = []
    st.session_state.conversation_id = None
    st.session_state.current_assistant = assistant_name
    st.session_state.chat_file_uploader_generation = int(
        st.session_state.get("chat_file_uploader_generation", 0)
    ) + 1
    clear_managed_uploads(
        "chat_managed_uploads",
        "chat_managed_upload_generation",
    )


for slug, icon, label in workspace_items:
    assistant_name = f"{icon} {label}"
    is_selected = (
        st.session_state.current_assistant
        == assistant_name
    )

    nav_state = "active" if is_selected else "idle"

    with st.sidebar.container(
        key=f"workspace_nav_{nav_state}_{slug}"
    ):
        st.button(
            label,
            key=f"workspace_button_{slug}",
            use_container_width=True,
            on_click=switch_workspace,
            args=(assistant_name,),
            disabled=is_selected,
        )

assistant = st.session_state.current_assistant

_current_workspace_slug = next(
    (
        slug
        for slug, icon, label in workspace_items
        if f"{icon} {label}" == assistant
    ),
    "technical",
)

# Persist the active workspace in the parent DOM on every completed Python rerun.
# This is intentionally not a temporary transition flag: recent Streamlit builds
# can retain keyed nodes from a previous conditional branch after reconciliation.
# A permanent marker lets workspace-scoped CSS keep those stale nodes hidden.
components.html(
    f"""
    <script>
    (() => {{
        const body = window.parent.document.body;
        body.dataset.atpCurrentWorkspace = {json.dumps(_current_workspace_slug)};
    }})();
    </script>
    """,
    height=0,
    width=0,
)

# Persistent workspace DOM isolation.
#
# Recent Streamlit builds can retain individual keyed child widgets from a
# previous conditional branch, even after the parent page container is replaced.
# Keep every workspace-specific root and child widget hidden outside its active
# workspace. This is intentionally persistent and avoids timers, observers,
# loading overlays, and other transition workarounds.
