@st.cache_data(ttl=900, max_entries=64, show_spinner=False)
def _normalize_uploaded_image_bytes_cached(
    raw,
    original_mime_type,
    max_dimension=2200,
    quality=90,
):
    """
    Cache CPU-heavy image normalization by immutable file bytes.

    The returned bytes and MIME type intentionally match the existing upload
    pipeline so this optimization does not change saved history or API input.
    """
    try:
        if Image is None or ImageOps is None:
            return raw, original_mime_type or "image/jpeg"

        image = Image.open(io.BytesIO(raw))
        image = ImageOps.exif_transpose(image)

        if image.mode not in ("RGB", "RGBA"):
            image = image.convert("RGB")

        width, height = image.size
        largest = max(width, height)
        if largest > max_dimension:
            scale = max_dimension / float(largest)
            new_size = (
                max(1, int(width * scale)),
                max(1, int(height * scale)),
            )
            image = image.resize(new_size, Image.LANCZOS)

        output = io.BytesIO()

        # Preserve transparency for PNG; otherwise use JPEG.
        if image.mode == "RGBA":
            image.save(output, format="PNG", optimize=True)
            mime_type = "image/png"
        else:
            image = image.convert("RGB")
            image.save(output, format="JPEG", quality=quality, optimize=True)
            mime_type = "image/jpeg"

        return output.getvalue(), mime_type
    except Exception:
        return raw, original_mime_type or "image/jpeg"


def normalize_uploaded_image_bytes(uploaded_file, max_dimension=2200, quality=90):
    """
    Normalize uploaded JPG/PNG images so EXIF orientation is applied consistently.

    Results are cached by the immutable upload bytes, preventing repeated PIL
    decoding, resizing, and encoding during Streamlit reruns.
    """
    try:
        raw = uploaded_file.getvalue()
        original_mime_type = getattr(uploaded_file, "type", "image/jpeg")
        return _normalize_uploaded_image_bytes_cached(
            raw,
            original_mime_type,
            max_dimension=max_dimension,
            quality=quality,
        )
    except Exception:
        return b"", "image/jpeg"


def normalized_image_data_url(uploaded_file):
    normalized_bytes, mime_type = normalize_uploaded_image_bytes(uploaded_file)
    encoded = base64.b64encode(normalized_bytes).decode()
    return f"data:{mime_type};base64,{encoded}"


def image_to_data_url(uploaded_file):
    return normalized_image_data_url(uploaded_file)


IMAGE_MARKER_PREFIX = "[[ATP_IMAGES_JSON:"

DOCUMENT_MARKER_PREFIX = "[[[ATPDOCS_JSON:"
DOCUMENT_MARKER_SUFFIX = ":ATPDOCS_JSON]]]"

IMAGE_MARKER_SUFFIX = "]]"


LEARNING_DISPLAY_LABELS = {
    "record_type": "Record Type",
    "title": "Title",
    "vehicle_make": "Vehicle Make",
    "vehicle_model": "Vehicle Model",
    "year_range": "Year Range",
    "year": "Year",
    "make": "Make",
    "model": "Model",
    "product_name": "Product Name",
    "product": "Product",
    "sku": "SKU",
    "factory_system": "Factory System",
    "symptom_or_topic": "Symptom / Topic",
    "included_parts": "Included Parts",
    "part_numbers": "Part Numbers",
    "connector_details": "Connector Details",
    "compatibility_conditions": "Compatibility Conditions",
    "diagnostic_steps": "Diagnostic Steps",
    "confirmed_solution": "Confirmed Solution",
    "installation_notes": "Installation Notes",
    "warnings": "Warnings",
    "evidence": "Evidence",
    "uncertain_information": "Needs Confirmation",
    "needs_confirmation": "Needs Confirmation",
    "identity": "Identity",
    "facts": "Verified Facts",
    "parts_or_features": "Parts / Features",
    "conditions": "Conditions",
    "procedure_or_response": "Procedure / Approved Response",
    "warnings_or_restrictions": "Warnings / Restrictions",
    "effective_dates": "Effective Dates",
    "search_keywords": "Search Keywords",
    "customer_reply_draft": "Customer Reply Draft",
}


def _friendly_learning_value(value):
    """Convert internal snake_case enum values into readable UI text."""
    clean_value = str(value or "").strip()
    if re.fullmatch(r"[a-z][a-z0-9_]*", clean_value):
        return clean_value.replace("_", " ").title()
    return clean_value


def format_learning_record_for_display(text):
    """Hide internal learning-field names and remove duplicate section headings.

    This formatter activates only for structured learning-style responses. Ordinary
    chat content, code, URLs, and technical values remain unchanged. Both current
    ``needs_confirmation`` output and older ``uncertain_information`` output are
    rendered as one user-facing ``Needs Confirmation`` section.
    """
    value = str(text or "")
    if not value.strip():
        return value

    field_pattern = re.compile(
        r"^(?P<indent>\s*)(?:[-*]\s*)?(?P<key>"
        + "|".join(re.escape(key) for key in LEARNING_DISPLAY_LABELS)
        + r")\s*:\s*(?P<value>.*)$",
        flags=re.IGNORECASE,
    )
    parsed = []
    recognized_count = 0
    for line in value.splitlines():
        match = field_pattern.match(line)
        parsed.append((line, match))
        if match:
            recognized_count += 1

    has_customer_reply = any(
        match and match.group("key").lower() == "customer_reply_draft"
        for _, match in parsed
    )
    has_confirmation_field = any(
        match and match.group("key").lower() in {
            "needs_confirmation", "uncertain_information"
        }
        for _, match in parsed
    )
    if recognized_count < 2 and not has_customer_reply and not has_confirmation_field:
        return value

    display_heading_lookup = {
        label.casefold(): label
        for label in set(LEARNING_DISPLAY_LABELS.values())
    }
    output_lines = []
    last_section_label = ""

    def append_heading(label):
        nonlocal last_section_label
        normalized = str(label or "").strip().casefold()
        if normalized and normalized == last_section_label:
            return
        while output_lines and not output_lines[-1].strip():
            output_lines.pop()
        if output_lines:
            output_lines.append("")
        output_lines.extend([f"### {label}", ""])
        last_section_label = normalized

    for original_line, match in parsed:
        stripped = original_line.strip()

        # Normalize already-human-readable section headings so an immediately
        # following internal key cannot create the same heading a second time.
        plain_heading = re.sub(r"^#{1,6}\s*", "", stripped)
        plain_heading = plain_heading.strip("* ").rstrip(":").strip()
        heading_label = display_heading_lookup.get(plain_heading.casefold())
        if heading_label and not match:
            append_heading(heading_label)
            continue

        if not match:
            output_lines.append(original_line)
            if stripped:
                last_section_label = ""
            continue

        key = match.group("key").lower()
        raw_value = match.group("value").strip()
        label = LEARNING_DISPLAY_LABELS[key]

        if key == "customer_reply_draft":
            append_heading(label)
            if raw_value:
                output_lines.append(raw_value)
            continue

        if key == "record_type":
            raw_value = _friendly_learning_value(raw_value)

        if not raw_value:
            append_heading(label)
            continue

        # A valued field is a compact labelled fact, not a separate section.
        output_lines.append(f"**{label}:** {raw_value}")
        last_section_label = ""

    result = "\n".join(output_lines)
    result = re.sub(r"\n{3,}", "\n\n", result)
    return result.strip()


def clean_visible_chat_text(text):
    """
    Remove raw/escaped HTML artifacts from model output and old saved messages.
    """
    value = str(text or "")

    try:
        marker_pattern = re.escape(IMAGE_MARKER_PREFIX) + r".*?" + re.escape(IMAGE_MARKER_SUFFIX)
        value = re.sub(marker_pattern, "", value, flags=re.DOTALL)
        document_marker_pattern = (
            re.escape(DOCUMENT_MARKER_PREFIX)
            + r".*?"
            + re.escape(DOCUMENT_MARKER_SUFFIX)
        )
        value = re.sub(
            document_marker_pattern,
            "",
            value,
            flags=re.DOTALL,
        )
    except Exception:
        pass

    value = (
        value.replace("&lt;", "<")
             .replace("&gt;", ">")
             .replace("&#60;", "<")
             .replace("&#62;", ">")
    )

    tag_names = r"(div|p|span|section|article|main|body|html|details|summary|button|script|svg|path|rect|style|code|pre)"

    # Remove fenced blocks containing HTML fragments.
    value = re.sub(
        r"```(?:html|HTML|text)?[\s\S]*?(?:</?\s*" + tag_names + r"\b)[\s\S]*?```",
        "",
        value,
        flags=re.IGNORECASE,
    )

    # Remove raw tags anywhere.
    value = re.sub(r"</?\s*" + tag_names + r"\b[^>]*>", "", value, flags=re.IGNORECASE)

    cleaned = []
    for line in value.splitlines():
        stripped = line.strip()
        compact = stripped.replace("`", "").replace(" ", "").lower()

        if compact in {
            "```", "```html", "```text",
            "</div>", "<div>", "</p>", "<p>", "</span>", "<span>",
            "</details>", "<details>", "</summary>", "<summary>",
            "</button>", "<button>", "</script>", "<script>",
            "</svg>", "<svg>", "</path>", "<path>", "</rect>", "<rect>",
            "</pre>", "<pre>", "</code>", "<code>"
        }:
            continue

        if re.fullmatch(r"[</>\s`]+", stripped):
            continue

        cleaned.append(line)

    value = "\n".join(cleaned)
    value = re.sub(r"\n{3,}", "\n\n", value)
    return value.strip()


@st.cache_data(ttl=900, max_entries=64, show_spinner=False)
def _make_image_preview_data_url_cached(
    raw,
    original_mime_type,
    max_size=(1200, 1200),
    quality=76,
):
    """Cache preview resizing and Base64 encoding across Streamlit reruns."""
    mime_type = original_mime_type or "image/jpeg"

    if Image is not None:
        try:
            img = Image.open(io.BytesIO(raw))
            img.thumbnail(max_size)
            output = io.BytesIO()

            if img.mode in ("RGBA", "LA", "P"):
                img = img.convert("RGBA")
                img.save(output, format="PNG", optimize=True)
                mime_type = "image/png"
            else:
                img = img.convert("RGB")
                img.save(output, format="JPEG", quality=quality, optimize=True)
                mime_type = "image/jpeg"

            raw = output.getvalue()
        except Exception:
            pass

    encoded = base64.b64encode(raw).decode()
    return f"data:{mime_type};base64,{encoded}"


def make_image_preview_data_url(uploaded_file, max_size=(1200, 1200), quality=76):
    raw = uploaded_file.getvalue()
    mime_type = getattr(uploaded_file, "type", "") or "image/jpeg"
    return _make_image_preview_data_url_cached(
        raw,
        mime_type,
        max_size=max_size,
        quality=quality,
    )


def get_uploaded_image_previews(uploaded_files):
    """
    Build normalized image previews for chat history.

    EXIF orientation is applied before the preview is encoded. The preview schema
    intentionally remains {"name", "data_url"} because the existing history
    parser and renderer expect those exact keys.
    """
    previews = []

    for uploaded_file in uploaded_files or []:
        mime_type = str(getattr(uploaded_file, "type", "") or "").lower()
        file_name = str(getattr(uploaded_file, "name", "image"))

        if not mime_type.startswith("image/"):
            continue

        try:
            normalized_bytes, normalized_mime = normalize_uploaded_image_bytes(uploaded_file)
            if not normalized_bytes:
                continue

            encoded = base64.b64encode(normalized_bytes).decode()
            previews.append({
                "name": file_name,
                "data_url": f"data:{normalized_mime};base64,{encoded}",
            })
        except Exception:
            continue

    return previews



def _human_file_size(size_bytes):
    try:
        value = max(0, int(size_bytes or 0))
    except (TypeError, ValueError):
        value = 0
    if value < 1024:
        return f"{value} B"
    if value < 1024 * 1024:
        return f"{value / 1024:.1f} KB"
    return f"{value / (1024 * 1024):.1f} MB"



