def _document_settings_state_key(workspace=None):
    active = str(workspace or st.session_state.get("current_assistant") or assistant or "")
    digest = hashlib.sha256(active.encode("utf-8")).hexdigest()[:12]
    return f"document_settings_{digest}"


def get_document_creator_settings(workspace=None):
    active = str(workspace or st.session_state.get("current_assistant") or assistant or "")
    defaults = dict(
        DOCUMENT_WORKSPACE_DEFAULTS.get(
            active,
            {
                "format": "pdf",
                "include_logo": False,
                "include_company_info": False,
                "watermark": "",
                "style": "Professional",
            },
        )
    )
    state_key = _document_settings_state_key(active)
    saved = st.session_state.get(state_key)
    if isinstance(saved, dict):
        defaults.update({
            key: saved.get(key, defaults[key])
            for key in defaults
        })
    defaults["format"] = str(defaults.get("format") or "pdf").lower()
    if defaults["format"] not in {"pdf", "docx", "pptx", "xlsx", "csv"}:
        defaults["format"] = "pdf"
    defaults["style"] = str(defaults.get("style") or "Professional")
    return defaults


def save_document_creator_settings(settings, workspace=None):
    clean = get_document_creator_settings(workspace)
    if isinstance(settings, dict):
        clean.update(settings)
    st.session_state[_document_settings_state_key(workspace)] = clean
    return clean


def _conversation_document_text(messages, current_answer=""):
    parts = []
    for message in messages or []:
        if not isinstance(message, dict):
            continue
        role = str(message.get("role") or "").strip().lower()
        content = str(message.get("content") or "")
        content, _ = extract_documents_from_message_content(content)
        content, _ = extract_images_from_message_content(content)
        content = clean_visible_chat_text(content).strip()
        if not content:
            continue
        label = "User" if role == "user" else "AutoTecPro AI"
        parts.append(f"{label}\n{content}")
    if str(current_answer or "").strip():
        parts.append(f"AutoTecPro AI\n{clean_visible_chat_text(current_answer).strip()}")
    return "\n\n".join(parts).strip()


def _document_request_uses_conversation(prompt_text):
    value = re.sub(r"\s+", " ", str(prompt_text or "")).strip().lower()
    return any(
        phrase in value
        for phrase in (
            "this conversation",
            "the conversation",
            "current conversation",
            "this chat",
            "current chat",
            "entire conversation",
            "whole conversation",
            "convert this to a document",
            "convert this into a document",
            "turn this into a document",
            "export this as a document",
            "save this as a document",
        )
    )


def _document_widget_prefix(workspace):
    active = str(
        workspace
        or st.session_state.get("current_assistant")
        or assistant
        or ""
    )
    digest = hashlib.sha256(active.encode("utf-8")).hexdigest()[:12]
    return f"document_widget_{digest}_"


def _document_settings_from_widget_values(
    format_key,
    logo_key,
    company_key,
    watermark_key,
    style_key,
):
    format_labels = {
        "PDF": "pdf",
        "Word": "docx",
        "PowerPoint": "pptx",
        "Excel": "xlsx",
        "CSV": "csv",
    }
    style_value = str(
        st.session_state.get(style_key) or "Professional"
    )
    if style_value not in {
        "Professional",
        "Minimal",
        "Presentation",
    }:
        style_value = "Professional"

    return {
        "format": format_labels.get(
            str(st.session_state.get(format_key) or "PDF"),
            "pdf",
        ),
        "include_logo": bool(
            st.session_state.get(logo_key, False)
        ),
        "include_company_info": bool(
            st.session_state.get(company_key, False)
        ),
        "watermark": (
            "CONFIDENTIAL"
            if bool(st.session_state.get(watermark_key, False))
            else ""
        ),
        "style": style_value,
    }


def _apply_document_settings(
    workspace,
    format_key,
    logo_key,
    company_key,
    watermark_key,
    style_key,
):
    """
    Save all settings together only after Apply is clicked.

    This replaces the previous change-by-change callback path and prevents
    historical cards from unexpectedly overwriting the active workspace
    settings during Streamlit reruns.
    """
    updated = _document_settings_from_widget_values(
        format_key,
        logo_key,
        company_key,
        watermark_key,
        style_key,
    )
    save_document_creator_settings(updated, workspace)


