def process_pending_graphic_regeneration():
    """Generate another version from a saved image's original prompt."""
    pending = st.session_state.pop(
        "pending_graphic_regeneration",
        None,
    )
    if not pending:
        return False

    prompt_text = str(pending.get("prompt") or "").strip()
    if not prompt_text:
        st.warning("The original generation prompt is unavailable.")
        return False

    try:
        with st.spinner("Creating another image version..."):
            images = generate_graphic_marketing_images(prompt_text, [])
            answer_text = generated_image_answer_text(
                images,
                regenerated=True,
            )
            stored_content = answer_text + serialize_images_marker(images)

            st.session_state.messages.append({
                "role": "assistant",
                "content": stored_content,
            })

            if history_is_enabled():
                try:
                    save_message(
                        st.session_state.conversation_id,
                        "assistant",
                        stored_content,
                    )
                except Exception as error:
                    st.warning(
                        f"Generated image was not saved to history: {error}"
                    )
    except Exception as error:
        st.error(str(error))
        return False

    st.session_state.scroll_to_bottom = True
    st.rerun()
    return True


def remove_technical_pricing(text):
    """
    Remove monetary values and price-focused lines from Technical Support output.

    This is a final safety layer in addition to the Technical Support prompt and
    restricted WooCommerce order sanitization. Product/model numbers such as
    14.4, 15.6, 17.2, 8GB, and 128GB are preserved.
    """
    value = str(text or "")
    if not value:
        return value

    money_patterns = [
        r"(?i)(?:CAD|USD|C\$|US\$)\s*\$?\s*\d[\d,]*(?:\.\d{1,2})?",
        r"(?i)\$\s*\d[\d,]*(?:\.\d{1,2})?",
        r"(?i)\d[\d,]*(?:\.\d{1,2})?\s*(?:CAD|USD)\b",
    ]
    for pattern in money_patterns:
        value = re.sub(pattern, "[price omitted]", value)

    price_terms = re.compile(
        r"(?i)\b(?:price|pricing|cost|subtotal|total price|sale price|"
        r"regular price|retail price|wholesale price|amount due)\b"
    )

    cleaned_lines = []
    for line in value.splitlines():
        if price_terms.search(line) and (
            "[price omitted]" in line
            or re.search(r"(?i)(?:CAD|USD|C\$|US\$|\$)", line)
        ):
            continue
        cleaned_lines.append(line)

    value = "\n".join(cleaned_lines)
    value = re.sub(r"(?:\n\s*){3,}", "\n\n", value).strip()
    return value



def _workspace_response_formatting_rules():
    """Shared presentation rules for readable operational AI responses."""
    return """

RESPONSE PRESENTATION RULES:
- Organize the answer for fast staff scanning. Do not write a wall of text.
- Use short Markdown section headings beginning with ## for major sections.
- Put one blank line before and after every major section.
- Use bullet points for specifications, findings, requirements, options, risks,
  and next steps. Keep one idea per bullet.
- Use numbered lists only when order matters, such as troubleshooting or setup.
- Use **bold labels** for important values such as status, model, order number,
  recommendation, and required confirmation.
- Keep paragraphs short: normally one to three sentences per paragraph.
- When several label-and-value facts are needed, place each fact on its own
  bullet or line instead of combining them into one long sentence.
- Use a Markdown table when comparing two or more products, options, vehicle
  configurations, specifications, compatibility results, or order records.
- Keep tables compact. Use clear column labels and do not create a table for a
  single simple fact or when a short list is easier to read.
- Put customer-facing drafts under a separate ## Customer Reply Draft heading.
  Prefix each draft paragraph with > so it is valid Markdown blockquote content,
  ready to copy and send. Do not place bullets, analysis notes, or internal
  instructions inside the draft.
- For Vehicle Configuration, Vehicle Identification, Recommended Product,
  Compatibility, Specifications, and product comparisons, prefer a compact
  Markdown table whenever three or more label-and-value facts are present.
- Every bullet and every numbered step must begin on a new physical line.
  Never place multiple bullet points or numbered steps on the same line.
- Do not add decorative separators after every section, excessive emoji, HTML,
  or code fences. Preserve all facts, uncertainty, warnings, and required steps.
"""

