def get_learning_vector_store_id(selected_assistant):
    if is_sales_workspace(selected_assistant):
        return SALES_VECTOR_STORE_ID
    if is_marketing_workspace(selected_assistant):
        return MARKETING_VECTOR_STORE_ID
    return TECHNICAL_VECTOR_STORE_ID


def normalize_text_for_match(value):
    value = str(value or "").lower()
    value = re.sub(r"[^a-z0-9\s]", " ", value)
    value = re.sub(r"\s+", " ", value).strip()
    return value


def text_similarity(a, b):
    return SequenceMatcher(None, normalize_text_for_match(a), normalize_text_for_match(b)).ratio()


def extract_json_object(raw_text):
    if not raw_text:
        return {}
    text = str(raw_text).strip()
    try:
        return json.loads(text)
    except Exception:
        pass
    match = re.search(r"\{.*\}", text, re.DOTALL)
    if match:
        try:
            return json.loads(match.group(0))
        except Exception:
            return {}
    return {}


def detect_vehicle_basic(text):
    """
    Detect the most specific AutoTecPro vehicle/model mentioned in text.

    Model names are checked before broad manufacturers so a phrase such as
    "2013 Dodge RAM" is classified as "2013 Dodge RAM", not only "DODGE".
    """
    value = re.sub(r"\s+", " ", str(text or "")).strip()
    if not value:
        return ""

    lower_value = value.lower()
    year_match = re.search(r"\b(19[8-9]\d|20[0-2]\d)\b", lower_value)
    year = year_match.group(1) if year_match else ""

    vehicle_patterns = [
        (r"\b(?:chevrolet|chevy)\s+silverado\b|\bsilverado\b", "Chevrolet Silverado"),
        (r"\b(?:gmc\s+)?sierra\b", "GMC Sierra"),
        (r"\b(?:chevrolet|chevy)\s+tahoe\b|\btahoe\b", "Chevrolet Tahoe"),
        (r"\b(?:chevrolet|chevy)\s+suburban\b|\bsuburban\b", "Chevrolet Suburban"),
        (r"\b(?:gmc\s+)?yukon\b", "GMC Yukon"),
        (r"\bford\s+f[\s-]?150\b|\bf[\s-]?150\b", "Ford F-150"),
        (r"\bford\s+f[\s-]?250\b|\bf[\s-]?250\b", "Ford F-250"),
        (r"\bford\s+f[\s-]?350\b|\bf[\s-]?350\b", "Ford F-350"),
        (r"\bford\s+f[\s-]?450\b|\bf[\s-]?450\b", "Ford F-450"),
        (r"\b(?:dodge|ram)\s+ram\b|\bdodge\s+ram\b|\bram\s+(?:1500|2500|3500)\b|\bram\b", "Dodge RAM"),
        (r"\bdodge\s+durango\b|\bdurango\b", "Dodge Durango"),
        (r"\btoyota\s+tundra\b|\btundra\b", "Toyota Tundra"),
        (r"\binfiniti\s+q50\b|\bq50\b", "Infiniti Q50"),
        (r"\binfiniti\s+q60\b|\bq60\b", "Infiniti Q60"),
        (r"\baudi\s+a4\b|\ba4\b", "Audi A4"),
        (r"\baudi\s+a5\b|\ba5\b", "Audi A5"),
        (r"\bmercedes(?:-benz)?\s+(?:c[\s-]?class|c300)\b|\bc300\b", "Mercedes C-Class"),
        (r"\bmercedes(?:-benz)?\s+glc\b|\bglc\b", "Mercedes GLC"),
        (r"\bjeep\s+grand\s+cherokee\b|\bgrand\s+cherokee\b", "Jeep Grand Cherokee"),
    ]

    for pattern, label in vehicle_patterns:
        if re.search(pattern, lower_value, flags=re.IGNORECASE):
            return f"{year} {label}".strip()

    manufacturer_patterns = [
        (r"\bchevrolet\b|\bchevy\b", "Chevrolet"),
        (r"\bgmc\b", "GMC"),
        (r"\bford\b", "Ford"),
        (r"\bdodge\b", "Dodge"),
        (r"\bram\b", "Dodge RAM"),
        (r"\btoyota\b", "Toyota"),
        (r"\binfiniti\b", "Infiniti"),
        (r"\baudi\b", "Audi"),
        (r"\bmercedes(?:-benz)?\b", "Mercedes-Benz"),
        (r"\bjeep\b", "Jeep"),
    ]

    for pattern, label in manufacturer_patterns:
        if re.search(pattern, lower_value, flags=re.IGNORECASE):
            return f"{year} {label}".strip()

    return ""


def is_missing_learning_vehicle(value):
    """Return True when an extracted vehicle value is empty or non-informative."""
    normalized = re.sub(
        r"[^a-z0-9]+",
        " ",
        str(value or "").lower(),
    ).strip()

    missing_values = {
        "",
        "n a",
        "na",
        "none",
        "null",
        "unknown",
        "unspecified",
        "not specified",
        "vehicle not specified",
        "not applicable",
        "general",
        "general knowledge",
    }
    return normalized in missing_values


def general_learning_label(selected_assistant):
    """Choose a meaningful label for reusable knowledge with no vehicle."""
    assistant_label = clean_assistant_label(selected_assistant).lower()

    if "sales" in assistant_label or "marketing" in assistant_label:
        return "General Sales"
    if "technical" in assistant_label or "support" in assistant_label:
        return "General Technical"
    return "General Knowledge"


def resolve_learning_vehicle(
    extracted_vehicle,
    question="",
    answer="",
    issue="",
    keywords="",
    product="",
    selected_assistant="",
):
    """
    Resolve the best learning metadata label without inventing a vehicle.

    The AI-extracted value is accepted only when informative. Otherwise the
    original conversation fields are scanned. Truly non-vehicle knowledge is
    assigned a workspace-specific general label.
    """
    extracted_value = str(extracted_vehicle or "").strip()
    if not is_missing_learning_vehicle(extracted_value):
        # Prefer a standardized model name when the AI value contains one.
        detected_from_extracted = detect_vehicle_basic(extracted_value)
        return detected_from_extracted or extracted_value[:160]

    combined_text = " ".join(
        str(value or "")
        for value in (question, answer, issue, keywords, product)
    )
    detected = detect_vehicle_basic(combined_text)
    if detected:
        return detected

    return general_learning_label(selected_assistant)


def display_learning_vehicle(row):
    """
    Return a useful Admin display label for old and new learned records.

    Existing Supabase rows are not rewritten. Missing legacy metadata is
    inferred at display time from the source fields.
    """
    row = row or {}
    return resolve_learning_vehicle(
        row.get("vehicle"),
        question=row.get("source_question") or row.get("question"),
        answer=row.get("source_answer") or row.get("approved_answer"),
        issue=row.get("issue"),
        keywords=row.get("keywords"),
        product=row.get("product"),
        selected_assistant=row.get("assistant"),
    )



STAFF_CONFIRMED_SOLUTION_PHRASES = (
    "this fixed it",
    "that fixed it",
    "fixed the issue",
    "issue is fixed",
    "problem is fixed",
    "confirmed working",
    "confirmed it works",
    "customer confirmed",
    "customer tested",
    "tested and working",
    "final solution",
    "final resolution",
    "resolved by",
    "solution is",
    "the fix is",
    "we fixed it by",
    "working now after",
    "solved by",
    "this is the solution",
    "use this procedure",
)


def redact_learning_private_data(value):
    """
    Remove common customer-identifying information before learning or syncing.

    This is intentionally conservative. It protects email addresses, phone
    numbers, order references, tracking numbers, street-address labels, and
    explicit customer-name fields while preserving technical numbers such as
    model years, screen sizes, firmware versions, and part numbers.
    """
    text_value = str(value or "")

    # Email addresses.
    text_value = re.sub(
        r"\b[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}\b",
        "[REDACTED EMAIL]",
        text_value,
        flags=re.IGNORECASE,
    )

    # UPS and common Canada Post tracking formats.
    text_value = re.sub(
        r"\b1Z[A-Z0-9]{16}\b",
        "[REDACTED TRACKING]",
        text_value,
        flags=re.IGNORECASE,
    )
    text_value = re.sub(
        r"\b[A-Z]{2}\d{9}CA\b|\b\d{16}\b",
        "[REDACTED TRACKING]",
        text_value,
        flags=re.IGNORECASE,
    )

    # Explicit WooCommerce/order references.
    text_value = re.sub(
        r"\b(?:order|woocommerce)\s*(?:number|no\.?|#)?\s*[:#-]?\s*\d{3,12}\b",
        "[REDACTED ORDER]",
        text_value,
        flags=re.IGNORECASE,
    )
    text_value = re.sub(
        r"(?<![A-Za-z0-9])#\d{3,12}\b",
        "[REDACTED ORDER]",
        text_value,
    )

    # Phone numbers with separators or country codes. Requiring at least
    # 10 digits avoids removing most vehicle years, firmware, and part numbers.
    def _redact_phone(match):
        candidate = match.group(0)
        digit_count = len(re.sub(r"\D", "", candidate))
        return "[REDACTED PHONE]" if 10 <= digit_count <= 15 else candidate

    text_value = re.sub(
        r"(?<![A-Za-z0-9])(?:\+?\d[\d\s().-]{8,}\d)(?![A-Za-z0-9])",
        _redact_phone,
        text_value,
    )

    # Explicitly labelled personal fields and street-address lines.
    text_value = re.sub(
        r"(?im)^\s*(?:customer|customer name|name|email|phone|telephone|"
        r"shipping address|billing address|address)\s*:\s*.*$",
        "[REDACTED CUSTOMER DATA]",
        text_value,
    )

    # Canadian/US-style postal and ZIP codes when clearly labelled.
    text_value = re.sub(
        r"(?i)\b(?:postal code|postcode|zip code|zip)\s*:\s*"
        r"(?:[A-Z]\d[A-Z][ -]?\d[A-Z]\d|\d{5}(?:-\d{4})?)\b",
        "[REDACTED POSTAL CODE]",
        text_value,
    )

    return re.sub(r"\n{3,}", "\n\n", text_value).strip()


def detect_staff_confirmed_solution(message_text):
    """
    Identify messages where staff clearly provides or confirms a real solution.

    A plain question is not treated as confirmed knowledge.
    """
    normalized = re.sub(
        r"\s+",
        " ",
        str(message_text or "").strip().lower(),
    )

    if not normalized:
        return False

    if any(phrase in normalized for phrase in STAFF_CONFIRMED_SOLUTION_PHRASES):
        return True

    # Structured staff notes are also accepted.
    structured_patterns = (
        r"\bsolution\s*:\s*\S+",
        r"\bfinal\s+(?:fix|resolution)\s*:\s*\S+",
        r"\bconfirmed\s+(?:fix|solution)\s*:\s*\S+",
        r"\broot\s+cause\s*:\s*\S+.*\bfix\s*:\s*\S+",
    )
    return any(
        re.search(pattern, normalized, flags=re.IGNORECASE | re.DOTALL)
        for pattern in structured_patterns
    )


STAFF_TEACHING_SIGNAL_PATTERNS = (
    r"\blearn this\b",
    r"\bremember this\b",
    r"\bsave this (?:answer|reply|solution|information|knowledge)\b",
    r"\bthe correct (?:answer|reply|solution|information) is\b",
    r"\bcorrect answer\s*:",
    r"\bapproved answer\s*:",
    r"\bfinal answer\s*:",
    r"\buse this (?:answer|reply|solution)\b",
    r"\banswer the customer (?:like|with|using) this\b",
    r"\bthis is how we should (?:answer|reply|respond)\b",
    r"\binstead,? (?:say|reply|answer|use)\b",
    r"\bdo not say\b.+\b(?:say|use|answer)\b",
    r"\bcorrection\s*:",
    r"\bupdated (?:answer|reply|solution)\s*:",
    r"\bstaff note\s*:",
    r"\binternal knowledge\s*:",
)


def detect_staff_teaching_content(message_text):
    """Detect staff-authored corrections, approved replies, and reusable Q&A."""
    raw = str(message_text or "").strip()
    normalized = re.sub(r"\s+", " ", raw.lower()).strip()
    if not normalized:
        return False

    if any(re.search(pattern, normalized, flags=re.IGNORECASE | re.DOTALL)
           for pattern in STAFF_TEACHING_SIGNAL_PATTERNS):
        return True

    # A pasted support/sales/marketing answer often contains several question and
    # answer pairs without an explicit command. Require substantial content so a
    # normal customer question is never mistaken for staff-approved knowledge.
    question_marks = raw.count("?")
    answer_markers = len(re.findall(
        r"(?im)^\s*(?:answer|response|solution|reply)\s*[:\-]",
        raw,
    ))
    qa_headings = len(re.findall(
        r"(?im)^\s*(?:q(?:uestion)?\s*\d*|a(?:nswer)?\s*\d*)\s*[:\-]",
        raw,
    ))
    return bool(
        len(raw) >= 220
        and question_marks >= 2
        and (answer_markers >= 1 or qa_headings >= 2)
    )


def _learning_context_messages(max_messages=10):
    """Return recent redacted messages with role labels for correction learning."""
    messages = list(st.session_state.get("messages") or [])
    lines = []
    for message in messages[-max(1, int(max_messages or 10)):]:
        role = str(message.get("role") or "").strip().upper()
        content, _ = extract_images_from_message_content(message.get("content", ""))
        content = redact_learning_private_data(clean_visible_chat_text(content))
        if content:
            lines.append(f"{role}: {content}")
    return "\n\n".join(lines)


def detect_unlabeled_staff_final_reply(message_text, selected_assistant=None):
    """
    Detect a staff-authored final reply even when no ``learn this`` command is used.

    The heuristic intentionally requires recent conversation context: a customer
    inquiry followed by an AI draft, then a substantial answer-like staff message.
    This prevents a newly pasted customer email from being mistaken for approved
    company knowledge while allowing Technical, Sales, and Marketing to learn from
    the staff member's final corrected reply automatically.
    """
    workspace = _normalized_workspace_name(selected_assistant)
    if workspace not in {"technical support", "sales", "marketing"}:
        return False

    raw = str(message_text or "").strip()
    model_identifiers = extract_learning_model_identifiers(raw)
    if len(raw) < 60:
        return False
    if len(raw) < 140 and not model_identifiers:
        return False

    # A final reply usually contains several complete statements, Q&A formatting,
    # customer-facing language, links, or explicit product/policy details.
    sentence_count = len(re.findall(r"[.!?](?:\s|$)", raw))
    answer_like_signals = sum(bool(re.search(pattern, raw, re.IGNORECASE | re.MULTILINE)) for pattern in (
        r"^\s*(?:hi|hello|dear)\b",
        r"\b(?:yes|no),?\s+(?:the|you|we|it|this)\b",
        r"\bwe (?:offer|recommend|provide|can|do|will)\b",
        r"\bthe (?:system|unit|product|installation|customer)\b",
        r"https?://",
        r"(?im)^\s*[-•*]?\s*[^\n]{3,120}\?\s*$",
    ))
    if sentence_count < 3 and answer_like_signals < 2:
        return False

    messages = list(st.session_state.get("messages") or [])
    if not messages:
        return False

    # The current user message may already have been appended to session history.
    prior = messages[:-1] if (
        str(messages[-1].get("role") or "").lower() == "user"
        and clean_visible_chat_text(messages[-1].get("content", "")).strip() == raw
    ) else messages
    recent = prior[-8:]

    saw_customer_inquiry = False
    saw_ai_draft_after_inquiry = False
    for message in recent:
        role = str(message.get("role") or "").strip().lower()
        content, _ = extract_images_from_message_content(message.get("content", ""))
        content = clean_visible_chat_text(content)
        if role == "user":
            question_count = content.count("?")
            inquiry_terms = bool(re.search(
                r"\b(?:customer|inquiry|interested|i have (?:a few )?questions|"
                r"do you|does the|can the|will the|how long|how much)\b",
                content,
                flags=re.IGNORECASE,
            ))
            if len(content) >= 100 and (question_count >= 1 or inquiry_terms):
                saw_customer_inquiry = True
        elif role == "assistant" and saw_customer_inquiry:
            if len(content.strip()) >= 100:
                saw_ai_draft_after_inquiry = True

    return saw_customer_inquiry and saw_ai_draft_after_inquiry


def _learning_source_strength(*, explicit_learning=False, staff_confirmed=False,
                              staff_teaching=False):
    """Return a deterministic trust tier for learned-knowledge governance."""
    if explicit_learning:
        return "explicit_staff_instruction", 98
    if staff_confirmed:
        return "staff_confirmed_solution", 95
    if staff_teaching:
        return "staff_authored_correction", 92
    return "ai_generated_draft", 65


EXPLICIT_LEARNING_COMMAND_PATTERNS = (
    # Direct teaching commands.
    r"\blearn (?:and )?(?:save )?(?:this|it)\b",
    r"\bteach (?:the ai|autotecpro ai)? ?(?:this|it)\b",

    # Natural save / memory wording.
    r"\bsave (?:this|it)(?: permanently)?\b",
    r"\bsave (?:this|it) (?:for|to) future (?:reference|use|cases?)\b",
    r"\bsave (?:this|it) (?:in|to) (?:the )?(?:knowledge base|memory|database)\b",
    r"\bremember (?:this|it)(?: for future (?:reference|use|cases?))?\b",
    r"\badd (?:this|it) to (?:the )?(?:knowledge base|memory|database)\b",
    r"\bstore (?:this|it)(?: as (?:permanent )?knowledge)?\b",
    r"\bkeep (?:this|it) for (?:later|future (?:reference|use|cases?))\b",
    r"\bdon['’]?t forget (?:this|it)\b",
    r"\buse (?:this|it) for future (?:cases?|reference|support)\b",
    r"\bmake (?:this|it) (?:permanent|part of (?:the )?knowledge base)\b",

    # Professional multi-file / department-specific teaching commands.
    r"\blearn (?:these|the) uploaded (?:files?|photos?|images?|documents?)\b",
    r"\blearn (?:this|these) as (?:an? )?(?:technical|sales|marketing) (?:record|knowledge|guideline|rule)\b",
    r"\bcreate (?:and )?save (?:an? )?(?:technical|sales|marketing) (?:record|knowledge|guideline)\b",
    r"\badd (?:these|the) (?:photos?|images?|files?|documents?) to (?:the )?(?:technical|sales|marketing) (?:database|knowledge base)\b",
)


def detect_explicit_learning_command(
    message_text,
    *,
    has_recent_context=False,
    has_attachments=False,
):
    """Detect a natural-language request to permanently save knowledge.

    Short phrases such as ``save this`` are accepted only when the current turn
    has an attachment or prior conversation context. This keeps the command easy
    for staff while avoiding accidental matches for unrelated save/download tasks.
    """
    normalized = re.sub(
        r"\s+",
        " ",
        str(message_text or "").strip().lower(),
    )
    if not normalized:
        return False

    # Never mistake deletion/forgetting instructions for a save command.
    if re.search(
        r"\b(?:forget|delete|remove|erase)\b.*"
        r"\b(?:knowledge|memory|record|this|it)\b",
        normalized,
    ):
        return False

    # Exclude common file/image/document save or download requests unless the
    # user explicitly mentions memory, learning, future use, or knowledge.
    if re.search(
        r"\b(?:download|export|save as|save (?:the )?(?:image|photo|file|pdf|document|draft|chat))\b",
        normalized,
    ) and not re.search(
        r"\b(?:memory|learn|knowledge|future|remember|permanent)\b",
        normalized,
    ):
        return False

    matched = any(
        re.search(pattern, normalized, flags=re.IGNORECASE)
        for pattern in EXPLICIT_LEARNING_COMMAND_PATTERNS
    )
    if not matched:
        return False

    # Very short ambiguous commands require something concrete to refer to.
    ambiguous_short = bool(
        re.fullmatch(
            r"(?:please )?(?:save|remember|store|learn) (?:this|it)[.!?]*",
            normalized,
        )
    )
    if ambiguous_short and not (has_recent_context or has_attachments):
        return False

    return True


