def extract_explicit_learning_payload(prompt_text):
    """Return only the staff-authored content after an explicit learning command."""
    value = str(prompt_text or "").strip()
    if not value:
        return ""
    patterns = (
        r"^\s*(?:please\s+)?learn\s+(?:and\s+save\s+)?this\s*[:\-]?\s*",
        r"^\s*(?:please\s+)?save\s+this\s+(?:to|in)\s+(?:memory|knowledge)\s*[:\-]?\s*",
        r"^\s*(?:please\s+)?remember\s+this\s*[:\-]?\s*",
    )
    cleaned = value
    for pattern in patterns:
        updated = re.sub(pattern, "", cleaned, count=1, flags=re.IGNORECASE).strip()
        if updated != cleaned:
            cleaned = updated
            break
    # A command with no body means: use the immediately preceding reviewable
    # content as evidence, but do not treat the command itself as knowledge.
    normalized = re.sub(r"[^a-z0-9]+", " ", cleaned.lower()).strip()
    if normalized in {"", "learn this", "learn and save this", "save this", "remember this"}:
        return ""
    return cleaned


def build_explicit_learning_ai_prompt(prompt_text, prior_context):
    """Build a compact extraction request; saving is performed by the app."""
    inline_payload = extract_explicit_learning_payload(prompt_text)
    clean_context = redact_learning_private_data(prior_context)
    source_text = inline_payload or clean_context
    return f"""[INTERNAL AUTOTECPRO LEARNING EXTRACTION]
Extract only NEW or CHANGED reusable facts from the staff-provided source below.
Do not repeat the customer email, prior AI draft, internal analysis, evidence narrative,
search keywords, or a Customer Reply Draft. Do not create a long professional report.
Return a compact structured knowledge delta suitable for merge/deduplication.

SOURCE:
{source_text or 'No reusable source content was supplied.'}
""".strip()

def recent_learning_conversation_context(max_messages=6):
    """
    Return a small privacy-filtered context window for short confirmations such
    as 'this fixed it'. This runs only after an eligible staff interaction.
    """
    messages = list(st.session_state.get("messages") or [])
    context_lines = []

    for message in messages[-max(1, int(max_messages or 6)):]:
        role = str(message.get("role") or "").strip().upper()
        content, _ = extract_images_from_message_content(
            message.get("content", "")
        )
        content = clean_visible_chat_text(content)
        content = redact_learning_private_data(content)

        if content:
            context_lines.append(f"{role}: {content}")

    return "\n\n".join(context_lines)


def extract_learning_model_identifiers(*values):
    """Extract likely AutoTecPro model/SKU/part identifiers without treating years as models."""
    combined = "\n".join(str(value or "") for value in values)
    candidates = []

    labelled_patterns = (
        r"\b(?:model|product|sku|part(?: number)?|product code|unit)\s*[:#-]?\s*([A-Z0-9][A-Z0-9._/-]{1,30})",
        r"\b((?:DO|KVN|KLD|YZG|ATP)[-_]?[A-Z0-9][A-Z0-9._/-]{1,28})\b",
        r"\b(\d{2,4}(?:[- ]?(?:PRO|MAX|PLUS|LITE|ULTRA|GEN\s*\d+))?)\b",
    )
    for pattern in labelled_patterns:
        for match in re.finditer(pattern, combined, flags=re.IGNORECASE):
            value = re.sub(r"\s+", "-", match.group(1).strip(" .,:;()[]{}"))
            compact = re.sub(r"[^A-Za-z0-9]", "", value)
            if not compact:
                continue
            if re.fullmatch(r"(?:19|20)\d{2}", compact):
                continue
            if compact.lower() in {"android13", "android14", "bluetooth50", "512gb"}:
                continue
            if value not in candidates:
                candidates.append(value)
    return candidates[:16]


def learning_context_original_inquiry(context_text):
    """Return the most relevant earlier user inquiry from a role-labelled context block."""
    blocks = re.split(r"\n\n(?=[A-Z]+: )", str(context_text or ""))
    inquiries = []
    for block in blocks:
        if not block.startswith("USER: "):
            continue
        content = block[6:].strip()
        if len(content) >= 40 and ("?" in content or re.search(
            r"\b(?:customer|interested|inquiry|question|how|does|do you|can|will)\b",
            content, flags=re.IGNORECASE)):
            inquiries.append(content)
    return inquiries[-1] if inquiries else ""


def compact_learning_sections(solution, sections, max_items=28):
    """Build a concise retrieval record and exclude narrative/debug-only sections."""
    section_order = (
        ("identity", "Identity"),
        ("facts", "Verified Facts"),
        ("parts_or_features", "Parts / Features"),
        ("conditions", "Conditions"),
        ("procedure_or_response", "Approved Procedure / Response"),
        ("warnings_or_restrictions", "Warnings / Restrictions"),
        ("effective_dates", "Effective Dates"),
        ("needs_confirmation", "Needs Confirmation"),
    )
    seen = set()
    lines = []
    base = re.sub(r"\n{3,}", "\n\n", str(solution or "")).strip()
    if base and len(base) <= 1200:
        lines.append(base)

    total = 0
    for key, label in section_order:
        values = sections.get(key) or []
        if isinstance(values, str):
            values = [values]
        clean = []
        for item in values:
            item = re.sub(r"\s+", " ", str(item or "")).strip(" -•")
            normalized = normalize_text_for_match(item)
            if not item or normalized in seen:
                continue
            seen.add(normalized)
            clean.append(item)
            total += 1
            if total >= max_items:
                break
        if clean:
            lines.append(label + ":\n" + "\n".join(f"- {item}" for item in clean))
        if total >= max_items:
            break

    result = "\n\n".join(lines).strip()
    return result[:7000]


def extract_learning_candidate(
    question,
    answer,
    selected_assistant,
    *,
    staff_confirmed=False,
    staff_teaching=False,
    conversation_context="",
    explicit_requested=False,
):
    """Extract a department-specific professional record without DB schema changes."""
    safe_question = redact_learning_private_data(question)
    safe_answer = redact_learning_private_data(answer)
    safe_context = redact_learning_private_data(conversation_context)
    profile = _professional_learning_profile(selected_assistant)

    extraction_prompt = f"""
You are AutoTecPro's professional internal knowledge engineer.

Convert the interaction into one reusable {profile['department']} knowledge record.
Return ONLY valid JSON with this schema:
{{
  "should_learn": true,
  "record_type": "one supported record type",
  "title": "specific searchable title",
  "vehicle": "specific vehicle make/model/year when relevant, otherwise empty",
  "year": "year or year range when relevant, otherwise empty",
  "make": "make/brand when relevant, otherwise empty",
  "model": "vehicle/product model when relevant, otherwise empty",
  "product": "exact AutoTecPro product/model/SKU when relevant, otherwise empty",
  "model_identifiers": ["exact model, SKU, product code, or part number"],
  "issue": "short reusable topic",
  "solution": "complete approved reusable knowledge",
  "structured_sections": {{
    "identity": [],
    "facts": [],
    "parts_or_features": [],
    "conditions": [],
    "procedure_or_response": [],
    "warnings_or_restrictions": [],
    "effective_dates": [],
    "evidence": [],
    "needs_confirmation": []
  }},
  "keywords": "comma-separated exact search terms",
  "was_unanswered": false,
  "resolved": true,
  "confidence_score": 0,
  "completeness_score": 0,
  "source_reliability_score": 0,
  "contradiction_detected": false,
  "reason": "short reason"
}}

Department: {profile['department']}
Supported types: {profile['record_types']}
Preferred fields: {profile['required_fields']}
Staff confirmed: {str(bool(staff_confirmed)).lower()}
Staff-authored teaching/correction: {str(bool(staff_teaching)).lower()}
Explicit learning request: {str(bool(explicit_requested)).lower()}

Rules:
- The CURRENT STAFF MESSAGE is the highest-priority source whenever it contains an
  approved answer, correction, final reply, confirmed fix, policy, specification,
  campaign rule, or reusable Q&A.
- Use RECENT CONTEXT to identify the original customer question and the earlier AI
  draft that the staff member is correcting. Learn the staff correction, not the
  earlier draft.
- The AI RESPONSE may help organize or summarize the staff-provided information, but
  it must never override a conflicting staff statement.
- For explicit learning, extract only the NEW or CHANGED reusable facts supported
  by the staff message, attachments, and recent context. Do not copy the full prior
  AI response, customer email, analysis, evidence narrative, or reply draft.
- Keep the stored solution compact and retrieval-focused. Prefer short verified facts,
  conditions, procedures, restrictions, and approved response rules over narrative.
- Preserve separate answers when the staff message contains multiple customer
  questions, but store them as concise independent facts rather than repeating the
  entire conversation.
- Never include a Customer Reply Draft inside stored knowledge.
- If the same fact already exists unchanged, do not duplicate it; prepare a merge/update.
- Never turn a guess, draft, unanswered question, temporary live data, or private data
  into approved knowledge.
- Preserve every exact model number, SKU, product code, part number, year range, quantity, market, date and restriction.
- When a staff answer names a model such as 861, 861-Pro, 836-Max, DO-RM861, or another exact code, place it in product/model_identifiers and use it in the searchable title and keywords.
- Treat the original customer inquiry and the later staff answer as one paired case. The staff answer is authoritative; the earlier AI draft is only context.
- Put unsupported fields in needs_confirmation; never invent them.
- For Technical photo/parts records, map visible items to Photo 1/2/3 in evidence.
- For Sales, include market/currency/effective/expiration dates when relevant.
- For Marketing, extract reusable brand rules, not only the sample copy.
- contradiction_detected must be true when supplied sources conflict materially.
- should_learn must be false if no concrete reusable knowledge exists.

STAFF MESSAGE:
{safe_question}

AI RESPONSE:
{safe_answer}

RECENT CONTEXT:
{safe_context}
"""
    try:
        response = client.responses.create(
            model="gpt-5.5",
            instructions="Return only valid JSON. No markdown.",
            input=extraction_prompt,
        )
        data = extract_json_object(response.output_text)
    except Exception:
        data = {}

    should_learn = bool(data.get("should_learn", False))
    issue = str(
        data.get("title") or data.get("issue")
        or conversation_title_from_text(safe_question or safe_context)
    ).strip()[:180]
    fallback_solution = safe_answer if explicit_requested else (
        safe_question if staff_confirmed and len(safe_question) >= 20 else safe_answer
    )
    solution = str(data.get("solution") or fallback_solution).strip()
    keywords = str(data.get("keywords") or "").strip()
    record_type = str(data.get("record_type") or "general_knowledge").strip()
    sections = data.get("structured_sections")
    if not isinstance(sections, dict):
        sections = {}

    def clean_items(name):
        value = sections.get(name) or []
        if isinstance(value, str):
            value = [value]
        return [str(item).strip() for item in value if str(item).strip()][:40]

    professional_sections = {
        name: clean_items(name)
        for name in (
            "identity", "facts", "parts_or_features", "conditions",
            "procedure_or_response", "warnings_or_restrictions",
            "effective_dates", "evidence", "needs_confirmation"
        )
    }

    # Keep permanent knowledge compact and retrieval-focused. Evidence and search
    # narrative remain available in the source conversation but are not duplicated
    # into every durable record.
    solution = compact_learning_sections(solution, professional_sections)

    model_identifiers = extract_learning_model_identifiers(
        safe_question, safe_answer, safe_context, data.get("product"),
        " ".join(data.get("model_identifiers") or [])
        if isinstance(data.get("model_identifiers"), list) else data.get("model_identifiers"),
    )
    product_value = str(data.get("product") or "").strip()
    if not product_value and model_identifiers:
        product_value = " / ".join(model_identifiers[:4])
    if model_identifiers:
        identifier_keywords = ", ".join(model_identifiers)
        keywords = ", ".join(filter(None, [identifier_keywords, keywords]))

    vehicle = resolve_learning_vehicle(
        data.get("vehicle"), question=safe_question, answer=safe_answer,
        issue=issue, keywords=keywords, product=product_value or safe_context,
        selected_assistant=selected_assistant,
    )

    try:
        confidence_score = max(0, min(100, int(data.get("confidence_score", 88 if staff_confirmed else 75))))
    except Exception:
        confidence_score = 88 if staff_confirmed else 75
    try:
        completeness_score = max(0, min(100, int(data.get("completeness_score", 70))))
    except Exception:
        completeness_score = 70
    contradiction = bool(data.get("contradiction_detected", False))

    minimum_solution_length = 50 if explicit_requested else (
        30 if (staff_confirmed or staff_teaching) else 100
    )
    if len(solution) < minimum_solution_length or len(safe_question) < 5:
        should_learn = False
    # Ordinary AI-generated drafts are not authoritative enough for permanent
    # learning. Auto Learn is intentionally staff-driven, like a durable company
    # memory: it learns approved corrections, explicit teaching, and confirmed fixes.
    if not (explicit_requested or staff_confirmed or staff_teaching):
        should_learn = False
    # Material contradictions require an explicit or confirmed staff source.
    if contradiction and not (explicit_requested or staff_confirmed):
        should_learn = False

    if record_type and record_type not in keywords.lower():
        keywords = ", ".join(filter(None, [record_type.replace("_", " "), keywords]))

    combined_text = f"{safe_question} {safe_answer}"
    year_match = re.search(r"\b(20[0-2][0-9]|19[8-9][0-9])\b", combined_text)
    analytics_payload = {
        "username": st.session_state.get("username"),
        "assistant": clean_assistant_label(selected_assistant),
        "vehicle": vehicle,
        "year": str(data.get("year") or (year_match.group(1) if year_match else "")).strip(),
        "make": str(data.get("make") or "").strip(),
        "model": str(data.get("model") or "").strip(),
        "issue": issue,
        "product": product_value[:180],
        "solution": solution,
        "keywords": keywords,
        "question": str(question or ""), "answer": str(answer or ""),
        "was_unanswered": bool(data.get("was_unanswered", False)),
        "resolved": bool(data.get("resolved", False)),
        "confidence_score": confidence_score,
        "conversation_id": st.session_state.get("conversation_id"),
        "created_at": now_iso(),
    }

    return {
        "should_learn": should_learn, "record_type": record_type,
        "vehicle": vehicle, "issue": issue, "solution": solution,
        "keywords": keywords, "confidence_score": confidence_score,
        "completeness_score": completeness_score,
        "contradiction_detected": contradiction,
        "reason": str(data.get("reason") or "").strip(),
        "staff_confirmed": bool(staff_confirmed),
        "staff_teaching": bool(staff_teaching),
        "model_identifiers": model_identifiers,
        "analytics_payload": analytics_payload,
    }

def make_learned_knowledge_document(record):
    """Create a rich searchable record while preserving the current TXT pipeline."""
    safe_record = {
        key: ("" if value is None else str(value))
        for key, value in dict(record or {}).items()
    }
    assistant_label = safe_record.get("assistant", "")
    department = _professional_learning_profile(assistant_label)["department"]

    return f"""AutoTecPro Professional Learned Knowledge

Department:
{department}

Record Type:
{safe_record.get("record_type", "general_knowledge")}

Title / Issue:
{safe_record.get("issue", "")}

Vehicle / Product:
{safe_record.get("vehicle", "") or "Not applicable"}

Approved Structured Knowledge:
{safe_record.get("solution", "")}

Search Keywords:
{safe_record.get("keywords", "")}

Quality:
- Confidence: {safe_record.get("confidence_score", "")}
- Times Seen: {safe_record.get("times_seen", "")}
- Staff Confirmed: {safe_record.get("staff_confirmed", "")}
- Source Type: {safe_record.get("source_type", "")}

Source Question:
{safe_record.get("source_question", "")}

Source Answer:
{safe_record.get("source_answer", "")}

Retrieval Instruction:
Prefer this approved record when its exact model number, product/SKU, vehicle/year,
factory system, market, channel, policy date, symptom, or record type matches the
user's request. Staff-approved facts override older AI drafts and ambiguous product
library candidates. Verify all Needs Confirmation items before treating them as
facts. Prefer newer approved versions over older or conflicting records.
"""


def wait_for_learned_vector_file_ready(vector_store_id, file_id, timeout_seconds=30):
    """Wait briefly for OpenAI vector ingestion instead of marking it synced early."""
    deadline = time.monotonic() + max(1, int(timeout_seconds or 30))
    last_status = "unknown"
    while time.monotonic() < deadline:
        try:
            vector_file = client.vector_stores.files.retrieve(
                vector_store_id=vector_store_id,
                file_id=file_id,
            )
            last_status = str(getattr(vector_file, "status", "") or "unknown").lower()
            if last_status == "completed":
                return True, last_status
            if last_status in {"failed", "cancelled"}:
                return False, last_status
        except Exception as error:
            diagnostic_log(
                "learned_vector_status_check_failed",
                error_type=type(error).__name__,
                error=str(error),
                file_id=file_id,
            )
        time.sleep(0.75)
    return False, last_status

def upload_learned_record_to_vector_store(record, vector_store_id):
    doc_text = make_learned_knowledge_document(record)
    safe_name = normalize_text_for_match(record.get("issue") or "learned_case")[:50].replace(" ", "_") or "learned_case"
    filename = f"autotecpro_learned_{safe_name}.txt"

    with tempfile.NamedTemporaryFile("w", suffix=".txt", delete=False, encoding="utf-8") as tmp:
        tmp.write(doc_text)
        tmp_path = tmp.name

    try:
        with open(tmp_path, "rb") as f:
            openai_file = client.files.create(file=(filename, f), purpose="assistants")

        client.vector_stores.files.create(
            vector_store_id=vector_store_id,
            file_id=openai_file.id,
        )
        ready, ingestion_status = wait_for_learned_vector_file_ready(
            vector_store_id,
            openai_file.id,
        )
        diagnostic_log(
            "learned_vector_ingestion_status",
            file_id=openai_file.id,
            vector_store_id=vector_store_id,
            ready=ready,
            status=ingestion_status,
        )
        if ingestion_status in {"failed", "cancelled"}:
            raise RuntimeError(
                f"Learned record vector ingestion {ingestion_status}."
            )
        return openai_file.id
    finally:
        try:
            os.remove(tmp_path)
        except Exception:
            pass


def remove_old_learned_vector_file(vector_store_id, file_id):
    """Best-effort removal of a superseded learned file after replacement succeeds."""
    vector_store_id = str(vector_store_id or "").strip()
    file_id = str(file_id or "").strip()
    if not vector_store_id or not file_id:
        return False
    try:
        client.vector_stores.files.delete(
            vector_store_id=vector_store_id,
            file_id=file_id,
        )
    except Exception:
        return False
    try:
        client.files.delete(file_id)
    except Exception:
        pass
    return True


def find_duplicate_learned_knowledge(candidate, selected_assistant):
    try:
        all_rows = safe_select_rows(
            "learned_knowledge",
            order_columns=["updated_at", "created_at"],
            limit=200,
        )

        approved_rows = [
            row for row in all_rows
            if not is_pending_knowledge_row(row)
        ]

        clean_assistant = clean_assistant_label(
            selected_assistant
        ).strip().lower()

        rows = [
            row for row in approved_rows
            if str(row.get("assistant") or "").strip().lower()
            == clean_assistant
        ] or approved_rows
    except Exception:
        return None, 0

    best_row = None
    best_score = 0

    candidate_text = " ".join([
        str(candidate.get("vehicle") or ""),
        str(candidate.get("issue") or ""),
        str((candidate.get("analytics_payload") or {}).get("product") or ""),
        " ".join(candidate.get("model_identifiers") or []),
        str(candidate.get("keywords") or ""),
        str(candidate.get("solution") or "")[:900],
    ])

    for row in rows:
        row_text = " ".join([
            str(row.get("vehicle") or ""),
            str(row.get("issue") or ""),
            str(row.get("keywords") or ""),
            str(
                row.get("solution")
                or row.get("approved_answer")
                or ""
            )[:600],
            str(
                row.get("source_question")
                or row.get("question")
                or ""
            ),
        ])

        score = text_similarity(candidate_text, row_text)
        issue_score = text_similarity(
            str(candidate.get("issue") or ""),
            str(row.get("issue") or ""),
        )

        vehicle_match = (
            bool(candidate.get("vehicle"))
            and bool(row.get("vehicle"))
            and normalize_text_for_match(
                str(candidate.get("vehicle") or "")
            )
            in normalize_text_for_match(
                str(row.get("vehicle") or "")
            )
        )

        if vehicle_match:
            score += 0.10
        if issue_score > 0.72:
            score += 0.12

        candidate_record_type = normalize_text_for_match(
            str(candidate.get("record_type") or "")
        )
        row_record_type = normalize_text_for_match(
            str(row.get("record_type") or "")
        )
        same_record_type = bool(
            candidate_record_type and row_record_type
            and candidate_record_type == row_record_type
        )
        if same_record_type:
            score += 0.06

        score = min(score, 1.0)

        if score > best_score:
            best_score = score
            best_row = row

    # Exact same department plus strong vehicle/topic identity should merge even
    # when wording changed substantially. Otherwise retain the conservative limit.
    if best_score >= 0.82:
        return best_row, best_score
    if best_row and best_score >= 0.74:
        candidate_vehicle = normalize_text_for_match(str(candidate.get("vehicle") or ""))
        row_vehicle = normalize_text_for_match(str(best_row.get("vehicle") or ""))
        candidate_issue = normalize_text_for_match(str(candidate.get("issue") or ""))
        row_issue = normalize_text_for_match(str(best_row.get("issue") or ""))
        if (candidate_vehicle and row_vehicle and
                (candidate_vehicle in row_vehicle or row_vehicle in candidate_vehicle) and
                text_similarity(candidate_issue, row_issue) >= 0.62):
            return best_row, best_score

    return None, best_score

def improve_existing_solution(existing_row, candidate):
    prompt = f"""
You are AutoTecPro's internal knowledge base editor.

Merge the existing knowledge and the new case into one compact, accurate, reusable solution.
Remove duplicate sentences and repeated sections. Keep only verified facts and genuinely unresolved items.
Never include a customer email, Customer Reply Draft, Evidence narrative, Search Keywords section, or internal analysis in the solution.
Preserve all exact model numbers, SKUs, product codes, part numbers, year ranges, and restrictions.
Merge only genuinely related knowledge; do not blend different vehicle generations or product families.

Return ONLY valid JSON:
{{
  "issue": "best short issue title",
  "vehicle": "best vehicle/product",
  "solution": "improved final solution",
  "keywords": "comma-separated keywords",
  "confidence_score": 0-100
}}

Do not invent facts. Preserve exact compatibility and troubleshooting details.

Existing Knowledge:
Vehicle: {existing_row.get("vehicle", "")}
Issue: {existing_row.get("issue", "")}
Solution: {existing_row.get("solution", "")}
Keywords: {existing_row.get("keywords", "")}
Confidence: {existing_row.get("confidence_score", 70)}
Times Seen: {existing_row.get("times_seen", 1)}

New Case:
Vehicle: {candidate.get("vehicle", "")}
Issue: {candidate.get("issue", "")}
Solution: {candidate.get("solution", "")}
Keywords: {candidate.get("keywords", "")}
Confidence: {candidate.get("confidence_score", 70)}
"""
    try:
        response = client.responses.create(
            model="gpt-5.5",
            instructions="Return only valid JSON. No markdown.",
            input=prompt
        )
        data = extract_json_object(response.output_text)
    except Exception:
        data = {}

    old_times_seen = int(existing_row.get("times_seen") or 1)
    old_confidence = int(existing_row.get("confidence_score") or 70)
    new_confidence = int(candidate.get("confidence_score") or 70)
    merged_confidence = max(old_confidence, min(98, round((old_confidence + new_confidence) / 2 + min(old_times_seen, 10))))

    merged_issue = str(
        data.get("issue")
        or candidate.get("issue")
        or existing_row.get("issue")
        or ""
    ).strip()[:180]
    merged_keywords = str(
        data.get("keywords")
        or candidate.get("keywords")
        or existing_row.get("keywords")
        or ""
    ).strip()

    merged_vehicle = resolve_learning_vehicle(
        data.get("vehicle")
        or candidate.get("vehicle")
        or existing_row.get("vehicle"),
        question=candidate.get("source_question") or existing_row.get("source_question"),
        answer=candidate.get("solution") or existing_row.get("source_answer"),
        issue=merged_issue,
        keywords=merged_keywords,
        product=existing_row.get("product"),
        selected_assistant=existing_row.get("assistant"),
    )

    return {
        "vehicle": merged_vehicle,
        "issue": merged_issue,
        "solution": str(data.get("solution") or candidate.get("solution") or existing_row.get("solution") or "").strip(),
        "keywords": merged_keywords,
        "confidence_score": int(data.get("confidence_score") or merged_confidence),
        "times_seen": old_times_seen + 1
    }



def build_local_analytics_payload(question, answer, selected_assistant):
    """Build analytics without an extra OpenAI request."""
    combined_text = f"{question or ''} {answer or ''}"
    vehicle = detect_vehicle_basic(combined_text)
    year_match = re.search(
        r"\b(20[0-2][0-9]|19[8-9][0-9])\b",
        combined_text,
    )
    return {
        "username": st.session_state.get("username"),
        "assistant": clean_assistant_label(selected_assistant),
        "vehicle": vehicle,
        "year": year_match.group(1) if year_match else "",
        "make": "",
        "model": "",
        "issue": conversation_title_from_text(question),
        "product": "",
        "solution": "",
        "keywords": "",
        "question": str(question or ""),
        "answer": str(answer or ""),
        "was_unanswered": False,
        "resolved": bool(str(answer or "").strip()),
        "confidence_score": 70,
        "conversation_id": st.session_state.get("conversation_id"),
        "created_at": now_iso(),
    }




def queue_ai_postprocess(
    question,
    answer,
    selected_assistant,
    detected_live_request,
    response_time,
    tokens_used,
    is_graphic_generation=False,
    is_structured_marketing_tool=False,
    is_structured_graphic_tool=False,
    explicit_learning=False,
    learning_context="",
):
    """Queue non-visible learning and analytics for the next Streamlit run."""
    live_type = str(
        (
            detected_live_request
            if isinstance(detected_live_request, dict)
            else {}
        ).get("type")
        or ""
    )
    if live_type.startswith("woocommerce_"):
        return

    postprocess_fingerprint = hashlib.sha256(
        (
            str(st.session_state.get("conversation_id") or "")
            + "\n" + str(question or "")
            + "\n" + str(answer or "")
        ).encode("utf-8", errors="ignore")
    ).hexdigest()
    if st.session_state.get("last_queued_postprocess_fingerprint") == postprocess_fingerprint:
        return
    st.session_state["last_queued_postprocess_fingerprint"] = postprocess_fingerprint

    st.session_state["pending_ai_postprocess"] = {
        "fingerprint": postprocess_fingerprint,
        "question": str(question or ""),
        "answer": str(answer or ""),
        "selected_assistant": str(selected_assistant or ""),
        "detected_live_request": (
            dict(detected_live_request)
            if isinstance(detected_live_request, dict)
            else {"type": "none"}
        ),
        "response_time": response_time,
        "tokens_used": tokens_used,
        "is_graphic_generation": bool(is_graphic_generation),
        "is_structured_marketing_tool": bool(
            is_structured_marketing_tool
        ),
        "is_structured_graphic_tool": bool(
            is_structured_graphic_tool
        ),
        "explicit_learning": bool(explicit_learning),
        "learning_context": str(learning_context or ""),
    }


def process_pending_ai_postprocess():
    """
    Process one queued maintenance job after the answer has already been saved
    and displayed. Failures remain non-blocking.
    """
    job = st.session_state.pop("pending_ai_postprocess", None)
    if not isinstance(job, dict):
        return

    fingerprint = str(job.get("fingerprint") or "")
    if fingerprint and st.session_state.get("last_processed_postprocess_fingerprint") == fingerprint:
        return
    if fingerprint:
        st.session_state["last_processed_postprocess_fingerprint"] = fingerprint

    postprocess_started_at = time.perf_counter()
    diagnostic_log(
        "ai_postprocess_started",
        fingerprint=fingerprint[:12],
        assistant=job.get("selected_assistant"),
        conversation_id=st.session_state.get("conversation_id"),
        logged_in=st.session_state.get("logged_in"),
    )

    learning_result = None
    if (
        not job.get("is_graphic_generation")
        and not job.get("is_structured_marketing_tool")
        and not job.get("is_structured_graphic_tool")
    ):
        try:
            learning_result = auto_learn_from_latest_answer(
                job.get("question"),
                job.get("answer"),
                job.get("selected_assistant"),
                detected_live_request=job.get("detected_live_request"),
                explicit_learning=bool(job.get("explicit_learning")),
                learning_context=job.get("learning_context"),
            )
            if learning_result and learning_result.get("learned"):
                mode = learning_result.get("mode", "saved")
                if learning_result.get("explicit_learning"):
                    message = f"Knowledge saved permanently ({mode})."
                elif learning_result.get("staff_confirmed"):
                    message = f"Confirmed staff solution learned ({mode})."
                elif learning_result.get("unlabeled_final_reply"):
                    message = f"Final staff reply learned automatically ({mode})."
                elif learning_result.get("staff_teaching"):
                    message = f"Staff correction learned ({mode})."
                else:
                    message = f"Knowledge learned from this case ({mode})."
                st.toast(message, icon="🧠")
        except Exception as error:
            learning_result = None
            diagnostic_log(
                "ai_postprocess_learning_failed",
                error_type=type(error).__name__,
                error=str(error),
                fingerprint=fingerprint[:12],
            )

    try:
        log_ai_analytics(
            job.get("question"),
            job.get("answer"),
            job.get("selected_assistant"),
            learning_result,
            response_time=job.get("response_time"),
            tokens_used=job.get("tokens_used"),
        )
    except Exception as error:
        diagnostic_log(
            "ai_postprocess_analytics_failed",
            error_type=type(error).__name__,
            error=str(error),
            fingerprint=fingerprint[:12],
        )

    diagnostic_log(
        "ai_postprocess_finished",
        fingerprint=fingerprint[:12],
        elapsed_seconds=round(time.perf_counter() - postprocess_started_at, 3),
        logged_in=st.session_state.get("logged_in"),
    )



def auto_learn_from_latest_answer(
    question,
    answer,
    selected_assistant,
    detected_live_request=None,
    explicit_learning=False,
    learning_context="",
):
    if selected_assistant == "⚙️ Admin Panel":
        return None

    # Graphic generation output is handled separately and must not become
    # technical or sales knowledge.
    if selected_assistant == "🎨 Graphic Marketing":
        return {
            "learned": False,
            "reason": "Graphic Marketing image-generation chats are not learned.",
            "analytics_payload": build_local_analytics_payload(
                question,
                answer,
                selected_assistant,
            ),
        }

    live_request = (
        detected_live_request
        if isinstance(detected_live_request, dict)
        else detect_live_request(question, selected_assistant)
    )
    live_request_type = str(
        live_request.get("type") or "none"
    ).strip().lower()

    if live_request_type != "none":
        return {
            "learned": False,
            "reason": (
                "Live-data requests are excluded from automatic learning "
                "to avoid storing temporary, changing, or private data."
            ),
            "analytics_payload": build_local_analytics_payload(
                question,
                answer,
                selected_assistant,
            ),
        }

    safe_question = redact_learning_private_data(question)
    safe_answer = redact_learning_private_data(answer)
    explicit_learning = bool(explicit_learning)
    unlabeled_final_reply = detect_unlabeled_staff_final_reply(
        safe_question,
        selected_assistant,
    )
    staff_teaching = (
        detect_staff_teaching_content(safe_question)
        or unlabeled_final_reply
    )
    staff_confirmed = (
        detect_staff_confirmed_solution(safe_question)
        or unlabeled_final_reply
        or explicit_learning
    )
    source_type, source_confidence_floor = _learning_source_strength(
        explicit_learning=explicit_learning,
        staff_confirmed=staff_confirmed,
        staff_teaching=staff_teaching,
    )
    conversation_context = (
        str(learning_context or "").strip()
        if explicit_learning and str(learning_context or "").strip()
        else (
            _learning_context_messages(max_messages=10)
            if (staff_confirmed or staff_teaching or explicit_learning)
            else ""
        )
    )

    explicit_payload = (
        extract_explicit_learning_payload(safe_question)
        if explicit_learning
        else ""
    )
    candidate_question = explicit_payload if explicit_learning else safe_question
    candidate_answer = "" if explicit_learning else safe_answer

    candidate = extract_learning_candidate(
        candidate_question,
        candidate_answer,
        selected_assistant,
        staff_confirmed=staff_confirmed,
        staff_teaching=staff_teaching,
        conversation_context=conversation_context,
        explicit_requested=explicit_learning,
    )
    if candidate.get("should_learn"):
        candidate["confidence_score"] = max(
            int(candidate.get("confidence_score") or 0),
            source_confidence_floor,
        )

    if not candidate.get("should_learn"):
        return {
            "learned": False,
            "staff_confirmed": staff_confirmed,
            "staff_teaching": staff_teaching,
            "unlabeled_final_reply": unlabeled_final_reply,
            "explicit_learning": explicit_learning,
            "reason": (
                candidate.get("reason")
                or "Not reusable or sufficiently confirmed."
            ),
            "analytics_payload": candidate.get("analytics_payload"),
        }

    vector_store_id = get_learning_vector_store_id(selected_assistant)
    duplicate_row, duplicate_score = find_duplicate_learned_knowledge(
        candidate,
        selected_assistant,
    )

    if duplicate_row:
        improved = improve_existing_solution(duplicate_row, candidate)

        record_for_file = {
            "assistant": clean_assistant_label(selected_assistant),
            "record_type": candidate.get("record_type") or "general_knowledge",
            "vehicle": improved["vehicle"],
            "issue": improved["issue"],
            "solution": improved["solution"],
            "keywords": improved["keywords"],
            "confidence_score": improved["confidence_score"],
            "times_seen": improved["times_seen"],
            "source_question": safe_question,
            "source_answer": safe_answer,
        }

        openai_file_id = upload_learned_record_to_vector_store(
            record_for_file,
            vector_store_id,
        )

        update_payload = {
            "username": st.session_state.get("username"),
            "assistant": clean_assistant_label(selected_assistant),
            "vehicle": improved["vehicle"],
            "issue": improved["issue"],
            "solution": improved["solution"],
            "approved_answer": improved["solution"],
            "question": safe_question,
            "keywords": improved["keywords"],
            "source_question": safe_question,
            "source_answer": safe_answer,
            "source_conversation_id": st.session_state.get("conversation_id"),
            "confidence_score": improved["confidence_score"],
            "times_seen": improved["times_seen"],
            "openai_file_id": openai_file_id,
            "vector_store_id": vector_store_id,
            "synced": True,
            "embedding_status": "synced",
            "source_type": source_type,
            "staff_confirmed": bool(staff_confirmed),
            "updated_at": now_iso(),
        }

        safe_update_row(
            "learned_knowledge",
            update_payload,
            duplicate_row["id"],
        )

        # Only remove the superseded vector after the replacement has uploaded
        # and the Supabase master record has been updated successfully.
        old_file_id = duplicate_row.get("openai_file_id")
        if old_file_id and old_file_id != openai_file_id:
            remove_old_learned_vector_file(
                duplicate_row.get("vector_store_id") or vector_store_id,
                old_file_id,
            )

        return {
            "learned": True,
            "mode": "updated",
            "staff_confirmed": staff_confirmed,
            "staff_teaching": staff_teaching,
            "unlabeled_final_reply": unlabeled_final_reply,
            "explicit_learning": explicit_learning,
            "duplicate_score": round(duplicate_score, 3),
            "record_id": duplicate_row["id"],
            "duplicate_of": duplicate_row["id"],
            "file_id": openai_file_id,
            "analytics_payload": candidate.get("analytics_payload"),
        }

    original_inquiry = learning_context_original_inquiry(conversation_context)
    authoritative_staff_answer = safe_question if (
        staff_confirmed or staff_teaching or explicit_learning
    ) else safe_answer

    new_record = {
        "username": st.session_state.get("username"),
        "record_type": candidate.get("record_type") or "general_knowledge",
        "assistant": clean_assistant_label(selected_assistant),
        "vehicle": candidate["vehicle"],
        "issue": candidate["issue"],
        "solution": candidate["solution"],
        "approved_answer": candidate["solution"],
        "question": original_inquiry or safe_question,
        "keywords": candidate["keywords"],
        "source_question": original_inquiry or safe_question,
        "source_answer": authoritative_staff_answer,
        "source_conversation_id": st.session_state.get("conversation_id"),
        "confidence_score": candidate["confidence_score"],
        "times_seen": 1,
        "times_used": 0,
        "search_count": 0,
        "vector_store_id": vector_store_id,
        "synced": False,
        "embedding_status": "pending",
        "source_type": source_type,
        "staff_confirmed": bool(staff_confirmed),
        "created_at": now_iso(),
        "updated_at": now_iso(),
    }

    openai_file_id = upload_learned_record_to_vector_store(
        new_record,
        vector_store_id,
    )
    new_record["openai_file_id"] = openai_file_id
    new_record["synced"] = True
    new_record["embedding_status"] = "synced"

    result = safe_insert_row("learned_knowledge", new_record)
    if not result.data:
        raise RuntimeError("Learning record was not saved.")

    return {
        "learned": True,
        "mode": "created",
        "staff_confirmed": staff_confirmed,
        "staff_teaching": staff_teaching,
        "unlabeled_final_reply": unlabeled_final_reply,
        "explicit_learning": explicit_learning,
        "record_id": result.data[0]["id"],
        "file_id": openai_file_id,
        "analytics_payload": candidate.get("analytics_payload"),
    }


# ============================================================
# AI Analytics Engine
# ============================================================

def extract_analytics_from_question(question, answer, selected_assistant):
    """Extract structured analytics signals from each AI interaction."""
    prompt = f"""
You are AutoTecPro's internal analytics engine.

Extract analytics from this AI interaction.

Return ONLY valid JSON:
{{
  "vehicle": "full vehicle if mentioned, else empty",
  "year": "year if mentioned, else empty",
  "make": "make/brand if mentioned, else empty",
  "model": "model if mentioned, else empty",
  "issue": "short issue/search topic",
  "product": "product/model/category searched, else empty",
  "solution": "short reusable solution summary, else empty",
  "keywords": "comma-separated keywords",
  "was_unanswered": true/false,
  "resolved": true/false,
  "confidence_score": 0-100
}}

Rules:
- was_unanswered is true if the AI could not answer, lacked documentation, asked for escalation, or only requested more info without a usable answer.
- resolved is true if the answer gives a clear useful solution, next step, compatibility fact, or customer-ready response.
- confidence_score should reflect how confident the AI answer appears based on the answer wording.
- Do not invent details.

Assistant:
{clean_assistant_label(selected_assistant)}

Question:
{question}

Answer:
{answer}
"""
    try:
        response = client.responses.create(
            model="gpt-5.5",
            instructions="Return only valid JSON. No markdown.",
            input=prompt
        )
        data = extract_json_object(response.output_text)
    except Exception:
        data = {}

    combined_text = str(question) + " " + str(answer)
    fallback_vehicle = detect_vehicle_basic(combined_text)
    fallback_year_match = re.search(r"\b(20[0-2][0-9]|19[8-9][0-9])\b", combined_text)

    try:
        confidence = int(data.get("confidence_score", 70))
    except Exception:
        confidence = 70

    vehicle = str(data.get("vehicle") or fallback_vehicle or "").strip()
    year = str(data.get("year") or (fallback_year_match.group(1) if fallback_year_match else "")).strip()
    make = str(data.get("make") or "").strip()
    model = str(data.get("model") or "").strip()

    # Lightweight fallback make/model split when AI extraction is empty.
    if vehicle and not make:
        vehicle_low = vehicle.lower()
        for brand in ["chevrolet", "chevy", "gmc", "ford", "toyota", "dodge", "ram", "infiniti", "audi", "mercedes"]:
            if brand in vehicle_low:
                make = brand.title()
                break

    if vehicle and not model:
        for possible_model in ["silverado", "sierra", "tahoe", "suburban", "yukon", "f150", "f-150", "f250", "f-250", "f350", "f-350", "tundra", "ram", "durango", "q50", "q60", "a4", "a5", "glc"]:
            if possible_model in vehicle.lower():
                model = possible_model.upper()
                break

    return {
        "username": st.session_state.get("username"),
        "assistant": clean_assistant_label(selected_assistant),
        "vehicle": vehicle,
        "year": year,
        "make": make,
        "model": model,
        "issue": str(data.get("issue") or conversation_title_from_text(question) or "").strip()[:180],
        "product": str(data.get("product") or "").strip()[:180],
        "solution": str(data.get("solution") or "").strip(),
        "keywords": str(data.get("keywords") or "").strip(),
        "question": str(question or ""),
        "answer": str(answer or ""),
        "was_unanswered": bool(data.get("was_unanswered", False)),
        "resolved": bool(data.get("resolved", False)),
        "confidence_score": max(0, min(100, confidence)),
        "conversation_id": st.session_state.get("conversation_id"),
        "created_at": now_iso()
    }

def log_ai_analytics(
    question,
    answer,
    selected_assistant,
    learning_result=None,
    response_time=None,
    tokens_used=None,
):
    """Save one analytics event without duplicating extraction calls."""
    try:
        shared_payload = (
            learning_result.get("analytics_payload")
            if isinstance(learning_result, dict)
            else None
        )
        payload = (
            dict(shared_payload)
            if isinstance(shared_payload, dict)
            else extract_analytics_from_question(
                question,
                answer,
                selected_assistant,
            )
        )

        if learning_result:
            payload["learned"] = bool(learning_result.get("learned"))
            payload["learning_mode"] = learning_result.get("mode")
            payload["learned_record_id"] = learning_result.get("record_id")
            payload["duplicate_of"] = learning_result.get("duplicate_of")
        else:
            payload["learned"] = False
            payload["learning_mode"] = None
            payload["learned_record_id"] = None
            payload["duplicate_of"] = None

        payload["response_time"] = response_time
        payload["tokens_used"] = tokens_used
        payload["learning_source"] = "automatic"

        safe_insert_row("ai_analytics", payload)
        return True

    except Exception:
        # Analytics should never break the main chat.
        return False

def top_counts(rows, field, limit=10):
    counts = {}
    for row in rows:
        value = str(row.get(field) or "").strip()
        if not value:
            continue
        counts[value] = counts.get(value, 0) + 1

    return sorted(counts.items(), key=lambda x: x[1], reverse=True)[:limit]


def keyword_counts(rows, limit=10):
    counts = {}
    for row in rows:
        keywords = str(row.get("keywords") or "")
        for kw in keywords.split(","):
            key = kw.strip().lower()
            if not key:
                continue
            counts[key] = counts.get(key, 0) + 1
    return sorted(counts.items(), key=lambda x: x[1], reverse=True)[:limit]


def render_count_table(title, data, col_name):
    st.markdown(f"#### {title}")
    if not data:
        st.info("No data yet.")
        return

    st.table([
        {col_name: item[0], "Count": item[1]}
        for item in data
    ])




def daily_question_counts(rows, limit=14):
    counts = {}
    for row in rows:
        day = str(row.get("created_at") or "")[:10]
        if not day:
            continue
        counts[day] = counts.get(day, 0) + 1

    items = sorted(counts.items())[-limit:]
    return [{"Date": k, "Questions": v} for k, v in items]


def assistant_counts(rows, limit=10):
    return top_counts(rows, "assistant", limit)


def user_counts(rows, limit=10):
    return top_counts(rows, "username", limit)


def learning_success_rate(rows):
    if not rows:
        return 0
    learned = len([r for r in rows if r.get("learned")])
    return round((learned / max(len(rows), 1)) * 100)




def count_today(rows, date_field="created_at"):
    today = datetime.now(timezone.utc).date().isoformat()
    return len([r for r in rows if str(r.get(date_field) or "").startswith(today)])


def safe_avg(rows, field):
    values = []
    for row in rows:
        try:
            if row.get(field) is not None:
                values.append(float(row.get(field)))
        except Exception:
            pass
    if not values:
        return 0
    return round(sum(values) / len(values), 2)


def duplicate_detection_rate(rows):
    if not rows:
        return 0
    dupes = len([r for r in rows if r.get("duplicate_of") or str(r.get("learning_mode") or "").lower() == "updated"])
    return round((dupes / max(len(rows), 1)) * 100)


def resolved_rate(rows):
    if not rows:
        return 0
    resolved = len([r for r in rows if r.get("resolved")])
    return round((resolved / max(len(rows), 1)) * 100)


def total_numeric(rows, field):
    total = 0
    for row in rows:
        try:
            total += int(row.get(field) or 0)
        except Exception:
            pass
    return total


def growth_counts(rows, field="created_at", limit=30, label="New Knowledge"):
    counts = {}
    for row in rows:
        day = str(row.get(field) or "")[:10]
        if not day:
            continue
        counts[day] = counts.get(day, 0) + 1
    items = sorted(counts.items())[-limit:]
    return [{"Date": k, label: v} for k, v in items]


def render_metric_row(metrics):
    cols = st.columns(len(metrics))
    for col, metric in zip(cols, metrics):
        label, value = metric[0], metric[1]
        delta = metric[2] if len(metric) > 2 else None
        col.metric(label, value, delta=delta)



# ============================================================
# Supabase Chat History Helpers
# ============================================================


def clean_assistant_label(assistant_name):
    """Normalize assistant labels so history works even when labels include emoji."""
    value = str(assistant_name or "")
    for icon in ["🔧", "📈", "📣", "🎨", "🧠", "📦", "📚", "⚙️", "⚙"]:
        value = value.replace(icon, "")
    return value.strip()


def normalize_workspace_assistant_name(assistant_name):
    """Map legacy saved workspace labels to current workspace names."""
    cleaned = clean_assistant_label(assistant_name)
    mapping = {
        "Sales & Marketing": "📈 Sales",
        "Sales and Marketing": "📈 Sales",
        "Sales": "📈 Sales",
        "Marketing": "📣 Marketing",
        "Technical Support": "🔧 Technical Support",
        "Graphic Marketing": "🎨 Graphic Marketing",
        "Knowledge Submission": "🧠 Knowledge Submission",
        "Product Library": "📦 Product Library",
        "Admin Panel": "⚙️ Admin Panel",
    }
    return mapping.get(cleaned, str(assistant_name or "").strip())


def conversation_title_from_text(text):
    """Fast fallback title used before the AI-generated title is available."""
    clean = re.sub(r"\s+", " ", str(text or "")).strip()
    clean = re.sub(r"📎\s*Attached:.*$", "", clean, flags=re.IGNORECASE).strip()
    if not clean:
        return "New Case"

    words = clean.split()
    fallback = " ".join(words[:7]).strip(" .,:;!?-")
    if not fallback:
        return "New Case"
    return fallback[:48]


def history_display_title(title):
    """
    Return a clean sidebar title.

    New chats use their saved AI-generated title. Older raw-message titles are
    compacted for display until they receive an AI-generated title.
    """
    clean = re.sub(r"\s+", " ", str(title or "")).strip()
    clean = re.sub(
        r"📎\s*Attached:.*$",
        "",
        clean,
        flags=re.IGNORECASE,
    ).strip()

    if not clean:
        return "New Case"

    lower = clean.lower()

    common_titles = [
        (r"which model supports?.*2013.*(?:dodge|ram)", "2013 RAM Compatibility"),
        (r"which model is it", "Vehicle Model Identification"),
        (r"france.*spain.*world cup", "France vs Spain Odds"),
        (r"what is this", "Image Identification"),
        (r"what are these", "Part Identification"),
        (r"this is the document", "Document Review"),
        (r"extract|extrac", "Document Data Extraction"),
    ]
    for pattern, replacement in common_titles:
        if re.search(pattern, lower):
            return replacement

    if re.fullmatch(r"1Z[A-Z0-9]{16}", clean.upper()):
        return "UPS Package Tracking"

    # Already-clean AI/manual titles remain as saved.
    if len(clean.split()) <= 5 and len(clean) <= 36:
        return clean

    compact = conversation_title_from_text(clean)
    words = compact.split()[:5]
    return " ".join(words)[:36].rstrip(" .,:;!?-") or "New Case"


@st.cache_data(ttl=86400, max_entries=256, show_spinner=False)
def _generate_ai_conversation_title_cached(user_text, answer_text):
    """Generate one long-prompt history title and cache identical retries."""
    response = client.responses.create(
        model="gpt-5.5",
        instructions=(
            "Create a clean professional title for a chat-history sidebar. "
            "Return only the title. Use 2 to 5 words. Do not use emoji. "
            "Do not use quotation marks, markdown, a prefix, or ending "
            "punctuation. Do not repeat the user's full sentence. Summarize "
            "the actual topic or task. Keep it under 36 characters. Preserve "
            "important vehicle models, product names, document types, or "
            "tracking context when useful."
        ),
        input=(
            f"User message: {user_text[:1200]}\n"
            f"Assistant response context: {answer_text[:800]}"
        ),
    )
    return str(response.output_text or "")


def generate_ai_conversation_title(
    first_message,
    assistant_answer="",
    detected_live_request=None,
):
    """
    Generate a concise ChatGPT-style conversation title.

    Failure is non-fatal: the existing fallback title remains unchanged.
    """
    user_text = re.sub(r"\s+", " ", str(first_message or "")).strip()
    answer_text = re.sub(r"\s+", " ", str(assistant_answer or "")).strip()

    if not user_text:
        return "New Case"

    fallback_title = conversation_title_from_text(user_text)
    request_info = (
        detected_live_request
        if isinstance(detected_live_request, dict)
        else detect_live_request(user_text, None)
    )
    live_type = str(request_info.get("type") or "none").strip().lower()

    # Short prompts and live lookups already produce reliable deterministic
    # titles, so avoid a separate OpenAI request for these common cases.
    # Most staff prompts can be titled accurately without a second model call.
    # Reserve AI title generation for unusually long or complex first messages.
    if (
        live_type != "none"
        or len(user_text.split()) <= 80
        or re.search(
            r"(?i)\b(?:model|sku|order|tracking|install|compatib|"
            r"document|report|proposal|manual|guide|image|photo)\b",
            user_text,
        )
    ):
        return history_display_title(fallback_title)

    try:
        raw_title = _generate_ai_conversation_title_cached(
            user_text,
            answer_text,
        )
        title = re.sub(r"\s+", " ", raw_title).strip()
        title = title.strip(" \"'`“”‘’")
        title = re.sub(r"[.!?:;,-]+$", "", title).strip()

        # Safety cleanup: no emoji/symbol decorations and no oversized titles.
        title = re.sub(
            r"[^A-Za-z0-9&/+\- ]+",
            "",
            title,
        )
        title = re.sub(r"\s+", " ", title).strip()

        if title:
            words = title.split()[:5]
            return " ".join(words)[:36].rstrip()
    except Exception:
        pass

    return conversation_title_from_text(user_text)


def update_conversation_ai_title(
    conversation_id,
    first_message,
    assistant_answer="",
    detected_live_request=None,
):
    """Generate and store an AI title once the first answer is complete."""
    if not conversation_id:
        return

    generated_ids = st.session_state.setdefault(
        "ai_title_generated_conversation_ids",
        set(),
    )
    conversation_key = str(conversation_id)

    if conversation_key in generated_ids:
        return

    title_started_at = time.perf_counter()
    try:
        pending_ids = st.session_state.setdefault("auto_title_pending_ids", set())
        is_new_automatic_title = conversation_key in pending_ids
        current_title = ""

        # Newly created conversations are known to contain the automatic fallback
        # title, so avoid an immediate Supabase read-back. Older/restored chats are
        # still verified to protect manually renamed titles.
        if not is_new_automatic_title:
            current = (
                supabase
                .table("conversations")
                .select("title")
                .eq("id", conversation_id)
                .limit(1)
                .execute()
            )
            if current.data:
                current_title = str(current.data[0].get("title") or "").strip()

        fallback_title = conversation_title_from_text(first_message)
        normalized_message = re.sub(
            r"\s+",
            " ",
            str(first_message or ""),
        ).strip()

        # Recognize both the current fallback and the older raw-message title
        # formats as automatic titles. Manually renamed titles stay untouched.
        legacy_titles = {
            "New Case",
            fallback_title,
            normalized_message[:55].strip(),
            normalized_message[:48].strip(),
            normalized_message[:40].strip(),
        }
        if current_title and current_title not in legacy_titles:
            generated_ids.add(conversation_key)
            return

        ai_title = generate_ai_conversation_title(
            first_message,
            assistant_answer,
            detected_live_request=detected_live_request,
        )
        if not ai_title:
            return

        supabase.table("conversations").update({
            "title": ai_title,
            "updated_at": now_iso(),
        }).eq("id", conversation_id).execute()

        generated_ids.add(conversation_key)
        pending_ids.discard(conversation_key)
        invalidate_history_cache(
            conversations=True,
            messages=False,
            username=st.session_state.get("username"),
        )
        diagnostic_log(
            "conversation_title_updated",
            conversation_id=conversation_id,
            elapsed_seconds=round(time.perf_counter() - title_started_at, 3),
        )
    except Exception as error:
        # Title generation must never interrupt the conversation.
        diagnostic_log(
            "conversation_title_update_failed",
            conversation_id=conversation_id,
            error_type=type(error).__name__,
            error=str(error),
            elapsed_seconds=round(time.perf_counter() - title_started_at, 3),
        )


def get_conversation_storage_count(username, role=None):
    """
    Count active saved conversations for the signed-in user only.

    Every account has an independent history, including admin accounts.
    Pinned and unpinned active conversations are both included in the
    displayed storage count.
    """
    username = str(username or "").strip()
    if not username:
        return 0

    try:
        return _active_conversation_count_cached(username)
    except Exception:
        pass

    try:
        rows = safe_select_rows(
            "conversations",
            order_columns=["updated_at", "created_at"],
            limit=5000,
        )
        return len([
            row
            for row in rows
            if str(row.get("username", "")).lower() == username.lower()
            and not (
                row.get("archived") is True
                or str(row.get("archived")).lower() == "true"
            )
        ])
    except Exception:
        return 0


MAX_UNPINNED_CONVERSATIONS_PER_USER = 100
INITIAL_HISTORY_PAGE_SIZE = 30
HISTORY_PAGE_INCREMENT = 20


def _detach_learning_reference_before_history_delete(conversation_id):
    """
    Preserve learned knowledge before deleting old chat history.

    Only the optional source_conversation_id link is cleared. The learned
    record, uploaded knowledge file, OpenAI file, and vector-store content
    remain untouched.
    """
    if not conversation_id:
        return

    columns = set(get_table_columns("learned_knowledge"))
    if "source_conversation_id" not in columns:
        return

    try:
        (
            supabase
            .table("learned_knowledge")
            .update({"source_conversation_id": None})
            .eq("source_conversation_id", conversation_id)
            .execute()
        )
    except Exception as error:
        raise RuntimeError(
            "Could not safely preserve learned knowledge before deleting "
            "the oldest conversation. No automatic deletion was performed."
        ) from error


def _delete_old_unpinned_conversation(username, conversation_id):
    """
    Delete one old unpinned conversation belonging to one user account.

    Pinned conversations are protected. Only that conversation and its
    message rows are deleted.
    """
    username = str(username or "").strip()
    if not username or not conversation_id:
        return False

    check = (
        supabase
        .table("conversations")
        .select("id, username, pinned")
        .eq("id", conversation_id)
        .eq("username", username)
        .limit(1)
        .execute()
    )
    rows = list(check.data or [])
    if not rows or bool(rows[0].get("pinned", False)):
        return False

    _detach_learning_reference_before_history_delete(conversation_id)

    (
        supabase
        .table("messages")
        .delete()
        .eq("conversation_id", conversation_id)
        .execute()
    )
    (
        supabase
        .table("conversations")
        .delete()
        .eq("id", conversation_id)
        .eq("username", username)
        .eq("pinned", False)
        .execute()
    )
    return True


def make_room_for_new_conversation(
    username,
    max_unpinned=MAX_UNPINNED_CONVERSATIONS_PER_USER,
):
    """
    Keep at most 100 unpinned conversations for one user.

    Use an exact database count first, then fetch only the oldest IDs that must
    be removed. This avoids downloading the user's entire history whenever a
    new conversation is created.
    """
    username = str(username or "").strip()
    if not username:
        raise RuntimeError("A valid username is required to save chat history.")

    try:
        max_unpinned = max(1, int(max_unpinned))
    except (TypeError, ValueError):
        max_unpinned = MAX_UNPINNED_CONVERSATIONS_PER_USER

    count_result = (
        supabase
        .table("conversations")
        .select("id", count="exact", head=True)
        .eq("username", username)
        .eq("pinned", False)
        .or_("archived.is.null,archived.eq.false")
        .execute()
    )
    current_count = int(count_result.count or 0)
    delete_count = max(0, current_count - max_unpinned + 1)
    if delete_count <= 0:
        return

    oldest_result = (
        supabase
        .table("conversations")
        .select("id")
        .eq("username", username)
        .eq("pinned", False)
        .or_("archived.is.null,archived.eq.false")
        .order("created_at", desc=False)
        .limit(delete_count)
        .execute()
    )

    for conversation in list(oldest_result.data or []):
        _delete_old_unpinned_conversation(
            username,
            conversation.get("id"),
        )


def create_conversation(username, assistant_name, first_message=None):
    """Create a new conversation and return its ID."""
    # History is isolated by username. Pinned chats are unlimited; only
    # unpinned chats are limited to the newest 100 for this account.
    make_room_for_new_conversation(username)
    payload = {
        "username": username,
        "assistant": clean_assistant_label(assistant_name),
        "title": conversation_title_from_text(first_message),
        "archived": False,
        "pinned": False,
        "created_at": now_iso(),
        "updated_at": now_iso()
    }

    try:
        result = supabase.table("conversations").insert(payload).execute()
    except Exception as e:
        # Backward compatible if the pinned column has not been added yet.
        if "pinned" in str(e).lower():
            payload.pop("pinned", None)
            result = supabase.table("conversations").insert(payload).execute()
        else:
            raise

    if not result.data:
        raise RuntimeError("Conversation was not created. Supabase returned no data.")

    conversation_id = result.data[0]["id"]
    st.session_state.setdefault("auto_title_pending_ids", set()).add(
        str(conversation_id)
    )
    invalidate_history_cache(
        conversations=True,
        messages=False,
        username=username,
    )
    return conversation_id


def save_message(
    conversation_id,
    role,
    content,
    touch_conversation=None,
):
    """
    Save one message and touch the conversation once at assistant completion.
    """
    if not conversation_id:
        raise RuntimeError("Missing conversation_id. Message was not saved.")

    save_started_at = time.perf_counter()
    supabase.table("messages").insert({
        "conversation_id": conversation_id,
        "role": role,
        "content": content,
        "created_at": now_iso(),
    }).execute()

    should_touch = (
        str(role or "").strip().lower() == "assistant"
        if touch_conversation is None
        else bool(touch_conversation)
    )

    if should_touch:
        supabase.table("conversations").update({
            "updated_at": now_iso(),
        }).eq("id", conversation_id).execute()

    invalidate_history_cache(
        conversations=should_touch,
        messages=True,
        username=st.session_state.get("username"),
        conversation_id=conversation_id,
    )
    diagnostic_log(
        "supabase_message_saved",
        role=role,
        conversation_id=conversation_id,
        touched_conversation=should_touch,
        elapsed_seconds=round(time.perf_counter() - save_started_at, 3),
    )

@st.cache_data(ttl=60, max_entries=256, show_spinner=False)
def _load_conversations_cached(
    username,
    unpinned_limit=INITIAL_HISTORY_PAGE_SIZE,
):
    """
    Load lightweight sidebar summaries incrementally.

    Pinned rows remain available independently. Unpinned rows are transferred
    only up to the current sidebar page size.
    """
    username = str(username or "").strip()
    if not username:
        return []

    try:
        clean_limit = int(unpinned_limit)
    except (TypeError, ValueError):
        clean_limit = INITIAL_HISTORY_PAGE_SIZE
    clean_limit = max(
        INITIAL_HISTORY_PAGE_SIZE,
        min(clean_limit, MAX_UNPINNED_CONVERSATIONS_PER_USER),
    )

    selected_columns = (
        "id,username,assistant,title,archived,pinned,"
        "created_at,updated_at"
    )
    base_filter = "archived.is.null,archived.eq.false"

    pinned_result = (
        supabase
        .table("conversations")
        .select(selected_columns)
        .eq("username", username)
        .eq("pinned", True)
        .or_(base_filter)
        .order("updated_at", desc=True)
        .execute()
    )
    unpinned_result = (
        supabase
        .table("conversations")
        .select(selected_columns)
        .eq("username", username)
        .eq("pinned", False)
        .or_(base_filter)
        .order("updated_at", desc=True)
        .limit(clean_limit)
        .execute()
    )

    return list(pinned_result.data or []) + list(
        unpinned_result.data or []
    )


@st.cache_data(ttl=60, max_entries=128, show_spinner=False)
def _active_conversation_count_cached(username):
    """Return the exact active saved-conversation count for one user."""
    username = str(username or "").strip()
    if not username:
        return 0

    result = (
        supabase
        .table("conversations")
        .select("id", count="exact", head=True)
        .eq("username", username)
        .or_("archived.is.null,archived.eq.false")
        .execute()
    )
    return int(result.count or 0)


@st.cache_data(ttl=60, max_entries=256, show_spinner=False)
def _load_messages_cached(conversation_id):
    """Load selected-conversation messages with a short cache."""
    if not conversation_id:
        return []

    # Fetch only the most recent messages. Ordering newest-first lets Supabase
    # apply the limit before transferring data; reverse locally for chat order.
    result = (
        supabase
        .table("messages")
        .select("role,content,created_at")
        .eq("conversation_id", conversation_id)
        .order("created_at", desc=True)
        .limit(2000)
        .execute()
    )

    rows = list(reversed(result.data or []))
    return [
        {
            "role": item.get("role", "assistant"),
            "content": item.get("content", ""),
        }
        for item in rows
    ]


def invalidate_history_cache(
    conversations=True,
    messages=True,
    username=None,
    conversation_id=None,
):
    """
    Invalidate only affected history cache entries when supported.

    Older Streamlit versions fall back safely to clearing the whole function
    cache, preserving compatibility with Streamlit Cloud.
    """
    if conversations:
        st.session_state.pop(
            "conversation_title_session_cache",
            None,
        )

    if conversations:
        # Multiple page-size variants may exist, so clear the paged summary
        # cache together with the exact count cache.
        try:
            _load_conversations_cached.clear()
        except Exception:
            pass
        try:
            _active_conversation_count_cached.clear()
        except Exception:
            pass

    if messages:
        try:
            if conversation_id:
                _load_messages_cached.clear(conversation_id)
            else:
                _load_messages_cached.clear()
        except TypeError:
            _load_messages_cached.clear()
        except Exception:
            pass


def load_messages(conversation_id):
    """Load messages for the selected conversation through a short cache."""
    cached_messages = _load_messages_cached(conversation_id)
    return [dict(message) for message in cached_messages]

def load_conversations(
    username,
    role=None,
    unpinned_limit=INITIAL_HISTORY_PAGE_SIZE,
):
    """
    Load active sidebar summaries for the signed-in user.

    Full messages remain lazy and are fetched only when a conversation opens.
    """
    return [
        dict(conversation)
        for conversation in _load_conversations_cached(
            str(username or "").strip(),
            unpinned_limit,
        )
    ]

def archive_conversation(conversation_id):
    if conversation_id:
        supabase.table("conversations").update({
            "archived": True,
            "updated_at": now_iso()
        }).eq("id", conversation_id).execute()
        invalidate_history_cache(
            conversations=True,
            messages=False,
            username=st.session_state.get("username"),
        )


def delete_conversation(conversation_id):
    """Permanently delete one conversation owned by the signed-in user."""
    if not conversation_id:
        return

    username = str(st.session_state.get("username") or "").strip()

    # Keep explicit message deletion for schemas without ON DELETE CASCADE.
    supabase.table("messages").delete().eq(
        "conversation_id",
        conversation_id,
    ).execute()

    delete_query = (
        supabase
        .table("conversations")
        .delete()
        .eq("id", conversation_id)
    )
    if username:
        delete_query = delete_query.eq("username", username)
    delete_query.execute()
    invalidate_history_cache(
        conversations=True,
        messages=True,
        username=st.session_state.get("username"),
        conversation_id=conversation_id,
    )


def toggle_pin_conversation(conversation_id, pinned):
    """Pin or unpin a conversation in the sidebar."""
    if not conversation_id:
        return

    supabase.table("conversations").update({
        "pinned": bool(pinned),
        "updated_at": now_iso()
    }).eq("id", conversation_id).execute()
    invalidate_history_cache(
        conversations=True,
        messages=False,
        username=st.session_state.get("username"),
    )


def format_history_date(value):
    if not value:
        return ""

    text = str(value)[:10]
    try:
        dt = datetime.fromisoformat(text)
        return dt.strftime("%b %-d")
    except Exception:
        try:
            dt = datetime.strptime(text, "%Y-%m-%d")
            return dt.strftime("%b %d").replace(" 0", " ")
        except Exception:
            return text


def _cached_conversation_row(conversation_id):
    """Resolve one conversation from cached sidebar rows without another query."""
    if not conversation_id:
        return None

    username = str(st.session_state.get("username") or "").strip()
    if not username:
        return None

    try:
        history_limit = int(
            st.session_state.get(
                "history_unpinned_limit",
                INITIAL_HISTORY_PAGE_SIZE,
            )
            or INITIAL_HISTORY_PAGE_SIZE
        )
        for conversation in _load_conversations_cached(
            username,
            history_limit,
        ):
            if str(conversation.get("id")) == str(conversation_id):
                return conversation
    except Exception:
        pass

    return None


def _cached_conversation_title(conversation_id):
    """Resolve a title from cached sidebar rows before querying Supabase."""
    conversation = _cached_conversation_row(conversation_id)
    if not conversation:
        return ""
    return str(conversation.get("title") or "").strip()


def get_current_conversation_title():
    cid = st.session_state.get("conversation_id")
    if not cid:
        return "New Case"

    cached_title = _cached_conversation_title(cid)
    if cached_title:
        return cached_title

    session_titles = st.session_state.setdefault(
        "conversation_title_session_cache",
        {},
    )
    conversation_key = str(cid)
    if conversation_key in session_titles:
        return session_titles[conversation_key]

    try:
        result = (
            supabase
            .table("conversations")
            .select("title")
            .eq("id", cid)
            .limit(1)
            .execute()
        )
        if result.data:
            title = result.data[0].get("title") or "New Case"
            session_titles[conversation_key] = title
            return title
    except Exception:
        pass
    return "New Case"


def render_rename_form(conversations):
    """Inline rename form shown below the history list."""
    rename_id = st.session_state.get("rename_conversation_id")
    if not rename_id:
        return

    target = None
    for convo in conversations:
        if str(convo.get("id")) == str(rename_id):
            target = convo
            break

    if not target:
        st.session_state.rename_conversation_id = None
        return

    st.sidebar.markdown('<div class="rename-box-title">Rename conversation</div>', unsafe_allow_html=True)

    with st.sidebar.form(f"rename_form_{rename_id}", clear_on_submit=False):
        new_title = st.text_input(
            "Title",
            value=st.session_state.get("rename_conversation_value", target.get("title") or "New Case"),
            label_visibility="collapsed"
        )

        save_col, cancel_col = st.columns([0.58, 0.42], gap="small")

        with save_col:
            save_clicked = st.form_submit_button("Save", use_container_width=True)

        with cancel_col:
            cancel_clicked = st.form_submit_button("Cancel", use_container_width=True)

    if save_clicked:
        cleaned = new_title.strip() or "New Case"
        supabase.table("conversations").update({
            "title": cleaned,
            "updated_at": now_iso()
        }).eq("id", rename_id).execute()

        st.session_state.rename_conversation_id = None
        st.session_state.rename_conversation_value = ""
        st.rerun()

    if cancel_clicked:
        st.session_state.rename_conversation_id = None
        st.session_state.rename_conversation_value = ""
        st.rerun()



# ============================================================
# ChatGPT-style HTML History Actions
# ============================================================

def app_action_url(action, conversation_id):
    """Build query-string URL for custom HTML history actions."""
    session_token = st.query_params.get("session")
    parts = []
    if session_token:
        parts.append(f"session={html.escape(str(session_token), quote=True)}")
    parts.append(f"hist_action={html.escape(str(action), quote=True)}")
    parts.append(f"cid={html.escape(str(conversation_id), quote=True)}")
    return "?" + "&".join(parts)


def clear_history_action_params():
    """Clear one-time history action query params while preserving login session."""
    session_token = st.query_params.get("session")
    st.query_params.clear()
    if session_token:
        st.query_params["session"] = session_token


def process_history_action():
    """Process open / rename / pin / archive / delete from custom HTML history links."""
    action = st.query_params.get("hist_action")
    cid = st.query_params.get("cid")

    if not action or not cid:
        return

    if "rename_conversation_id" not in st.session_state:
        st.session_state.rename_conversation_id = None
    if "history_unpinned_limit" not in st.session_state:
        st.session_state.history_unpinned_limit = INITIAL_HISTORY_PAGE_SIZE
    if "rename_conversation_value" not in st.session_state:
        st.session_state.rename_conversation_value = ""

    try:
        if action == "open":
            st.session_state.conversation_id = cid
            st.session_state.messages = load_messages(cid)
            st.session_state.rename_conversation_id = None
            st.session_state.scroll_to_bottom = True

        elif action == "rename":
            st.session_state.rename_conversation_id = str(cid)
            st.session_state.rename_conversation_value = get_conversation_title_by_id(cid)

        elif action == "pin":
            cached_conversation = _cached_conversation_row(cid)
            if cached_conversation is not None:
                pinned = bool(cached_conversation.get("pinned", False))
            else:
                current = (
                    supabase.table("conversations")
                    .select("pinned")
                    .eq("id", cid)
                    .limit(1)
                    .execute()
                )
                pinned = False
                if current.data:
                    pinned = bool(current.data[0].get("pinned", False))
            toggle_pin_conversation(cid, not pinned)

        elif action == "archive":
            archive_conversation(cid)
            if st.session_state.conversation_id == cid:
                st.session_state.conversation_id = None
                st.session_state.messages = []

        elif action == "delete":
            delete_conversation(cid)
            if st.session_state.conversation_id == cid:
                st.session_state.conversation_id = None
                st.session_state.messages = []

    except Exception as e:
        st.session_state.history_action_error = str(e)

    clear_history_action_params()
    st.rerun()


def get_conversation_title_by_id(conversation_id):
    cached_title = _cached_conversation_title(conversation_id)
    if cached_title:
        return cached_title

    session_titles = st.session_state.setdefault(
        "conversation_title_session_cache",
        {},
    )
    conversation_key = str(conversation_id or "")
    if conversation_key in session_titles:
        return session_titles[conversation_key]

    try:
        result = (
            supabase
            .table("conversations")
            .select("title")
            .eq("id", conversation_id)
            .limit(1)
            .execute()
        )
        if result.data:
            title = result.data[0].get("title") or "New Case"
            session_titles[conversation_key] = title
            return title
    except Exception:
        pass
    return "New Case"


def _history_datetime(conversation):
    """Return the best available timezone-aware datetime for history grouping."""
    raw_value = (
        conversation.get("updated_at")
        or conversation.get("created_at")
        or ""
    )

    if not raw_value:
        return None

    try:
        parsed = datetime.fromisoformat(
            str(raw_value).replace("Z", "+00:00")
        )
        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=timezone.utc)
        return parsed.astimezone(timezone.utc)
    except Exception:
        return None


def _history_group_name(conversation):
    """Group conversations into familiar, mobile-friendly date sections."""
    conversation_time = _history_datetime(conversation)
    if conversation_time is None:
        return "Older"

    now = datetime.now(timezone.utc)
    today = now.date()
    conversation_date = conversation_time.date()
    days_old = (today - conversation_date).days

    if days_old <= 0:
        return "Today"
    if days_old == 1:
        return "Yesterday"
    if days_old <= 7:
        return "Last 7 Days"
    return "Older"


def _history_time_label(conversation):
    """Small secondary label shown beside each saved conversation."""
    conversation_time = _history_datetime(conversation)
    if conversation_time is None:
        return ""

    group_name = _history_group_name(conversation)

    if group_name == "Today":
        return conversation_time.strftime("%I:%M %p").lstrip("0")
    if group_name == "Yesterday":
        return "Yesterday"
    if group_name == "Last 7 Days":
        return conversation_time.strftime("%a")
    return conversation_time.strftime("%b %d")


def render_history_cards(conversations):
    """
    Responsive Streamlit-native conversation history.

    Stability:
    - Keeps existing open, rename, pin, archive, and delete functions.
    - Uses only native Streamlit widgets plus scoped CSS.
    - Does not introduce JavaScript or a second state-management system.
    """
    search_value = str(
        st.session_state.get("history_search_query", "")
    ).strip().lower()

    visible_conversations = []

    for conversation in conversations:
        title = str(conversation.get("title") or "New Case")
        assistant_name = str(conversation.get("assistant") or "")

        if (
            not search_value
            or search_value in title.lower()
            or search_value in assistant_name.lower()
        ):
            visible_conversations.append(conversation)

    pinned_conversations = [
        conversation
        for conversation in visible_conversations
        if conversation.get("pinned")
    ]

    normal_conversations = [
        conversation
        for conversation in visible_conversations
        if not conversation.get("pinned")
    ]

    grouped = {
        "Today": [],
        "Yesterday": [],
        "Last 7 Days": [],
        "Older": [],
    }

    for conversation in normal_conversations:
        grouped[_history_group_name(conversation)].append(conversation)

    recent_conversations = []
    for group_name in ("Today", "Yesterday", "Last 7 Days", "Older"):
        recent_conversations.extend(grouped[group_name])

    sections = [
        ("Pinned", pinned_conversations),
        ("Recents", recent_conversations),
    ]

    if not pinned_conversations and not recent_conversations:
        empty_text = (
            "No matching conversations."
            if search_value
            else "No saved conversations yet."
        )
        st.markdown(
            f'<div class="history-empty-state">{html.escape(empty_text)}</div>',
            unsafe_allow_html=True,
        )
        return

    history_box = st.sidebar.container(
        height=460,
        border=False,
    )

    with history_box:
        for section_name, section_conversations in sections:
            st.markdown(
                (
                    '<div class="history-section-label">'
                    f'{html.escape(section_name)}'
                    '</div>'
                    '<div class="history-section-heading-gap" '
                    'aria-hidden="true"></div>'
                ),
                unsafe_allow_html=True,
            )
            if not section_conversations:
                empty_label = (
                    "No pinned conversations"
                    if section_name == "Pinned"
                    else "No recent conversations"
                )
                st.markdown(
                    (
                        '<div class="history-empty-state">'
                        f'{html.escape(empty_label)}'
                        '</div>'
                    ),
                    unsafe_allow_html=True,
                )
                continue

            for conversation in section_conversations:
                conversation_id = conversation["id"]
                title = str(
                    conversation.get("title")
                    or "New Case"
                )
                pinned = bool(
                    conversation.get("pinned", False)
                )
                is_current = (
                    str(
                        st.session_state.get(
                            "conversation_id"
                        )
                    )
                    == str(conversation_id)
                )

                # Display the complete saved AI title. CSS keeps it on one
                # line and adds an ellipsis only at the actual row boundary.
                title_short = history_display_title(title)
                time_label = _history_time_label(
                    conversation
                )

                history_label = title_short

                row_state = []
                if is_current:
                    row_state.append("active")
                if pinned:
                    row_state.append("pinned")

                row_suffix = "_".join(row_state) or "normal"

                row = st.container(
                    key=(
                        f"history_row_{row_suffix}_"
                        f"{conversation_id}"
                    )
                )

                with row:
                    if st.button(
                        history_label,
                        key=f"open_{conversation_id}",
                        help=title,
                        use_container_width=True,
                    ):
                        st.session_state.conversation_id = conversation_id
                        st.session_state.messages = load_messages(
                            conversation_id
                        )
                        st.session_state.rename_conversation_id = None
                        st.session_state.scroll_to_bottom = True
                        st.rerun()

                    if time_label:
                        st.markdown(
                            (
                                '<div class="history-row-meta">'
                                f'{html.escape(time_label)}'
                                '</div>'
                            ),
                            unsafe_allow_html=True,
                        )

                    with st.popover(
                        "⋯",
                        help="Conversation actions",
                    ):
                        st.markdown(
                            (
                                '<div class="history-menu-title">'
                                f'{html.escape(title_short)}'
                                '</div>'
                            ),
                            unsafe_allow_html=True,
                        )

                        if st.button(
                            "Rename",
                            key=f"rename_{conversation_id}",
                            use_container_width=True,
                        ):
                            st.session_state.rename_conversation_id = str(
                                conversation_id
                            )
                            st.session_state.rename_conversation_value = title
                            st.rerun()

                        pin_label = (
                            "Unpin chat"
                            if pinned
                            else "Pin chat"
                        )

                        if st.button(
                            pin_label,
                            key=f"pin_{conversation_id}",
                            use_container_width=True,
                        ):
                            try:
                                toggle_pin_conversation(
                                    conversation_id,
                                    not pinned,
                                )
                                st.rerun()
                            except Exception:
                                st.toast(
                                    "Pin needs the pinned column in Supabase."
                                )

                        if st.button(
                            "Archive",
                            key=f"archive_{conversation_id}",
                            use_container_width=True,
                        ):
                            archive_conversation(conversation_id)
                            if (
                                st.session_state.conversation_id
                                == conversation_id
                            ):
                                st.session_state.conversation_id = None
                                st.session_state.messages = []
                            st.rerun()

                        if st.button(
                            "Delete",
                            key=f"delete_{conversation_id}",
                            use_container_width=True,
                        ):
                            delete_conversation(conversation_id)
                            if (
                                st.session_state.conversation_id
                                == conversation_id
                            ):
                                st.session_state.conversation_id = None
                                st.session_state.messages = []
                            st.rerun()


def install_global_chat_file_dropzone():
    """
    Reliably forward files dropped anywhere over the main chat, or pasted
    images, into the existing Streamlit chat file uploader.

    The browser listeners are replaced on every Streamlit rerun, and the
    current chat uploader input is located dynamically inside its keyed
    container. No separate backend upload path is introduced.
    """
    components.html(
        """
        <script>
        (() => {
            const parentWindow = window.parent;
            const doc = parentWindow.document;
            const CONTROLLER_KEY = "__atpGlobalChatDropzoneV2";
            const CHAT_SHELL_SELECTOR =
                'div[class*="st-key-atp_upload_shell_chat_files"]';
            const ACCEPTED_EXTENSIONS = [
                ".jpg", ".jpeg", ".png", ".pdf", ".txt",
                ".doc", ".docx", ".xls", ".xlsx", ".xlsm", ".xlsb", ".csv",
                ".ppt", ".pptx"
            ];

            // Streamlit reruns can destroy the component iframe while leaving
            // listeners on the parent document. Always remove the previous
            // listener set before installing the current one.
            try {
                parentWindow[CONTROLLER_KEY]?.cleanup?.();
            } catch (error) {
                console.warn(
                    "AutoTecPro AI: previous dropzone cleanup failed.",
                    error
                );
            }

            let disposed = false;
            let dragActive = false;
            let hideTimer = null;

            function ensureOverlay() {
                let overlay = doc.getElementById("atp-global-drop-overlay");

                if (!overlay) {
                    overlay = doc.createElement("div");
                    overlay.id = "atp-global-drop-overlay";
                    overlay.innerHTML = `
                        <div style="
                            width:min(520px,82vw);
                            padding:34px 28px;
                            border-radius:22px;
                            border:2px dashed rgba(255,255,255,.78);
                            background:rgba(15,23,42,.92);
                            box-shadow:0 24px 70px rgba(0,0,0,.42);
                            color:#fff;
                            text-align:center;
                            font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;
                        ">
                            <div style="font-size:42px;line-height:1;margin-bottom:12px;">
                                📎
                            </div>
                            <div style="font-size:22px;font-weight:800;margin-bottom:7px;">
                                Drop files to attach
                            </div>
                            <div style="font-size:14px;color:#cbd5e1;">
                                JPG, PNG, PDF, TXT, Word, Excel, CSV, or PowerPoint
                            </div>
                        </div>
                    `;

                    Object.assign(overlay.style, {
                        position: "fixed",
                        inset: "0",
                        zIndex: "2147483646",
                        display: "none",
                        alignItems: "center",
                        justifyContent: "center",
                        background: "rgba(2,6,23,.68)",
                        backdropFilter: "blur(6px)",
                        WebkitBackdropFilter: "blur(6px)",
                        pointerEvents: "none"
                    });

                    doc.body.appendChild(overlay);
                }

                return overlay;
            }

            const overlay = ensureOverlay();

            function showOverlay() {
                if (disposed) return;
                dragActive = true;
                if (hideTimer) {
                    parentWindow.clearTimeout(hideTimer);
                    hideTimer = null;
                }
                overlay.style.display = "flex";
            }

            function hideOverlay() {
                dragActive = false;
                if (hideTimer) {
                    parentWindow.clearTimeout(hideTimer);
                    hideTimer = null;
                }
                overlay.style.display = "none";
            }

            function scheduleOverlayHide() {
                if (hideTimer) {
                    parentWindow.clearTimeout(hideTimer);
                }

                hideTimer = parentWindow.setTimeout(() => {
                    if (!dragActive) {
                        overlay.style.display = "none";
                    }
                }, 90);
            }

            function eventContainsFiles(event) {
                const transfer = event.dataTransfer;
                if (!transfer) return false;

                const types = Array.from(transfer.types || []);
                if (types.includes("Files")) return true;

                return Array.from(transfer.items || []).some(
                    (item) => item.kind === "file"
                );
            }

            function getCurrentChatFileInput() {
                const shells = Array.from(
                    doc.querySelectorAll(CHAT_SHELL_SELECTOR)
                ).filter((shell) => shell.isConnected);

                // During a Streamlit rerun, an old shell can briefly coexist
                // with the newly mounted one. Prefer the newest connected shell.
                for (let index = shells.length - 1; index >= 0; index -= 1) {
                    const inputs = Array.from(
                        shells[index].querySelectorAll('input[type="file"]')
                    ).filter(
                        (input) =>
                            input.isConnected &&
                            !input.disabled
                    );

                    if (inputs.length) {
                        return inputs[inputs.length - 1];
                    }
                }

                return null;
            }

            const MIME_BY_EXTENSION = {
                ".jpg": "image/jpeg",
                ".jpeg": "image/jpeg",
                ".png": "image/png",
                ".pdf": "application/pdf",
                ".txt": "text/plain",
                ".doc": "application/msword",
                ".docx": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
                ".xls": "application/vnd.ms-excel",
                ".xlsx": "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                ".xlsm": "application/vnd.ms-excel.sheet.macroEnabled.12",
                ".xlsb": "application/vnd.ms-excel.sheet.binary.macroEnabled.12",
                ".csv": "text/csv",
                ".ppt": "application/vnd.ms-powerpoint",
                ".pptx": "application/vnd.openxmlformats-officedocument.presentationml.presentation"
            };

            function fileExtension(file) {
                const name = String(file?.name || "").toLowerCase();
                return ACCEPTED_EXTENSIONS.find(
                    (extension) => name.endsWith(extension)
                ) || "";
            }

            function acceptedFiles(fileList) {
                // Preserve the browser's original File objects. Rebuilding Office
                // files can make Excel uploads fail in Chromium even when Word,
                // PDF, and images continue to work.
                return Array.from(fileList || []).filter(
                    (file) => Boolean(fileExtension(file))
                );
            }

            function setInputFiles(input, files) {
                const transfer = new DataTransfer();
                const seen = new Set();

                // Preserve files already present in the current uploader.
                for (const file of Array.from(input.files || [])) {
                    const signature = [
                        file.name,
                        file.size,
                        file.lastModified,
                        file.type
                    ].join("|");

                    if (!seen.has(signature)) {
                        seen.add(signature);
                        transfer.items.add(file);
                    }
                }

                for (const file of files) {
                    const signature = [
                        file.name,
                        file.size,
                        file.lastModified,
                        file.type
                    ].join("|");

                    if (!seen.has(signature)) {
                        seen.add(signature);
                        transfer.items.add(file);
                    }
                }

                const filesSetter = Object.getOwnPropertyDescriptor(
                    parentWindow.HTMLInputElement.prototype,
                    "files"
                )?.set;

                if (filesSetter) {
                    filesSetter.call(input, transfer.files);
                } else {
                    input.files = transfer.files;
                }

                // Dispatch both events because Streamlit/React versions can
                // listen to either one.
                input.dispatchEvent(
                    new parentWindow.Event("input", {
                        bubbles: true,
                        composed: true
                    })
                );
                input.dispatchEvent(
                    new parentWindow.Event("change", {
                        bubbles: true,
                        composed: true
                    })
                );
            }

            function attachFilesWithRetry(fileList, attempt = 0) {
                if (disposed) return;

                const files = acceptedFiles(fileList);
                if (!files.length) return;

                const input = getCurrentChatFileInput();

                if (!input) {
                    // Streamlit may be between unmounting the old uploader and
                    // mounting the new generation. Retry briefly instead of
                    // silently failing and requiring a browser refresh.
                    if (attempt < 20) {
                        parentWindow.setTimeout(
                            () => attachFilesWithRetry(files, attempt + 1),
                            75
                        );
                    } else {
                        console.warn(
                            "AutoTecPro AI: chat uploader was not available after retries."
                        );
                    }
                    return;
                }

                try {
                    setInputFiles(input, files);
                } catch (error) {
                    // A stale input can disappear between lookup and assignment.
                    // Retry against the newest mounted input.
                    if (attempt < 20) {
                        parentWindow.setTimeout(
                            () => attachFilesWithRetry(files, attempt + 1),
                            75
                        );
                    } else {
                        console.error(
                            "AutoTecPro AI: could not attach dropped files.",
                            error
                        );
                    }
                }
            }

            function onDragEnter(event) {
                if (!eventContainsFiles(event)) return;
                event.preventDefault();
                showOverlay();
            }

            function onDragOver(event) {
                if (!eventContainsFiles(event)) return;
                event.preventDefault();
                event.stopPropagation();

                if (event.dataTransfer) {
                    event.dataTransfer.dropEffect = "copy";
                }

                showOverlay();
            }

            function onDragLeave(event) {
                if (!eventContainsFiles(event)) return;
                event.preventDefault();

                // Avoid an error-prone drag-depth counter. Hide only after a
                // short delay; another dragover immediately cancels the hide.
                dragActive = false;
                scheduleOverlayHide();
            }

            function onDrop(event) {
                if (!eventContainsFiles(event)) return;

                event.preventDefault();
                event.stopPropagation();
                hideOverlay();

                const files = Array.from(event.dataTransfer?.files || []);
                attachFilesWithRetry(files);
            }

            function onPaste(event) {
                const clipboardFiles = Array.from(
                    event.clipboardData?.files || []
                );
                if (!clipboardFiles.length) return;

                const imageFiles = clipboardFiles.filter((file) =>
                    String(file.type || "").toLowerCase().startsWith("image/")
                );
                if (!imageFiles.length) return;

                event.preventDefault();
                attachFilesWithRetry(imageFiles);
            }

            function onWindowBlur() {
                hideOverlay();
            }

            function cleanup() {
                if (disposed) return;
                disposed = true;

                doc.removeEventListener("dragenter", onDragEnter, true);
                doc.removeEventListener("dragover", onDragOver, true);
                doc.removeEventListener("dragleave", onDragLeave, true);
                doc.removeEventListener("drop", onDrop, true);
                doc.removeEventListener("paste", onPaste, true);
                parentWindow.removeEventListener("blur", onWindowBlur);

                if (hideTimer) {
                    parentWindow.clearTimeout(hideTimer);
                    hideTimer = null;
                }

                overlay.style.display = "none";
            }

            doc.addEventListener("dragenter", onDragEnter, true);
            doc.addEventListener("dragover", onDragOver, true);
            doc.addEventListener("dragleave", onDragLeave, true);
            doc.addEventListener("drop", onDrop, true);
            doc.addEventListener("paste", onPaste, true);
            parentWindow.addEventListener("blur", onWindowBlur);

            parentWindow[CONTROLLER_KEY] = { cleanup };

            // Cleanup when this particular component iframe is destroyed.
            window.addEventListener("beforeunload", cleanup, { once: true });
        })();
        </script>
        """,
        height=0,
        width=0,
    )



def auto_scroll_to_latest():
    """Scroll browser to the latest chat reply after a rerun."""
    components.html(
        """
        <script>
        const scrollToBottom = () => {
            const doc = window.parent.document;
            const anchor = doc.getElementById("chat-bottom-anchor");
            if (anchor) {
                anchor.scrollIntoView({behavior: "smooth", block: "end"});
            } else {
                window.parent.scrollTo({top: doc.body.scrollHeight, behavior: "smooth"});
            }
        };
        setTimeout(scrollToBottom, 120);
        setTimeout(scrollToBottom, 500);
        </script>
        """,
        height=0,
    )


