def save_knowledge_submission(
    knowledge_type,
    subject,
    issue,
    solution,
    uploaded_files=None,
):
    """
    Validate and save a structured staff submission as Pending Review.

    The existing Admin approval/reject workflow remains unchanged.
    """
    safe_subject = redact_learning_private_data(subject)
    safe_issue = redact_learning_private_data(issue)
    safe_solution = redact_learning_private_data(solution)

    if not safe_subject:
        raise ValueError("Please enter a subject, product, or vehicle.")

    if len(safe_issue) < 10:
        raise ValueError(
            "Please provide a little more detail about the issue or situation."
        )

    if len(safe_solution) < 20:
        raise ValueError(
            "Please provide a little more detail about the confirmed solution."
        )

    combined_description = (
        f"Subject / Product / Vehicle:\n{safe_subject}\n\n"
        f"Issue / Situation:\n{safe_issue}\n\n"
        f"Confirmed Solution / Response:\n{safe_solution}"
    )

    selected_assistant, vector_store_id = knowledge_submission_destination(
        knowledge_type
    )

    # AI still analyzes all three fields together for keywords and confidence.
    candidate = extract_learning_candidate(
        combined_description,
        "",
        selected_assistant,
        staff_confirmed=True,
        conversation_context="",
    )

    if not candidate.get("should_learn"):
        reason = candidate.get("reason") or (
            "The submission does not yet contain clear, reusable knowledge."
        )
        raise ValueError(reason)

    # Preserve the staff's structured fields exactly. This keeps the existing
    # Admin review page, approve/merge logic, reject logic, and vector sync
    # fully compatible with the current database schema.
    candidate["vehicle"] = safe_subject
    candidate["issue"] = safe_issue
    candidate["solution"] = safe_solution

    pending_attachments = []
    for uploaded_file in uploaded_files or []:
        try:
            if is_admin_image_file(uploaded_file):
                knowledge_file, _ = convert_admin_image_to_knowledge_file(
                    uploaded_file,
                    (
                        "Sales Database"
                        if is_sales_workspace(selected_assistant)
                        else "Technical Support Database"
                    ),
                    admin_context=combined_description,
                )
                pending_attachments.append(
                    _create_pending_openai_file(knowledge_file)
                )
            else:
                pending_attachments.append(
                    _create_pending_openai_file(uploaded_file)
                )
        except Exception as error:
            raise RuntimeError(
                f"Supporting file "
                f"'{getattr(uploaded_file, 'name', 'file')}' "
                f"could not be stored for review: {error}"
            ) from error

    marker = f"[PENDING_KNOWLEDGE:{knowledge_type}]"
    clean_keywords = str(candidate.get("keywords") or "").strip()
    queued_keywords = (
        f"{marker}, {clean_keywords}" if clean_keywords else marker
    )

    pending_payload = {
        "username": st.session_state.get("username"),
        "assistant": clean_assistant_label(selected_assistant),
        "vehicle": safe_subject,
        "issue": safe_issue,
        "solution": safe_solution,
        "approved_answer": safe_solution,
        "question": combined_description,
        "keywords": queued_keywords,
        "source_question": combined_description,
        "source_answer": "",
        "source_conversation_id": None,
        "confidence_score": candidate["confidence_score"],
        "times_seen": 1,
        "times_used": 0,
        "search_count": 0,
        "vector_store_id": vector_store_id,
        "openai_file_id": (
            PENDING_ATTACHMENT_PREFIX
            + json.dumps(pending_attachments, ensure_ascii=False)
            if pending_attachments
            else ""
        ),
        "synced": False,
        "embedding_status": "pending_review",
        "source_type": f"pending_knowledge_submission:{knowledge_type}",
        "staff_confirmed": True,
        "created_at": now_iso(),
        "updated_at": now_iso(),
    }

    result = safe_insert_row("learned_knowledge", pending_payload)
    if not result.data:
        raise RuntimeError("The pending knowledge submission was not saved.")

    return {
        "mode": "pending",
        "record_id": result.data[0].get("id"),
        "issue": safe_issue,
        "vehicle": safe_subject,
        "destination": clean_assistant_label(selected_assistant),
        "attachment_count": len(pending_attachments),
        "status": "Pending Review",
    }


def _delete_pending_openai_files(attachments):
    """Best-effort cleanup for rejected pending attachments."""
    for attachment in attachments or []:
        file_id = str(attachment.get("file_id") or "").strip()
        if not file_id:
            continue
        try:
            client.files.delete(file_id)
        except Exception:
            pass



def get_pending_review_admin_client():
    """
    Use the existing privileged Supabase connection for the Admin review queue.

    Staff submissions continue to use the normal client. Only Admin review
    reads and mutations use service-role access so Row Level Security cannot
    hide one staff member's pending record from the administrator.
    """
    if str(st.session_state.get("role") or "").strip().lower() != "admin":
        raise PermissionError("Admin access is required.")

    return get_supabase_admin_client()


def select_pending_knowledge_rows(limit=500):
    """Load pending-review candidates through the privileged Admin client."""
    admin_client = get_pending_review_admin_client()
    last_error = None

    for order_column in ("created_at", "updated_at"):
        try:
            result = (
                admin_client
                .table("learned_knowledge")
                .select("*")
                .order(order_column, desc=True)
                .limit(max(1, min(int(limit or 500), 1000)))
                .execute()
            )
            return list(result.data or [])
        except Exception as error:
            last_error = error

    try:
        result = (
            admin_client
            .table("learned_knowledge")
            .select("*")
            .limit(max(1, min(int(limit or 500), 1000)))
            .execute()
        )
        return list(result.data or [])
    except Exception:
        if last_error:
            raise last_error
        raise


def admin_update_pending_row(row_id, payload):
    """Update a pending/approved row through the privileged Admin client."""
    clean_payload = filter_payload_for_table(
        "learned_knowledge",
        payload,
    )
    clean_payload = {
        key: value
        for key, value in clean_payload.items()
        if value is not None
    }

    return (
        get_pending_review_admin_client()
        .table("learned_knowledge")
        .update(clean_payload)
        .eq("id", row_id)
        .execute()
    )

def admin_delete_pending_row(row_id):
    """Delete a pending row through the privileged Admin client."""
    return (
        get_pending_review_admin_client()
        .table("learned_knowledge")
        .delete()
        .eq("id", row_id)
        .execute()
    )


def approve_pending_knowledge(row, edited_solution=None):
    """Approve one pending row, merge duplicates, and sync to vector stores."""
    approval_stage = "validating pending record"

    try:
        if not is_pending_knowledge_row(row):
            raise ValueError(
                "This record is not a pending knowledge submission."
            )

        knowledge_type, attachments = _pending_submission_metadata(row)
        attachments = [
            item for item in (attachments or [])
            if isinstance(item, dict)
        ]

        selected_assistant, vector_store_id = (
            knowledge_submission_destination(knowledge_type)
        )

        approval_stage = "preparing approved solution"
        solution = redact_learning_private_data(
            edited_solution
            if edited_solution is not None
            else row.get("solution")
            or row.get("approved_answer")
            or ""
        )
        solution = str(solution or "").strip()

        if len(solution) < 25:
            raise ValueError("The approved solution needs more detail.")

        candidate = {
            "vehicle": str(row.get("vehicle") or "").strip(),
            "issue": str(
                row.get("issue")
                or row.get("question")
                or ""
            ).strip(),
            "solution": solution,
            "keywords": re.sub(
                r"\[PENDING_KNOWLEDGE:[a-z0-9_\-]+\]\s*,?\s*",
                "",
                str(row.get("keywords") or ""),
                flags=re.IGNORECASE,
            ).strip(" ,"),
            "confidence_score": int(
                row.get("confidence_score") or 90
            ),
            "should_learn": True,
        }

        approval_stage = "checking existing approved knowledge"
        duplicate_row, duplicate_score = (
            find_duplicate_learned_knowledge(
                candidate,
                selected_assistant,
            )
        )

        if (
            duplicate_row
            and str(duplicate_row.get("id"))
            == str(row.get("id"))
        ):
            duplicate_row = None

        approval_stage = "attaching supporting files"
        attached_file_ids = []

        for attachment in attachments:
            file_id = str(
                attachment.get("file_id") or ""
            ).strip()
            if not file_id:
                continue

            client.vector_stores.files.create(
                vector_store_id=vector_store_id,
                file_id=file_id,
            )
            attached_file_ids.append(file_id)

        if duplicate_row:
            approval_stage = "merging duplicate knowledge"
            improved = improve_existing_solution(
                duplicate_row,
                candidate,
            )

            record_for_file = {
                "assistant": str(
                    clean_assistant_label(selected_assistant) or ""
                ),
                "vehicle": str(improved.get("vehicle") or ""),
                "issue": str(improved.get("issue") or ""),
                "solution": str(improved.get("solution") or ""),
                "keywords": str(improved.get("keywords") or ""),
                "confidence_score": int(
                    improved.get("confidence_score") or 90
                ),
                "times_seen": int(
                    improved.get("times_seen") or 1
                ),
                "source_question": str(
                    row.get("question") or ""
                ),
                "source_answer": "",
            }

            approval_stage = "uploading merged knowledge"
            learned_file_id = (
                upload_learned_record_to_vector_store(
                    record_for_file,
                    vector_store_id,
                )
            )

            update_payload = {
                "username": str(row.get("username") or ""),
                "assistant": record_for_file["assistant"],
                "vehicle": record_for_file["vehicle"],
                "issue": record_for_file["issue"],
                "solution": record_for_file["solution"],
                "approved_answer": record_for_file["solution"],
                "question": str(row.get("question") or ""),
                "keywords": record_for_file["keywords"],
                "source_question": str(
                    row.get("source_question")
                    or row.get("question")
                    or ""
                ),
                "source_answer": "",
                "confidence_score": (
                    record_for_file["confidence_score"]
                ),
                "times_seen": record_for_file["times_seen"],
                "openai_file_id": str(learned_file_id or ""),
                "vector_store_id": str(vector_store_id or ""),
                "synced": True,
                "embedding_status": "synced",
                "source_type": (
                    "approved_knowledge_submission:"
                    f"{knowledge_type}"
                ),
                "staff_confirmed": True,
                "updated_at": now_iso(),
            }

            approval_stage = "saving merged knowledge"
            admin_update_pending_row(
                duplicate_row["id"],
                update_payload,
            )
            admin_delete_pending_row(row.get("id"))

            return {
                "mode": "merged",
                "record_id": duplicate_row.get("id"),
                "duplicate_score": duplicate_score,
                "attachment_count": len(attached_file_ids),
            }

        approved_record = {
            "username": str(row.get("username") or ""),
            "assistant": str(
                clean_assistant_label(selected_assistant) or ""
            ),
            "vehicle": candidate["vehicle"],
            "issue": candidate["issue"],
            "solution": candidate["solution"],
            "approved_answer": candidate["solution"],
            "question": str(row.get("question") or ""),
            "keywords": candidate["keywords"],
            "source_question": str(
                row.get("source_question")
                or row.get("question")
                or ""
            ),
            "source_answer": "",
            "confidence_score": candidate["confidence_score"],
            "times_seen": int(row.get("times_seen") or 1),
            "times_used": int(row.get("times_used") or 0),
            "search_count": int(row.get("search_count") or 0),
            "vector_store_id": str(vector_store_id or ""),
            "synced": False,
            "embedding_status": "pending",
            "source_type": (
                "approved_knowledge_submission:"
                f"{knowledge_type}"
            ),
            "staff_confirmed": True,
            "updated_at": now_iso(),
        }

        approval_stage = "uploading approved knowledge"
        learned_file_id = upload_learned_record_to_vector_store(
            approved_record,
            vector_store_id,
        )

        approved_record["openai_file_id"] = str(
            learned_file_id or ""
        )
        approved_record["synced"] = True
        approved_record["embedding_status"] = "synced"

        approval_stage = "saving approved knowledge"
        admin_update_pending_row(
            row.get("id"),
            approved_record,
        )

        return {
            "mode": "approved",
            "record_id": row.get("id"),
            "attachment_count": len(attached_file_ids),
        }

    except Exception as error:
        raise RuntimeError(
            f"Approval failed while {approval_stage}: {error}"
        ) from error

def reject_pending_knowledge(row):
    """Reject one pending submission and remove its temporary attachments."""
    _, attachments = _pending_submission_metadata(row)
    _delete_pending_openai_files(attachments)
    admin_delete_pending_row(row.get("id"))


def render_pending_knowledge_review():
    """Render a lightweight admin queue with edit, approve, and reject."""
    st.markdown("### 📥 Pending Submissions")
    st.caption(
        "Review staff knowledge before it becomes searchable company knowledge."
    )

    if st.button(
        "Refresh Pending List",
        key="refresh_pending_knowledge",
        type="secondary",
    ):
        st.session_state.pending_knowledge_refresh_token = (
            int(st.session_state.get("pending_knowledge_refresh_token", 0)) + 1
        )
        st.rerun()

    try:
        rows = select_pending_knowledge_rows(limit=500)
        pending_rows = [row for row in rows if is_pending_knowledge_row(row)]
    except Exception as error:
        st.error(f"Unable to load pending submissions: {error}")
        pending_rows = []

    if not pending_rows:
        st.info("There are no pending knowledge submissions.")
        return

    st.caption(f"{len(pending_rows)} submission(s) waiting for review.")

    for row in pending_rows:
        row_id = row.get("id")
        knowledge_type, attachments = _pending_submission_metadata(row)
        type_label = next(
            (
                label
                for type_key, _, label in KNOWLEDGE_SUBMISSION_TYPES
                if type_key == knowledge_type
            ),
            "Knowledge",
        )
        issue = str(row.get("issue") or row.get("question") or "Submission")
        username = str(row.get("username") or "Staff")
        vehicle = str(row.get("vehicle") or "").strip()

        title_parts = [type_label, issue[:80], f"by {username}"]
        with st.expander(" | ".join(title_parts), expanded=False):
            st.write(f"**Submitted by:** {username}")
            st.write(f"**Target:** {row.get('assistant') or ''}")
            if vehicle:
                st.write(f"**Vehicle / Product:** {vehicle}")
            st.write(f"**Supporting files:** {len(attachments)}")
            st.markdown("**Original submission**")
            st.write(row.get("question") or "")

            edited_solution = st.text_area(
                "Approved knowledge",
                value=str(
                    row.get("solution")
                    or row.get("approved_answer")
                    or ""
                ),
                height=180,
                key=f"pending_solution_{row_id}",
            )

            approve_col, reject_col = st.columns(2, gap="small")
            with approve_col:
                if st.button(
                    "✅ Approve / Merge",
                    key=f"approve_pending_{row_id}",
                    
                    use_container_width=True,
                ):
                    try:
                        with st.spinner("Approving and synchronizing..."):
                            result = approve_pending_knowledge(
                                row,
                                edited_solution=edited_solution,
                            )
                        if result.get("mode") == "merged":
                            st.success("Approved and merged with existing knowledge.")
                        else:
                            st.success("Approved and synchronized successfully.")
                        st.rerun()
                    except Exception as error:
                        st.error(f"Approval failed: {error}")

            with reject_col:
                if st.button(
                    "Reject",
                    key=f"reject_pending_{row_id}",
                    type="secondary",
                    use_container_width=True,
                ):
                    try:
                        reject_pending_knowledge(row)
                        st.success("Submission rejected.")
                        st.rerun()
                    except Exception as error:
                        st.error(f"Rejection failed: {error}")



def render_knowledge_submission_workspace():
    """Render the structured staff-facing knowledge submission page."""
    install_knowledge_submission_css()

    if "knowledge_submission_type" not in st.session_state:
        st.session_state.knowledge_submission_type = "technical_solution"

    if "knowledge_submission_text_generation" not in st.session_state:
        st.session_state.knowledge_submission_text_generation = 0

    with st.container(key="knowledge_submission_page"):
        st.markdown("## 🧠 Knowledge Submission")
        st.caption(
            "Share a confirmed solution, installation procedure, product fact, "
            "sales rule, or FAQ so AutoTecPro AI can reuse it."
        )

        st.markdown("#### Knowledge Type")

        for row_start in (0, 3):
            row_items = KNOWLEDGE_SUBMISSION_TYPES[row_start:row_start + 3]
            columns = st.columns(3, gap="small")

            for column, (type_key, icon, label) in zip(columns, row_items):
                selected = (
                    st.session_state.knowledge_submission_type == type_key
                )
                state = "active" if selected else "idle"

                with column:
                    with st.container(
                        key=f"knowledge_type_{state}_{type_key}"
                    ):
                        if st.button(
                            f"{icon}  {label}",
                            key=f"knowledge_type_button_{type_key}",
                            use_container_width=True,
                        ):
                            if not selected:
                                st.session_state.knowledge_submission_type = (
                                    type_key
                                )
                                st.rerun()

        selected_type = st.session_state.knowledge_submission_type
        destination_label, _ = knowledge_submission_destination(selected_type)
        field_config = knowledge_submission_field_config(selected_type)

        with st.container(key="knowledge_submission_destination_caption"):
            st.caption(
                "Destination: "
                + (
                    "Sales Database"
                    if destination_label == "📈 Sales"
                    else "Technical Support Database"
                )
            )

        generation = st.session_state.knowledge_submission_text_generation

        with st.container(key="knowledge_structured_fields"):
            subject = st.text_input(
                field_config["subject_label"],
                key=f"knowledge_submission_subject_{generation}",
                placeholder=field_config["subject_placeholder"],
                help=(
                    "Enter the main vehicle, product, question, template, "
                    "procedure, or topic."
                ),
            )

            issue = st.text_area(
                field_config["issue_label"],
                key=f"knowledge_submission_issue_{generation}",
                height=138,
                placeholder=field_config["issue_placeholder"],
                help=(
                    "Keep this focused on the issue, customer situation, "
                    "question, or context."
                ),
            )

            solution = st.text_area(
                field_config["solution_label"],
                key=f"knowledge_submission_solution_{generation}",
                height=138,
                placeholder=field_config["solution_placeholder"],
                help=(
                    "Enter only confirmed information, an approved response, "
                    "or a tested procedure."
                ),
            )

        supporting_files = managed_file_uploader(
            storage_key="knowledge_submission_uploads",
            generation_key="knowledge_submission_upload_generation",
            widget_prefix="knowledge_submission_files",
            accepted_types=["jpg", "jpeg", "png", "pdf", "txt", "docx"],
            heading="📎 Supporting Files (Optional)",
        )

        clean_subject = str(subject or "").strip()
        clean_issue = str(issue or "").strip()
        clean_solution = str(solution or "").strip()

        # Keep the action visually active at all times. Streamlit does not
        # rerun a normal text widget on every keystroke, so a live grey/blue
        # state can remain stale until the user clicks elsewhere. Required-field
        # validation still runs immediately after Submit Knowledge is clicked.
        with st.container(key="knowledge_submit_button_ready"):
            submit_clicked = st.button(
                "🧠 Submit Knowledge",
                key="submit_staff_knowledge",
                
                use_container_width=True,
            )

        if submit_clicked:
            # Re-read the current widget values after the click-triggered rerun.
            clean_subject = str(
                st.session_state.get(
                    f"knowledge_submission_subject_{generation}",
                    subject,
                )
                or ""
            ).strip()
            clean_issue = str(
                st.session_state.get(
                    f"knowledge_submission_issue_{generation}",
                    issue,
                )
                or ""
            ).strip()
            clean_solution = str(
                st.session_state.get(
                    f"knowledge_submission_solution_{generation}",
                    solution,
                )
                or ""
            ).strip()

            validation_errors = []
            if not clean_subject:
                validation_errors.append(
                    f"{field_config['subject_label']} is required."
                )
            if len(clean_issue) < 5:
                validation_errors.append(
                    f"{field_config['issue_label']} must contain at least 5 characters."
                )
            if len(clean_solution) < 5:
                validation_errors.append(
                    f"{field_config['solution_label']} must contain at least 5 characters."
                )

            if validation_errors:
                st.warning(" ".join(validation_errors))
            else:
                with st.spinner("Reviewing and saving knowledge..."):
                    try:
                        result = save_knowledge_submission(
                            selected_type,
                            clean_subject,
                            clean_issue,
                            clean_solution,
                            supporting_files,
                        )

                        st.session_state.knowledge_submission_last_result = result
                        st.session_state.knowledge_submission_text_generation = (
                            int(
                                st.session_state.get(
                                    "knowledge_submission_text_generation",
                                    0,
                                )
                            )
                            + 1
                        )
                        clear_managed_uploads(
                            "knowledge_submission_uploads",
                            "knowledge_submission_upload_generation",
                        )
                        st.rerun()
                    except Exception as error:
                        st.error(f"Knowledge could not be submitted: {error}")

        last_result = st.session_state.get(
            "knowledge_submission_last_result"
        )
        if last_result:
            status_rows = [
                (
                    "Database",
                    html.escape(
                        str(last_result.get("destination") or "Unknown")
                    ),
                ),
                (
                    "Subject / Product / Vehicle",
                    html.escape(
                        str(last_result.get("vehicle") or "Not specified")
                    ),
                ),
                (
                    "Knowledge",
                    html.escape(
                        str(last_result.get("issue") or "Saved")
                    ),
                ),
            ]

            if last_result.get("attachment_count"):
                status_rows.append(
                    (
                        "Supporting files",
                        (
                            f"{int(last_result['attachment_count'])} "
                            "attached for review"
                        ),
                    )
                )

            status_html = "".join(
                (
                    '<div class="knowledge-status-row">'
                    f"<strong>{label}:</strong> {value}</div>"
                )
                for label, value in status_rows
            )

            st.markdown(
                (
                    '<div class="knowledge-status-card">'
                    '<div class="knowledge-status-title">'
                    "✅ Pending Admin Review"
                    "</div>"
                    f"{status_html}"
                    "</div>"
                ),
                unsafe_allow_html=True,
            )


