def apply_marketing_tools_form_css():
    """Keep Marketing tool form text readable on narrow mobile screens."""
    st.markdown(
        """
        <style>
        /*
         * Mobile-only Marketing form compatibility fix.
         *
         * This stylesheet is injected only while the Marketing workspace is
         * rendered. Desktop styling and every non-Marketing workspace remain
         * unchanged.
         */
        @media screen and (max-width: 1600px) {
            /*
             * Exact mobile/tablet fix for the closed Marketing Mode value.
             * On the deployed Safari build, BaseWeb renders the visible selected
             * value through the labelled input itself. Target that stable
             * accessibility attribute directly instead of depending on wrapper
             * classes or nesting.
             */
            input[aria-label="Marketing mode"],
            input[aria-label="Marketing mode"]:focus,
            input[aria-label="Marketing mode"]:active,
            input[aria-label="Marketing mode"][value] {
                color: #ffffff !important;
                -webkit-text-fill-color: #ffffff !important;
                caret-color: #ffffff !important;
                opacity: 1 !important;
            }

            /*
             * Exact accessibility-attribute protection for the new Competitor
             * Analysis controls on mobile Safari. This follows the same method
             * that fixed the Marketing Mode selected-value issue.
             */
            input[aria-label="Competitor company"],
            input[aria-label="Target market / region"],
            input[aria-label="Competitor product / model"],
            input[aria-label="Competitor public product URL (optional)"],
            input[aria-label="AutoTecPro product / model"],
            textarea[aria-label="Competitor specifications or page content (optional)"],
            textarea[aria-label="Additional instructions (optional)"] {
                color: #f8fafc !important;
                -webkit-text-fill-color: #f8fafc !important;
                caret-color: #f87171 !important;
                opacity: 1 !important;
            }

            input[aria-label="Competitor company"]::placeholder,
            input[aria-label="Competitor product / model"]::placeholder,
            input[aria-label="Competitor public product URL (optional)"]::placeholder,
            input[aria-label="AutoTecPro product / model"]::placeholder,
            textarea[aria-label="Competitor specifications or page content (optional)"]::placeholder,
            textarea[aria-label="Additional instructions (optional)"]::placeholder {
                color: #94a3b8 !important;
                -webkit-text-fill-color: #94a3b8 !important;
                opacity: 1 !important;
            }

            /*
             * Marketing mode selector outside the form, plus every selectbox
             * and multiselect inside the currently rendered Marketing form.
             * BaseWeb uses different nested nodes for the closed value on iOS
             * Safari, so cover the combobox, value container and descendants.
             */
            /*
             * Scope the closed Marketing Mode value through a dedicated keyed
             * container. This avoids relying on generated selectbox key classes,
             * which are not consistently exposed by mobile Safari/Streamlit.
             */
            div[class*="st-key-marketing_mode_control"]
            div[data-testid="stSelectbox"] [data-baseweb="select"],
            div[class*="st-key-marketing_mode_control"]
            div[data-testid="stSelectbox"] [data-baseweb="select"] > div,
            div[class*="st-key-marketing_mode_control"]
            div[data-testid="stSelectbox"]
            [data-baseweb="select"] [role="combobox"],
            div[class*="st-key-marketing_mode_control"]
            div[data-testid="stSelectbox"] [data-baseweb="select"] span,
            div[class*="st-key-marketing_mode_control"]
            div[data-testid="stSelectbox"] [data-baseweb="select"] p,
            div[class*="st-key-marketing_mode_control"]
            div[data-testid="stSelectbox"]
            [data-baseweb="select"] *:not(svg):not(path),
            div[data-testid="stForm"] [data-baseweb="select"],
            div[data-testid="stForm"] [data-baseweb="select"] > div,
            div[data-testid="stForm"]
            [data-baseweb="select"] [role="combobox"],
            div[data-testid="stForm"] [data-baseweb="select"] span {
                color: #f8fafc !important;
                -webkit-text-fill-color: #f8fafc !important;
                opacity: 1 !important;
            }

            /*
             * Closed select values may be drawn through an input or a nested
             * div rather than a span, depending on the Streamlit/BaseWeb build.
             */
            div[class*="st-key-marketing_mode_control"]
            div[data-testid="stSelectbox"] [data-baseweb="select"] input,
            div[class*="st-key-marketing_mode_control"]
            div[data-testid="stSelectbox"] [data-baseweb="select"] div,
            div[data-testid="stForm"] [data-baseweb="select"] input,
            div[data-testid="stForm"] [data-baseweb="select"] div {
                color: #f8fafc !important;
                -webkit-text-fill-color: #f8fafc !important;
                caret-color: #f87171 !important;
                opacity: 1 !important;
            }

            /* Typed values in Marketing text inputs and text areas. */
            div[data-testid="stForm"] [data-testid="stTextInput"] input,
            div[data-testid="stForm"]
            div[data-testid="stTextInputRootElement"] input,
            div[data-testid="stForm"] [data-testid="stTextArea"] textarea,
            div[data-testid="stForm"] input[type="text"],
            div[data-testid="stForm"] input[type="url"],
            div[data-testid="stForm"] textarea {
                color: #f8fafc !important;
                -webkit-text-fill-color: #f8fafc !important;
                caret-color: #f87171 !important;
                opacity: 1 !important;
            }

            /* Keep placeholder text readable but distinct from entered text. */
            div[data-testid="stForm"] [data-testid="stTextInput"] input::placeholder,
            div[data-testid="stForm"]
            div[data-testid="stTextInputRootElement"] input::placeholder,
            div[data-testid="stForm"]
            [data-testid="stTextArea"] textarea::placeholder,
            div[data-testid="stForm"] input[type="text"]::placeholder,
            div[data-testid="stForm"] input[type="url"]::placeholder,
            div[data-testid="stForm"] textarea::placeholder {
                color: #94a3b8 !important;
                -webkit-text-fill-color: #94a3b8 !important;
                opacity: 1 !important;
            }

            /*
             * Safari autofill and disabled/read-only states can otherwise
             * restore a black text fill after a rerun or field selection.
             */
            div[data-testid="stForm"] input:-webkit-autofill,
            div[data-testid="stForm"] input:-webkit-autofill:hover,
            div[data-testid="stForm"] input:-webkit-autofill:focus,
            div[data-testid="stForm"] input:disabled,
            div[data-testid="stForm"] textarea:disabled {
                color: #f8fafc !important;
                -webkit-text-fill-color: #f8fafc !important;
                caret-color: #f87171 !important;
                opacity: 1 !important;
                transition: background-color 9999s ease-out 0s !important;
            }

            /*
             * Shared Marketing form focus styling.
             *
             * Streamlit/BaseWeb draws the outer input/textarea wrapper border.
             * The global app stylesheet can also draw a border or glow on the
             * editable element itself, producing two nested red rectangles on
             * mobile Safari. Keep the BaseWeb wrapper as the only border owner.
             */
            div[data-testid="stForm"] [data-baseweb="input"],
            div[data-testid="stForm"] [data-baseweb="textarea"] {
                border: 1px solid #334155 !important;
                border-radius: 11px !important;
                outline: none !important;
                box-shadow: none !important;
                overflow: hidden !important;
            }

            div[data-testid="stForm"] [data-baseweb="input"]:focus-within,
            div[data-testid="stForm"] [data-baseweb="textarea"]:focus-within {
                border-color: var(--atp-red) !important;
                outline: none !important;
                box-shadow: none !important;
            }

            div[data-testid="stForm"] [data-baseweb="input"] input,
            div[data-testid="stForm"] [data-baseweb="input"] input:focus,
            div[data-testid="stForm"] [data-baseweb="input"] input:focus-visible,
            div[data-testid="stForm"] [data-baseweb="input"] input:active,
            div[data-testid="stForm"] [data-baseweb="textarea"] textarea,
            div[data-testid="stForm"] [data-baseweb="textarea"] textarea:focus,
            div[data-testid="stForm"] [data-baseweb="textarea"] textarea:focus-visible,
            div[data-testid="stForm"] [data-baseweb="textarea"] textarea:active {
                border: none !important;
                outline: none !important;
                box-shadow: none !important;
                background-color: transparent !important;
            }
        }

        </style>
        """,
        unsafe_allow_html=True,
    )


MARKETING_TOOL_OPTIONS = {
    "💬 Marketing Chat": "chat",
    "🛡️ Brand Consistency": "brand",
    "📝 Product Listing Generator": "listing",
    "🔎 SEO Optimizer": "seo",
    "📊 Competitor Analysis": "competitor",
}


def _clean_marketing_form_value(value, max_length=12000):
    """Normalize user-entered Marketing tool fields without changing meaning."""
    cleaned = str(value or "").replace("\x00", "").strip()
    return cleaned[:max(1, int(max_length or 12000))]


def _marketing_tool_request(tool_key, display_text, prompt_text):
    """Return a stable request payload consumed by the existing chat pipeline."""
    return {
        "tool": str(tool_key or "").strip(),
        "display_text": _clean_marketing_form_value(display_text, 4000),
        "prompt": _clean_marketing_form_value(prompt_text, 24000),
    }


def build_brand_consistency_request(content, content_type, target_audience, notes):
    """Build a grounded brand-review request for the existing Marketing AI."""
    content = _clean_marketing_form_value(content, 16000)
    content_type = _clean_marketing_form_value(content_type, 120)
    target_audience = _clean_marketing_form_value(target_audience, 300)
    notes = _clean_marketing_form_value(notes, 2000)

    display_text = (
        f"Brand Consistency Review — {content_type}\n\n"
        f"{content[:1200]}"
    )
    prompt_text = f"""
MARKETING TOOL: AUTOTECPRO BRAND CONSISTENCY ENGINE

Review the supplied content against the AutoTecPro Marketing Vector Store and
Sales Vector Store. Use retrieved brand guidance, approved product facts,
warranty language, dealer rules, promotions, and customer-facing policies as
the source of truth.

Content type: {content_type}
Target audience: {target_audience or "Not specified"}
Additional instructions: {notes or "None"}

CONTENT TO REVIEW:
{content}

Return these sections:
1. Brand Compliance Score (0-100)
2. What Already Matches the AutoTecPro Brand
3. Brand, Accuracy, or Policy Issues
4. Unsupported or Risky Claims
5. Recommended Corrections
6. Revised Final Version

Rules:
- Do not invent specifications, compatibility, prices, promotions, warranty
  terms, support promises, or policies.
- Clearly mark any point that cannot be verified from AutoTecPro knowledge.
- Preserve the original language unless a different language is requested.
- The revised version must be ready to use and should not include analysis
  notes inside the final copy.
"""
    return _marketing_tool_request("brand_consistency", display_text, prompt_text)


def build_product_listing_request(
    product_name,
    compatibility,
    specifications,
    platforms,
    tone,
    audience,
    keywords,
    notes,
):
    """Build one multi-platform listing request using existing product knowledge."""
    product_name = _clean_marketing_form_value(product_name, 300)
    compatibility = _clean_marketing_form_value(compatibility, 2000)
    specifications = _clean_marketing_form_value(specifications, 8000)
    platforms = [
        _clean_marketing_form_value(item, 80)
        for item in (platforms or [])
        if str(item or "").strip()
    ]
    tone = _clean_marketing_form_value(tone, 120)
    audience = _clean_marketing_form_value(audience, 500)
    keywords = _clean_marketing_form_value(keywords, 1500)
    notes = _clean_marketing_form_value(notes, 2500)

    platform_text = ", ".join(platforms) or "WooCommerce"
    display_text = (
        f"Generate Product Listing — {product_name}\n"
        f"Platforms: {platform_text}"
    )
    prompt_text = f"""
MARKETING TOOL: AUTOTECPRO PRODUCT LISTING GENERATOR

Create accurate, platform-specific product listings using the AutoTecPro
Marketing Vector Store and Sales Vector Store. Search the knowledge stores
before writing. Treat the supplied fields as context, but verify factual
product claims against AutoTecPro knowledge.

Product name / model: {product_name}
Vehicle compatibility: {compatibility or "Use verified AutoTecPro knowledge"}
Specifications and features:
{specifications or "Use verified AutoTecPro knowledge"}

Target platforms: {platform_text}
Tone: {tone or "Professional and conversion-focused"}
Target audience: {audience or "Vehicle owners and qualified dealers"}
Priority keywords: {keywords or "Derive from verified product information"}
Additional instructions: {notes or "None"}

For EACH selected platform, produce:
1. Optimized Title
2. Short Description
3. Key Feature Bullets
4. Full Product Description
5. Compatibility / Fitment Section
6. What's Included
7. Installation and Support Wording
8. Warranty / Policy Wording only when verified
9. Search Keywords / Tags
10. Platform-specific compliance notes

Then provide:
- A Product Fact Verification section listing facts confirmed from AutoTecPro
  knowledge and any details still requiring staff confirmation.
- A concise reusable master listing.

Rules:
- Never invent compatibility, technical specifications, retained factory
  features, prices, promotions, warranty terms, or included accessories.
- Do not claim universal fitment.
- Keep platform versions meaningfully different instead of duplicating one
  generic listing.
- Do not output HTML unless the staff explicitly requests it.
"""
    return _marketing_tool_request("product_listing", display_text, prompt_text)


def build_seo_optimizer_request(
    page_type,
    product_or_topic,
    primary_keyword,
    secondary_keywords,
    market,
    existing_content,
    page_url,
    notes,
):
    """Build an SEO audit and rewrite request without requiring another service."""
    page_type = _clean_marketing_form_value(page_type, 120)
    product_or_topic = _clean_marketing_form_value(product_or_topic, 500)
    primary_keyword = _clean_marketing_form_value(primary_keyword, 300)
    secondary_keywords = _clean_marketing_form_value(secondary_keywords, 1200)
    market = _clean_marketing_form_value(market, 200)
    existing_content = _clean_marketing_form_value(existing_content, 16000)
    page_url = _clean_marketing_form_value(page_url, 1000)
    notes = _clean_marketing_form_value(notes, 2500)

    display_text = (
        f"SEO Optimization — {product_or_topic or page_type}\n"
        f"Primary keyword: {primary_keyword or 'AI to recommend'}"
    )
    prompt_text = f"""
MARKETING TOOL: AUTOTECPRO SEO OPTIMIZER

Optimize this page using the AutoTecPro Marketing Vector Store and Sales Vector
Store for factual and brand accuracy. Use web search only when a supplied public
URL or current public search information is materially useful.

Page type: {page_type}
Product / topic: {product_or_topic}
Primary keyword: {primary_keyword or "Recommend the best primary keyword"}
Secondary keywords: {secondary_keywords or "Recommend relevant secondary keywords"}
Target market / region: {market or "Canada and United States"}
Existing page URL: {page_url or "Not supplied"}
Additional instructions: {notes or "None"}

EXISTING CONTENT:
{existing_content or "No existing copy supplied. Create a new SEO-ready draft."}

Return:
1. SEO Audit Summary
2. Search Intent
3. Recommended Primary and Secondary Keywords
4. SEO Title (include character count)
5. Meta Description (include character count)
6. Recommended URL Slug
7. H1
8. H2 / H3 Structure
9. Optimized Page Copy
10. FAQ Section
11. Image Alt-Text Suggestions
12. Internal-Link Suggestions
13. Structured-Data / Schema Recommendations
14. Accuracy and Brand Verification Notes
15. Final SEO Checklist

Rules:
- Do not claim live keyword volume, ranking position, or competitor traffic
  unless verified live data is actually available.
- Never invent product facts, compatibility, pricing, warranty, promotions, or
  policies.
- Separate verified recommendations from assumptions requiring staff review.
- Write for humans first and avoid keyword stuffing.
"""
    return _marketing_tool_request("seo_optimizer", display_text, prompt_text)



def build_competitor_analysis_request(
    competitor_name,
    competitor_url,
    competitor_product,
    autotecpro_product,
    target_market,
    comparison_focus,
    competitor_details,
    notes,
):
    """Build a grounded, one-competitor comparison request."""
    competitor_name = _clean_marketing_form_value(competitor_name, 300)
    competitor_url = _clean_marketing_form_value(competitor_url, 1500)
    competitor_product = _clean_marketing_form_value(competitor_product, 500)
    autotecpro_product = _clean_marketing_form_value(autotecpro_product, 500)
    target_market = _clean_marketing_form_value(target_market, 300)
    comparison_focus = [
        _clean_marketing_form_value(item, 120)
        for item in (comparison_focus or [])
        if str(item or "").strip()
    ]
    competitor_details = _clean_marketing_form_value(competitor_details, 12000)
    notes = _clean_marketing_form_value(notes, 3000)

    focus_text = ", ".join(comparison_focus) or (
        "Product features, compatibility, pricing and value, warranty, support, "
        "installation, product-page quality, SEO, messaging, and dealer advantages"
    )

    display_text = (
        f"Competitor Analysis — {competitor_name or competitor_product or 'Competitor'}\n"
        f"Compared with: {autotecpro_product}"
    )

    prompt_text = f"""
MARKETING TOOL: AUTOTECPRO COMPETITOR ANALYSIS

Analyze one competitor product against one AutoTecPro product.

Use the AutoTecPro Marketing Vector Store and Sales Vector Store as the source
of truth for AutoTecPro product facts, compatibility, support language,
warranty/policy wording, dealer information, and brand positioning.

Use web search for current public competitor information when a competitor URL
or public competitor details are supplied. Treat competitor information as
unverified until supported by the public source. Do not infer missing prices,
specifications, compatibility, warranty terms, availability, or policies.

Competitor company: {competitor_name or "Not specified"}
Competitor product: {competitor_product or "Not specified"}
Competitor public URL: {competitor_url or "Not supplied"}
AutoTecPro product / model: {autotecpro_product}
Target market / region: {target_market or "Canada and United States"}
Comparison priorities: {focus_text}
Additional instructions: {notes or "None"}

SUPPLIED COMPETITOR DETAILS:
{competitor_details or "No additional competitor text supplied."}

Return these sections:

1. Executive Summary
2. Information Sources and Verification Status
3. Side-by-Side Product Comparison
4. Feature and Vehicle-Compatibility Comparison
5. Pricing and Value Analysis
6. Warranty, Installation, and Support Comparison
7. Competitor Strengths
8. Competitor Weaknesses
9. AutoTecPro Advantages
10. AutoTecPro Gaps or Areas to Improve
11. Product-Page and Marketing Message Comparison
12. SEO Opportunities
13. Dealer / Distributor Positioning Opportunities
14. Recommended Sales Positioning
15. Suggested Sales Pitch
16. Suggested AutoTecPro Product Title
17. Suggested AutoTecPro Website Copy
18. Campaign Message Ideas
19. Facts Requiring Manual Verification
20. Confidence Summary

Rules:
- Clearly label verified facts, source-supported competitor claims, assumptions,
  and unavailable information.
- Never invent competitor or AutoTecPro specifications, compatibility, prices,
  promotions, warranty terms, support promises, availability, or policies.
- If the URL cannot be accessed, say so and continue only with supplied text
  and verified AutoTecPro knowledge.
- Do not present opinions as measured market facts.
- Do not claim keyword rankings, traffic, sales volume, or market share unless
  verified live data is available.
- Keep the final recommendations practical and specific to AutoTecPro.
"""
    return _marketing_tool_request(
        "competitor_analysis",
        display_text,
        prompt_text,
    )


