def _product_library_subtype_options(asset_type):
    """Return stable subtype options for the selected top-level asset type."""
    return PRODUCT_ASSET_SUBTYPES.get(str(asset_type or "other"), ["other"])


def _product_library_asset_heading(asset):
    """Build a readable Asset Type / Subtype / filename heading."""
    asset = asset or {}
    type_label = PRODUCT_ASSET_LABELS.get(
        asset.get("asset_type"), str(asset.get("asset_type") or "Other")
    )
    subtype = str(asset.get("asset_subtype") or "").strip()
    subtype_label = PRODUCT_ASSET_SUBTYPE_LABELS.get(subtype, subtype.replace("_", " ").title())
    filename = str(asset.get("original_filename") or "Unnamed file")
    return f"{type_label} / {subtype_label} — {filename}" if subtype_label else f"{type_label} — {filename}"


def _product_library_clean_code(value):
    clean = re.sub(r"[^A-Za-z0-9._-]+", "-", str(value or "").strip())
    return clean.strip("-._")[:80]


def _product_library_safe_filename(value):
    original = Path(str(value or "file")).name
    stem = re.sub(r"[^A-Za-z0-9._-]+", "-", Path(original).stem).strip("-._")
    suffix = re.sub(r"[^A-Za-z0-9.]", "", Path(original).suffix.lower())
    return f"{stem or 'file'}{suffix}"[:180]


def _product_library_google_configured():
    return bool(
        GOOGLE_DRIVE_CLIENT_ID
        and GOOGLE_DRIVE_CLIENT_SECRET
        and GOOGLE_DRIVE_REFRESH_TOKEN
        and GOOGLE_DRIVE_ROOT_FOLDER_ID
    )


@st.cache_data(ttl=300, show_spinner=False)
def _product_library_google_access_token():
    if not _product_library_google_configured():
        raise RuntimeError(
            "Google Drive is not configured. Add the Google Drive OAuth secrets "
            "and root folder ID in Streamlit Secrets."
        )
    response = http_session.post(
        "https://oauth2.googleapis.com/token",
        data={
            "client_id": GOOGLE_DRIVE_CLIENT_ID,
            "client_secret": GOOGLE_DRIVE_CLIENT_SECRET,
            "refresh_token": GOOGLE_DRIVE_REFRESH_TOKEN,
            "grant_type": "refresh_token",
        },
        timeout=LIVE_HTTP_TIMEOUT,
    )
    payload = safe_json_response(response)
    token = str(payload.get("access_token") or "").strip()
    if not token:
        raise RuntimeError("Google OAuth did not return an access token.")
    return token


def _product_library_drive_headers():
    return {"Authorization": f"Bearer {_product_library_google_access_token()}"}


def _product_library_drive_find_folder(name, parent_id):
    safe_name = str(name or "").replace("'", "\\'")
    query = (
        "mimeType='application/vnd.google-apps.folder' and trashed=false "
        f"and name='{safe_name}' and '{parent_id}' in parents"
    )
    response = http_session.get(
        "https://www.googleapis.com/drive/v3/files",
        headers=_product_library_drive_headers(),
        params={"q": query, "fields": "files(id,name,webViewLink)", "pageSize": 10},
        timeout=LIVE_HTTP_TIMEOUT,
    )
    payload = safe_json_response(response)
    files = payload.get("files") or []
    return files[0] if files else None


def _product_library_drive_create_folder(name, parent_id):
    existing = _product_library_drive_find_folder(name, parent_id)
    if existing:
        return existing
    response = http_session.post(
        "https://www.googleapis.com/drive/v3/files",
        headers={**_product_library_drive_headers(), "Content-Type": "application/json"},
        json={
            "name": str(name),
            "mimeType": "application/vnd.google-apps.folder",
            "parents": [str(parent_id)],
        },
        params={"fields": "id,name,webViewLink"},
        timeout=LIVE_HTTP_TIMEOUT,
    )
    return safe_json_response(response)


def _product_library_drive_upload_bytes(filename, content_type, data, parent_id):
    boundary = f"atp_{int(time.time() * 1000)}_{hashlib.md5(filename.encode()).hexdigest()[:8]}"
    metadata = json.dumps({"name": filename, "parents": [parent_id]}).encode("utf-8")
    body = b"".join([
        f"--{boundary}\r\nContent-Type: application/json; charset=UTF-8\r\n\r\n".encode(),
        metadata,
        b"\r\n",
        f"--{boundary}\r\nContent-Type: {content_type or 'application/octet-stream'}\r\n\r\n".encode(),
        data,
        b"\r\n",
        f"--{boundary}--\r\n".encode(),
    ])
    response = http_session.post(
        "https://www.googleapis.com/upload/drive/v3/files",
        headers={
            **_product_library_drive_headers(),
            "Content-Type": f"multipart/related; boundary={boundary}",
        },
        params={"uploadType": "multipart", "fields": "id,name,webViewLink,size,mimeType"},
        data=body,
        timeout=60,
    )
    return safe_json_response(response)


def _product_library_test_drive_connection():
    if not _product_library_google_configured():
        return False, "Google Drive secrets are incomplete."
    response = http_session.get(
        f"https://www.googleapis.com/drive/v3/files/{quote(GOOGLE_DRIVE_ROOT_FOLDER_ID, safe='')}",
        headers=_product_library_drive_headers(),
        params={"fields": "id,name,mimeType,webViewLink"},
        timeout=LIVE_HTTP_TIMEOUT,
    )
    payload = safe_json_response(response)
    if payload.get("mimeType") != "application/vnd.google-apps.folder":
        return False, "The configured root ID is not a Google Drive folder."
    return True, f"Connected to Google Drive folder: {payload.get('name') or payload.get('id')}"


@st.cache_data(ttl=300, show_spinner=False)
def _product_library_google_status():
    """Return safe Google Drive account and root-folder details for Admin UI."""
    status = {
        "configured": _product_library_google_configured(),
        "connected": False,
        "account_email": "",
        "account_name": "",
        "root_folder_name": "",
        "root_folder_id": GOOGLE_DRIVE_ROOT_FOLDER_ID,
        "root_web_url": "",
        "error": "",
    }
    if not status["configured"]:
        status["error"] = "Google Drive secrets are incomplete."
        return status

    try:
        headers = _product_library_drive_headers()
        about_response = http_session.get(
            "https://www.googleapis.com/drive/v3/about",
            headers=headers,
            params={"fields": "user(displayName,emailAddress)"},
            timeout=LIVE_HTTP_TIMEOUT,
        )
        about_payload = safe_json_response(about_response)
        user = about_payload.get("user") or {}
        status["account_email"] = str(user.get("emailAddress") or "").strip()
        status["account_name"] = str(user.get("displayName") or "").strip()

        folder_response = http_session.get(
            f"https://www.googleapis.com/drive/v3/files/{quote(GOOGLE_DRIVE_ROOT_FOLDER_ID, safe='')}",
            headers=headers,
            params={"fields": "id,name,mimeType,webViewLink,trashed"},
            timeout=LIVE_HTTP_TIMEOUT,
        )
        folder = safe_json_response(folder_response)
        if folder.get("mimeType") != "application/vnd.google-apps.folder":
            raise RuntimeError("The configured root ID is not a Google Drive folder.")
        if folder.get("trashed"):
            raise RuntimeError("The configured Google Drive root folder is in Trash.")

        status["root_folder_name"] = str(folder.get("name") or "").strip()
        status["root_folder_id"] = str(folder.get("id") or GOOGLE_DRIVE_ROOT_FOLDER_ID)
        status["root_web_url"] = str(folder.get("webViewLink") or "").strip()
        status["connected"] = True
    except Exception as error:
        status["error"] = str(error)
    return status


def _product_library_onedrive_configured():
    return bool(
        ONEDRIVE_TENANT_ID
        and ONEDRIVE_CLIENT_ID
        and ONEDRIVE_CLIENT_SECRET
        and ONEDRIVE_DRIVE_ID
    )


@st.cache_data(ttl=300, show_spinner=False)
def _product_library_onedrive_access_token():
    """Get a Microsoft Graph app-only token when OneDrive is configured."""
    if not _product_library_onedrive_configured():
        raise RuntimeError("OneDrive secrets are incomplete.")
    response = http_session.post(
        f"https://login.microsoftonline.com/{quote(ONEDRIVE_TENANT_ID, safe='')}/oauth2/v2.0/token",
        data={
            "client_id": ONEDRIVE_CLIENT_ID,
            "client_secret": ONEDRIVE_CLIENT_SECRET,
            "scope": "https://graph.microsoft.com/.default",
            "grant_type": "client_credentials",
        },
        timeout=LIVE_HTTP_TIMEOUT,
    )
    payload = safe_json_response(response)
    token = str(payload.get("access_token") or "").strip()
    if not token:
        raise RuntimeError("Microsoft OAuth did not return an access token.")
    return token


@st.cache_data(ttl=300, show_spinner=False)
def _product_library_onedrive_status():
    """Validate optional OneDrive configuration without changing upload routing."""
    status = {
        "configured": _product_library_onedrive_configured(),
        "connected": False,
        "drive_name": "",
        "owner_name": "",
        "root_folder_name": "",
        "root_folder_id": ONEDRIVE_ROOT_FOLDER_ID or "root",
        "error": "",
    }
    if not status["configured"]:
        status["error"] = "OneDrive secrets are incomplete."
        return status
    try:
        headers = {"Authorization": f"Bearer {_product_library_onedrive_access_token()}"}
        drive_response = http_session.get(
            f"https://graph.microsoft.com/v1.0/drives/{quote(ONEDRIVE_DRIVE_ID, safe='')}",
            headers=headers,
            timeout=LIVE_HTTP_TIMEOUT,
        )
        drive = safe_json_response(drive_response)
        status["drive_name"] = str(drive.get("name") or "").strip()
        status["owner_name"] = str(((drive.get("owner") or {}).get("user") or {}).get("displayName") or "").strip()

        root_id = ONEDRIVE_ROOT_FOLDER_ID or "root"
        item_url = (
            f"https://graph.microsoft.com/v1.0/drives/{quote(ONEDRIVE_DRIVE_ID, safe='')}/root"
            if root_id == "root"
            else f"https://graph.microsoft.com/v1.0/drives/{quote(ONEDRIVE_DRIVE_ID, safe='')}/items/{quote(root_id, safe='')}"
        )
        item_response = http_session.get(item_url, headers=headers, timeout=LIVE_HTTP_TIMEOUT)
        item = safe_json_response(item_response)
        if not item.get("folder"):
            raise RuntimeError("The configured OneDrive root item is not a folder.")
        status["root_folder_name"] = str(item.get("name") or "").strip()
        status["root_folder_id"] = str(item.get("id") or root_id)
        status["connected"] = True
    except Exception as error:
        status["error"] = str(error)
    return status


def _product_library_optimize_image(data, filename, max_px, quality=88):
    if Image is None:
        raise RuntimeError("Pillow is unavailable; image optimization cannot run.")
    with Image.open(io.BytesIO(data)) as image:
        image = ImageOps.exif_transpose(image)
        resampling = getattr(getattr(Image, "Resampling", Image), "LANCZOS", 1)
        image.thumbnail((max_px, max_px), resampling)
        has_alpha = image.mode in {"RGBA", "LA"} or (
            image.mode == "P" and "transparency" in image.info
        )
        output = io.BytesIO()
        if has_alpha:
            if image.mode != "RGBA":
                image = image.convert("RGBA")
            image.save(output, format="PNG", optimize=True)
            extension = ".png"
            content_type = "image/png"
        else:
            if image.mode != "RGB":
                image = image.convert("RGB")
            image.save(output, format="JPEG", quality=quality, optimize=True, progressive=True)
            extension = ".jpg"
            content_type = "image/jpeg"
    stem = re.sub(r"[^A-Za-z0-9._-]+", "-", Path(filename).stem).strip("-._") or "image"
    return output.getvalue(), f"{stem}{extension}", content_type


def _product_library_storage_bucket():
    """Return the private Product Library bucket through the server admin client."""
    return get_supabase_admin_client().storage.from_(PRODUCT_LIBRARY_BUCKET)


def _product_library_storage_upload(path, data, content_type):
    """Upload an optimized display copy without opening anonymous Storage access."""
    bucket = _product_library_storage_bucket()
    options = {"content-type": content_type, "upsert": "true"}
    try:
        return bucket.upload(path, data, file_options=options)
    except TypeError:
        # Compatibility with older supabase-py releases used by existing builds.
        return bucket.upload(path, data, options)


def _product_library_signed_url(path, expires=3600):
    """Create a temporary URL for a private Product Library image."""
    clean_path = str(path or "").strip().lstrip("/")
    if not clean_path:
        return ""

    try:
        payload = _product_library_storage_bucket().create_signed_url(
            clean_path,
            int(expires or 3600),
        )

        candidates = []
        if isinstance(payload, dict):
            candidates.extend([
                payload.get("signedURL"),
                payload.get("signedUrl"),
                payload.get("signed_url"),
            ])
            nested = payload.get("data")
            if isinstance(nested, dict):
                candidates.extend([
                    nested.get("signedURL"),
                    nested.get("signedUrl"),
                    nested.get("signed_url"),
                ])

        payload_data = getattr(payload, "data", None)
        if isinstance(payload_data, dict):
            candidates.extend([
                payload_data.get("signedURL"),
                payload_data.get("signedUrl"),
                payload_data.get("signed_url"),
            ])

        for candidate in candidates:
            candidate = str(candidate or "").strip()
            if not candidate:
                continue
            if candidate.startswith("http://") or candidate.startswith("https://"):
                return candidate

            supabase_url = str(st.secrets.get("SUPABASE_URL") or "").rstrip("/")
            if supabase_url:
                if not candidate.startswith("/"):
                    candidate = "/" + candidate
                return supabase_url + candidate

    except Exception as error:
        diagnostic_log(
            "product_library_signed_url_failed",
            path=clean_path,
            error=error,
        )

    return ""


def _product_library_storage_remove(paths):
    """Remove private display copies through the server-side admin client."""
    clean_paths = [str(path).strip() for path in (paths or []) if str(path).strip()]
    if not clean_paths:
        return None
    bucket = _product_library_storage_bucket()
    try:
        return bucket.remove(clean_paths)
    except TypeError:
        return bucket.remove(path=clean_paths)


def _product_library_drive_trash_file(file_id):
    """Move one archived Google Drive file to Trash without exposing OAuth data."""
    clean_id = str(file_id or "").strip()
    if not clean_id or not _product_library_google_configured():
        return False
    response = http_session.patch(
        f"https://www.googleapis.com/drive/v3/files/{quote(clean_id, safe='')}",
        headers={**_product_library_drive_headers(), "Content-Type": "application/json"},
        params={"fields": "id,trashed"},
        json={"trashed": True},
        timeout=LIVE_HTTP_TIMEOUT,
    )
    payload = safe_json_response(response)
    return bool(payload.get("trashed"))


def _product_library_delete_asset(asset):
    """Delete one asset from Storage, Drive archive, and product_assets metadata."""
    if not isinstance(asset, dict) or not asset.get("id"):
        raise RuntimeError("The selected Product Library asset is invalid.")

    storage_path = str(asset.get("storage_path") or "").strip()
    if storage_path:
        _product_library_storage_remove([storage_path])

    archive_file_id = str(asset.get("archive_file_id") or "").strip()
    if archive_file_id:
        _product_library_drive_trash_file(archive_file_id)

    supabase.table("product_assets").delete().eq("id", asset["id"]).execute()
    _product_library_clear_read_caches()


def _product_library_replace_asset(product, asset, replacement_file):
    """
    Replace one Product Library asset while preserving the product and asset type.

    The replacement is uploaded first. The old asset is removed only after the
    new asset has been saved successfully, preventing data loss when an upload
    fails.
    """
    if not isinstance(product, dict) or not product.get("id"):
        raise RuntimeError("The selected Product Library product is invalid.")
    if not isinstance(asset, dict) or not asset.get("id"):
        raise RuntimeError("The selected Product Library asset is invalid.")
    if replacement_file is None:
        raise RuntimeError("Please select a replacement file.")

    new_asset = None
    try:
        new_asset = _product_library_upload_asset(
            product,
            str(asset.get("asset_type") or "other"),
            replacement_file,
            str(asset.get("asset_subtype") or "other"),
        )
        _product_library_delete_asset(asset)
        _product_library_clear_read_caches()
        return new_asset
    except Exception:
        # If the replacement uploaded but the old record could not be removed,
        # clean up the new record to avoid leaving an unexpected duplicate.
        if isinstance(new_asset, dict) and new_asset.get("id"):
            try:
                _product_library_delete_asset(new_asset)
            except Exception as rollback_error:
                diagnostic_log(
                    "product_library_replace_rollback_failed",
                    asset_id=new_asset.get("id"),
                    error=rollback_error,
                )
        raise


def _product_library_delete_product(product):
    """
    Delete a product immediately and clean up all linked files.

    Database records are removed even when an external file provider cannot
    delete one of its files. Any external cleanup failure is logged and returned
    as a warning so a temporary Google Drive or Storage issue cannot leave the
    product stuck in the Admin panel.
    """
    if not isinstance(product, dict) or not product.get("id"):
        raise RuntimeError("The selected Product Library product is invalid.")

    product_id = product["id"]
    assets = (
        supabase.table("product_assets")
        .select("id,storage_path,archive_file_id")
        .eq("product_id", product_id)
        .execute().data
        or []
    )

    cleanup_warnings = []
    deleted_asset_count = 0

    for asset in assets:
        asset_id = asset.get("id")
        storage_path = str(asset.get("storage_path") or "").strip()
        archive_file_id = str(asset.get("archive_file_id") or "").strip()

        if storage_path:
            try:
                _product_library_storage_remove([storage_path])
            except Exception as error:
                cleanup_warnings.append(f"Supabase Storage: {error}")
                diagnostic_log(
                    "product_library_delete_storage_cleanup_failed",
                    product_id=product_id,
                    asset_id=asset_id,
                    error=error,
                )

        if archive_file_id:
            try:
                _product_library_drive_trash_file(archive_file_id)
            except Exception as error:
                cleanup_warnings.append(f"Google Drive: {error}")
                diagnostic_log(
                    "product_library_delete_drive_cleanup_failed",
                    product_id=product_id,
                    asset_id=asset_id,
                    error=error,
                )

        if asset_id:
            supabase.table("product_assets").delete().eq("id", asset_id).execute()
            deleted_asset_count += 1

    supabase.table("product_library").delete().eq("id", product_id).execute()
    _product_library_clear_read_caches()

    return {
        "deleted_asset_count": deleted_asset_count,
        "cleanup_warnings": cleanup_warnings,
    }


def _product_library_update_product(product_id, product_name, compatibility, description, aliases, active):
    """Update editable product metadata while keeping the stable product code."""
    payload = {
        "product_name": str(product_name or "").strip(),
        "vehicle_compatibility": str(compatibility or "").strip(),
        "description": str(description or "").strip(),
        "aliases": [str(item).strip() for item in (aliases or []) if str(item).strip()],
        "active": bool(active),
        "updated_by": str(st.session_state.get("username") or ""),
        "updated_at": datetime.now(timezone.utc).isoformat(),
    }
    if not payload["product_name"]:
        raise RuntimeError("Product name is required.")
    result = (
        supabase.table("product_library")
        .update(payload)
        .eq("id", product_id)
        .execute()
    )
    _product_library_clear_read_caches()
    return (result.data or [payload])[0]


def _product_library_asset_data_url(asset):
    """Download one private optimized image and return a history-safe data URL."""
    asset = asset or {}
    path = str(asset.get("storage_path") or "").strip().lstrip("/")
    if not path:
        return ""

    def _extract_bytes(payload):
        """Normalize common supabase-py and HTTP response shapes into bytes."""
        if payload is None:
            return b""
        if isinstance(payload, bytes):
            return payload
        if isinstance(payload, bytearray):
            return bytes(payload)
        if isinstance(payload, memoryview):
            return payload.tobytes()

        if isinstance(payload, dict):
            for key in ("data", "content", "body"):
                candidate = payload.get(key)
                result = _extract_bytes(candidate)
                if result:
                    return result

        for attribute in ("data", "content", "body"):
            candidate = getattr(payload, attribute, None)
            result = _extract_bytes(candidate)
            if result:
                return result

        reader = getattr(payload, "read", None)
        if callable(reader):
            try:
                result = reader()
                return _extract_bytes(result)
            except Exception:
                return b""

        return b""

    raw = b""

    # Primary path: use the same privileged Supabase client that successfully
    # uploads Product Library display copies.
    try:
        payload = _product_library_storage_bucket().download(path)
        raw = _extract_bytes(payload)
    except Exception as error:
        diagnostic_log(
            "product_library_chat_image_download_failed",
            path=path,
            error=error,
        )

    # First fallback: create a short-lived signed URL through supabase-py.
    if not raw:
        try:
            signed_url = _product_library_signed_url(path, expires=300)
            if signed_url:
                response = http_session.get(
                    signed_url,
                    timeout=LIVE_HTTP_TIMEOUT,
                )
                response.raise_for_status()
                raw = bytes(response.content or b"")
        except Exception as error:
            diagnostic_log(
                "product_library_chat_signed_image_download_failed",
                path=path,
                error=error,
            )

    # Final compatibility fallback: call the authenticated Storage REST endpoint
    # directly. This avoids response-shape differences between supabase-py
    # versions while keeping the private bucket protected.
    if not raw:
        try:
            supabase_url = str(st.secrets.get("SUPABASE_URL") or "").rstrip("/")
            admin_key = str(
                st.secrets.get("SUPABASE_SECRET_KEY")
                or st.secrets.get("SUPABASE_SERVICE_ROLE_KEY")
                or ""
            ).strip()
            bucket_name = str(
                asset.get("storage_bucket")
                or PRODUCT_LIBRARY_BUCKET
            ).strip()

            if supabase_url and admin_key and bucket_name:
                object_url = (
                    f"{supabase_url}/storage/v1/object/authenticated/"
                    f"{quote(bucket_name, safe='')}/{quote(path, safe='/')}"
                )
                response = http_session.get(
                    object_url,
                    headers={
                        "apikey": admin_key,
                        "Authorization": f"Bearer {admin_key}",
                        "Accept": "application/octet-stream",
                    },
                    timeout=LIVE_HTTP_TIMEOUT,
                )
                response.raise_for_status()
                raw = bytes(response.content or b"")
        except Exception as error:
            diagnostic_log(
                "product_library_chat_rest_image_download_failed",
                path=path,
                error=error,
            )

    if not raw:
        diagnostic_log(
            "product_library_chat_image_empty",
            path=path,
            asset_id=asset.get("id"),
        )
        return ""

    optimized_name = str(
        asset.get("optimized_filename")
        or Path(path).name
        or ""
    ).lower()
    if optimized_name.endswith(".png"):
        mime_type = "image/png"
    elif optimized_name.endswith((".jpg", ".jpeg")):
        mime_type = "image/jpeg"
    elif optimized_name.endswith(".webp"):
        mime_type = "image/webp"
    else:
        mime_type = str(asset.get("content_type") or "image/jpeg")
        if not mime_type.startswith("image/"):
            mime_type = "image/jpeg"

    return f"data:{mime_type};base64,{base64.b64encode(raw).decode('ascii')}"


def _product_library_prompt_requests_facts(prompt):
    """Detect product, compatibility, fitment, specification, or feature questions."""
    value = re.sub(r"\s+", " ", str(prompt or "")).strip().casefold()
    if not value:
        return False

    # Explicit learning is handled by a separate high-priority workflow and must
    # never trigger Product Library retrieval.
    if detect_explicit_learning_command(
        value,
        has_recent_context=bool(st.session_state.get("messages")),
        has_attachments=False,
    ):
        return False

    fact_terms = (
        "compatible", "compatibility", "fit", "fits", "fitment", "support",
        "supports", "work with", "works with", "which year", "what year",
        "year range", "vehicle year", "model year", "product code", "model code",
        "sku", "specification", "specifications", "spec", "specs", "feature",
        "features", "function", "functionality", "retains", "retained",
        "factory feature", "sync", "uconnect", "climate control", "camera",
        "screen size", "hardware", "ram", "storage", "android version",
        "difference", "differences", "compare", "comparison", "included",
        "what is", "tell me about",
    )
    has_fact_intent = any(term in value for term in fact_terms)

    # Exact AutoTecPro-style model codes should also trigger a product-fact lookup,
    # even when the user asks a short question such as "732-S3?".
    has_model_code = bool(re.search(
        r"(?<![a-z0-9])(?:[a-z]{1,6}[-/]?)?\d{2,4}(?:[-/][a-z0-9]{1,8})?(?![a-z0-9])",
        value,
    ))
    has_vehicle_year = bool(
        re.search(r"\b(?:19\d{2}|20\d{2})\b", value)
        and re.search(
            r"\b(?:f[- ]?1?50|f[- ]?250|f[- ]?350|f[- ]?450|f[- ]?550|"
            r"silverado|sierra|ram|tundra|tacoma|q50|q60|wrangler|gladiator|"
            r"expedition|navigator|mustang|camaro|challenger|charger)\b",
            value,
        )
    )
    return bool(has_fact_intent or has_model_code or has_vehicle_year)


def _product_library_prompt_requests_images(prompt):
    """Detect natural requests for Product Library visual assets."""
    value = re.sub(r"\s+", " ", str(prompt or "")).strip().lower()
    if not value:
        return False

    image_words = (
        "photo", "photos", "picture", "pictures", "image", "images",
        "show me", "display", "view", "look like", "what does",
        "front", "rear", "back", "side", "installed", "screen on",
        "screen off", "mainboard", "motherboard", "pcb", "canbus",
        "can box", "decoder", "harness", "cable", "connector",
        "wiring", "pinout", "camera", "microphone", "gps", "usb",
        "antenna", "sim slot", "ports", "part", "parts",
        "accessory", "accessories", "included items", "included parts",
    )
    return any(word in value for word in image_words)


