def _product_library_normalize_followup_phrase(prompt):
    """Normalize natural Product Library follow-ups that refer to the current model."""
    value = re.sub(r"\s+", " ", str(prompt or "")).strip().lower()
    if not value:
        return ""

    # Staff often refer to the remembered Product Library record indirectly.
    # Remove those references so commands such as
    # "show me all photo of this model" normalize to "show me all photo".
    value = re.sub(
        r"\b(?:of|for)\s+(?:this|the|same)\s+"
        r"(?:model|unit|screen|radio|product|one)\b",
        "",
        value,
    )
    value = re.sub(
        r"\b(?:this|the|same)\s+"
        r"(?:model|unit|screen|radio|product|one)\b",
        "",
        value,
    )
    value = re.sub(r"\s+", " ", value).strip(" .,:;!?-")
    return value


def _product_library_is_asset_refinement_followup(prompt):
    """Detect natural short commands that refine the previous product gallery."""
    value = _product_library_normalize_followup_phrase(prompt)
    if not value:
        return False

    # These commands intentionally work without repeating the model number after
    # a verified Product Library product has already been selected.
    exact_commands = {
        "photo", "photos", "image", "images", "all", "all photo", "all photos",
        "all image", "all images", "show all", "show all photo",
        "show all photos", "show all image", "show all images",
        "show photo", "show photos", "show image", "show images",
        "show me all", "show me all photo", "show me all photos",
        "show me all image", "show me all images", "show them all",
        "show every photo", "show every image",
        "front", "rear", "back", "left", "right", "installed",
        "screen on", "screen off", "packaging", "package",
        "part", "parts", "accessory", "accessories", "kit",
        "mainboard", "motherboard", "pcb", "canbus", "can bus",
        "harness", "wiring", "usb", "gps", "wifi", "wi-fi",
        "sim", "microphone", "mic", "camera", "lvds", "power cable",
        "pinout", "ports", "connector", "connectors",
    }
    if value in exact_commands:
        return True

    refinement_phrases = (
        "only parts", "parts only", "part only", "only accessories",
        "accessories only", "only front", "front only", "only rear",
        "rear only", "back only", "only left", "left only",
        "only right", "right only", "only installed", "installed only",
        "only harness", "harness only", "only canbus", "canbus only",
        "only wiring", "wiring only", "only camera", "camera only",
        "only microphone", "microphone only", "only gps", "gps only",
        "only usb", "usb only", "only mainboard", "mainboard only",
        "front photo", "front photos", "rear photo", "rear photos",
        "left photo", "left photos", "right photo", "right photos",
        "show front", "show rear", "show left", "show right",
        "show parts", "show accessories", "show harness", "show canbus",
    )
    return any(phrase in value for phrase in refinement_phrases)


def _product_library_requests_all_photos(prompt):
    """Return True when a follow-up asks to restore every photo for the product."""
    value = _product_library_normalize_followup_phrase(prompt)
    return value in {
        "photo", "photos", "image", "images", "all", "all photo", "all photos",
        "all image", "all images", "show all", "show all photo",
        "show all photos", "show all image", "show all images",
        "show photo", "show photos", "show image", "show images",
        "show me all", "show me all photo", "show me all photos",
        "show me all image", "show me all images", "show them all",
        "show every photo", "show every image",
    }


def _product_library_parts_only_requested(prompt):
    """Return True when the user wants only included-parts/accessory images."""
    value = _product_library_normalize_followup_phrase(prompt)
    return any(phrase in value for phrase in (
        "only parts", "parts only", "part only", "only accessories",
        "accessories only", "parts photo", "parts photos", "part photo",
        "part photos", "included parts", "included accessories",
    ))


def _product_library_requested_subtypes(prompt):
    """Return ordered subtype intents inferred from the user's wording."""
    value = _product_library_normalize_followup_phrase(prompt)
    if not value:
        return []

    matches = []
    for subtype, phrases in PRODUCT_LIBRARY_ASSET_INTENTS.items():
        best_position = None
        for phrase in phrases:
            position = value.find(phrase)
            if position >= 0 and (best_position is None or position < best_position):
                best_position = position
        if best_position is not None:
            matches.append((best_position, subtype))

    matches.sort(key=lambda item: item[0])
    return [subtype for _, subtype in matches]


def _product_library_asset_relevance(asset, requested_subtypes):
    """Score one image asset against requested subtype intent and legacy metadata."""
    asset = asset or {}
    subtype = str(asset.get("asset_subtype") or "").strip().lower()
    asset_type = str(asset.get("asset_type") or "").strip().lower()
    filename = str(
        asset.get("original_filename")
        or asset.get("optimized_filename")
        or ""
    ).strip().lower().replace("_", " ").replace("-", " ")

    score = 0
    if requested_subtypes:
        for index, requested in enumerate(requested_subtypes):
            if subtype == requested:
                score = max(score, 300 - index)
            elif requested == "accessories" and asset_type == "parts_photo":
                # A generic "only parts" follow-up means every Parts Photo,
                # even when individual files are classified as harness/CANBUS/etc.
                score = max(score, 260 - index)
            elif requested.replace("_", " ") in filename:
                score = max(score, 220 - index)

        # Legacy files may not yet have subtype metadata. Apply conservative
        # filename synonyms only within the already-matched product.
        for requested in requested_subtypes:
            for phrase in PRODUCT_LIBRARY_ASSET_INTENTS.get(requested, ()):
                if phrase in filename:
                    score = max(score, 180)

    if asset_type in {"product_photo", "parts_photo"}:
        score += 20
    if subtype and subtype != "other":
        score += 5
    return score


def _product_library_product_score(product, prompt):
    """Score product-code, vehicle, year, system, size, and alias matches."""
    value = re.sub(r"\s+", " ", str(prompt or "")).strip().casefold()
    if not value:
        return 0

    code = str(product.get("product_code") or "").strip().casefold()
    name = str(product.get("product_name") or "").strip().casefold()
    compatibility = str(
        product.get("vehicle_compatibility") or ""
    ).strip().casefold()
    description = str(product.get("description") or "").strip().casefold()
    aliases = [
        str(item).strip().casefold()
        for item in (product.get("aliases") or [])
        if str(item).strip()
    ]

    score = 0

    # A product-code request is considered decisive.
    if code and re.search(
        rf"(?<![a-z0-9]){re.escape(code)}(?![a-z0-9])",
        value,
    ):
        score += 200

    if name and name in value:
        score += 80

    for alias in aliases:
        if alias and alias in value:
            score += 70

    searchable = " ".join(
        [code, name, compatibility, description, *aliases]
    )
    prompt_tokens = {
        token
        for token in re.findall(r"[a-z0-9][a-z0-9._/-]*", value)
        if len(token) >= 2
    }

    important_terms = {
        "sync", "f150", "f250", "f350", "f450", "f550",
        "silverado", "sierra", "ram", "qhd", "manual", "auto",
        "android", "tesla", "inch",
    }

    for token in prompt_tokens:
        if token in searchable:
            score += 8 if token in important_terms else 4

    # Match a requested vehicle year against compatibility ranges such as
    # 2015-2021, including common Unicode dash variants.
    requested_years = {
        int(year)
        for year in re.findall(r"\b(19\d{2}|20\d{2})\b", value)
    }
    normalized_searchable = (
        searchable.replace("–", "-").replace("—", "-").replace("−", "-")
    )
    product_years = {
        int(year)
        for year in re.findall(r"\b(19\d{2}|20\d{2})\b", normalized_searchable)
    }
    year_ranges = [
        (int(start), int(end))
        for start, end in re.findall(
            r"\b(19\d{2}|20\d{2})\s*-\s*(19\d{2}|20\d{2})\b",
            normalized_searchable,
        )
    ]

    for requested_year in requested_years:
        if requested_year in product_years:
            score += 20
        elif any(
            min(start, end) <= requested_year <= max(start, end)
            for start, end in year_ranges
        ):
            score += 20

    # Screen-size phrases are strong disambiguators.
    requested_sizes = re.findall(
        r"\b(\d{2}(?:\.\d)?)\s*(?:inch|inches|in|\\?[\"])\b",
        value,
    )
    for size in requested_sizes:
        if size in searchable:
            score += 25

    return score


def _product_library_candidate_label(product):
    """Build a concise human-readable candidate label."""
    code = str(product.get("product_code") or "Unknown code").strip()
    name = str(product.get("product_name") or "Unnamed product").strip()
    compatibility = str(
        product.get("vehicle_compatibility") or ""
    ).strip()
    description = str(product.get("description") or "").strip()

    details = compatibility or description
    details = re.sub(r"\s+", " ", details)
    if len(details) > 120:
        details = details[:117].rstrip() + "..."

    return f"{code} — {name}" + (f" — {details}" if details else "")


def _product_library_pending_candidates():
    value = st.session_state.get("product_library_pending_candidates")
    return value if isinstance(value, list) else []


def _product_library_candidate_facets(candidate):
    """Return normalized selection facets for one Product Library candidate.

    Older Product Library rows do not always store screen size and factory system in
    dedicated columns. Infer the well-established AutoTecPro code conventions as a
    fallback so clarification replies such as ``SYNC 1`` followed by ``14.4`` can
    resolve deterministically without asking for a final option number.
    """
    aliases = candidate.get("aliases") or []
    if not isinstance(aliases, list):
        aliases = [aliases]

    code = str(candidate.get("product_code") or "").strip()
    values = [
        code,
        candidate.get("product_name"),
        candidate.get("vehicle_compatibility"),
        candidate.get("description"),
        *aliases,
    ]
    joined = " ".join(str(item or "") for item in values).casefold()
    normalized = re.sub(r"[^a-z0-9.]+", " ", joined).strip()
    compact = _product_library_normalize_code(joined)
    code_compact = _product_library_normalize_code(code)

    sync_versions = set()
    for match in re.findall(r"\bsync\s*([123])\b", normalized):
        sync_versions.add(match)
    # AutoTecPro Ford 732 family conventions: QS1/S2/S3 map to SYNC 1/2/3.
    if re.search(r"(?:^|pro)qs1$", code_compact) or code_compact.endswith("qs1"):
        sync_versions.add("1")
    if code_compact.endswith("s2"):
        sync_versions.add("2")
    if code_compact.endswith("s3"):
        sync_versions.add("3")

    screen_sizes = set(re.findall(r"\b(\d{2}(?:\.\d)?)\s*(?:inch|inches|in|\")?\b", normalized))
    # Product-code fallback for the Ford 732 family.
    if code_compact.startswith("732pro"):
        screen_sizes.add("17")
    elif code_compact.startswith("732"):
        screen_sizes.add("14.4")

    climate_terms = set()
    if re.search(r"\bmanual\s*(?:a/?c|ac|climate)\b", normalized):
        climate_terms.add("manual")
    if re.search(r"\bauto(?:matic)?\s*(?:a/?c|ac|climate)\b", normalized):
        climate_terms.add("automatic")

    return {
        "normalized": normalized,
        "compact": compact,
        "sync_versions": sync_versions,
        "screen_sizes": screen_sizes,
        "climate_terms": climate_terms,
    }


def _product_library_reply_facets(prompt):
    """Extract only explicit clarification facets from a short user reply."""
    value = re.sub(r"\s+", " ", str(prompt or "")).strip().casefold()
    normalized = re.sub(r"[^a-z0-9.]+", " ", value).strip()

    sync_versions = set(re.findall(r"\bsync\s*([123])\b", normalized))
    if not sync_versions:
        compact = re.sub(r"[^a-z0-9]+", "", value)
        compact_match = re.search(r"sync([123])", compact)
        if compact_match:
            sync_versions.add(compact_match.group(1))

    screen_sizes = set()
    for match in re.findall(r"(?<!\d)(\d{2}(?:\.\d)?)(?!\d)", value):
        if match in {"14.4", "17", "12.1", "13.8", "15.6", "17.2"}:
            screen_sizes.add(match)

    climate_terms = set()
    if re.search(r"\bmanual\s*(?:a/?c|ac|climate)?\b", normalized):
        climate_terms.add("manual")
    if re.search(r"\bauto(?:matic)?\s*(?:a/?c|ac|climate)?\b", normalized):
        climate_terms.add("automatic")

    return {
        "sync_versions": sync_versions,
        "screen_sizes": screen_sizes,
        "climate_terms": climate_terms,
    }


def _product_library_resolve_pending_selection(prompt):
    """Resolve a clarification reply and auto-open once one product remains.

    The narrowed candidate list is preserved between turns. Factory-system and
    screen-size replies are applied as structured facets, including Product Library
    rows that rely on AutoTecPro product-code conventions instead of dedicated
    metadata fields. As soon as one verified candidate remains, it is returned to
    the normal image lookup in the same turn—no final option-number confirmation.
    """
    candidates = _product_library_pending_candidates()
    if not candidates:
        return None

    value = re.sub(r"\s+", " ", str(prompt or "")).strip()
    lowered = value.casefold()

    if lowered in {"cancel", "none", "neither", "start over"}:
        st.session_state.pop("product_library_pending_candidates", None)
        st.session_state.pop("product_library_pending_filters", None)
        return {"cancelled": True}

    number_match = re.fullmatch(r"(?:option\s*)?(\d{1,2})", lowered)
    if number_match:
        selected_index = int(number_match.group(1)) - 1
        if 0 <= selected_index < len(candidates):
            selected = candidates[selected_index]
            st.session_state.pop("product_library_pending_candidates", None)
            st.session_state.pop("product_library_pending_filters", None)
            return {"product": selected}

    normalized_reply = _product_library_normalize_code(value)
    for candidate in candidates:
        if normalized_reply == _product_library_normalize_code(candidate.get("product_code")):
            st.session_state.pop("product_library_pending_candidates", None)
            st.session_state.pop("product_library_pending_filters", None)
            return {"product": candidate}

    reply_facets = _product_library_reply_facets(value)
    previous_filters = st.session_state.get("product_library_pending_filters")
    if not isinstance(previous_filters, dict):
        previous_filters = {}
    cumulative = {
        "sync_versions": set(previous_filters.get("sync_versions") or []),
        "screen_sizes": set(previous_filters.get("screen_sizes") or []),
        "climate_terms": set(previous_filters.get("climate_terms") or []),
    }
    for key in cumulative:
        cumulative[key].update(reply_facets.get(key) or set())

    has_structured_facets = any(cumulative.values())
    filtered = []
    if has_structured_facets:
        for candidate in candidates:
            facets = _product_library_candidate_facets(candidate)
            if cumulative["sync_versions"] and not (
                cumulative["sync_versions"] & facets["sync_versions"]
            ):
                continue
            if cumulative["screen_sizes"] and not (
                cumulative["screen_sizes"] & facets["screen_sizes"]
            ):
                continue
            if cumulative["climate_terms"] and not (
                cumulative["climate_terms"] & facets["climate_terms"]
            ):
                continue
            filtered.append(candidate)

    # Preserve legacy natural text matching for aliases or model wording that is not
    # represented by the structured facets above.
    if not has_structured_facets:
        normalized_text = re.sub(r"[^a-z0-9.]+", " ", lowered).strip()
        compact_text = _product_library_normalize_code(value)
        reply_tokens = [token for token in normalized_text.split() if token]
        for candidate in candidates:
            facets = _product_library_candidate_facets(candidate)
            token_match = bool(reply_tokens) and all(
                token in facets["normalized"] or token in facets["compact"]
                for token in reply_tokens
            )
            compact_match = bool(compact_text) and compact_text in facets["compact"]
            if token_match or compact_match:
                filtered.append(candidate)

    if len(filtered) == 1:
        selected = filtered[0]
        st.session_state.pop("product_library_pending_candidates", None)
        st.session_state.pop("product_library_pending_filters", None)
        return {"product": selected, "auto_resolved": True}

    if len(filtered) > 1:
        st.session_state["product_library_pending_candidates"] = filtered
        st.session_state["product_library_pending_filters"] = {
            key: sorted(values) for key, values in cumulative.items()
        }
        return {
            "clarification": True,
            "candidates": filtered,
            "narrowed": True,
        }

    if len(value) <= 40:
        return {
            "clarification": True,
            "candidates": candidates,
            "invalid_selection": True,
        }

    st.session_state.pop("product_library_pending_candidates", None)
    st.session_state.pop("product_library_pending_filters", None)
    return None



def _product_library_normalize_code(value):
    """Normalize human-entered/stored product codes for reliable matching."""
    clean = str(value or "").strip().casefold()
    clean = clean.replace("–", "-").replace("—", "-").replace("−", "-")
    return re.sub(r"[^a-z0-9]+", "", clean)


@st.cache_data(ttl=60, max_entries=4, show_spinner=False)
def _product_library_cached_products():
    """Cache the bounded Product Library catalogue used by chat lookup."""
    database = get_supabase_admin_client()
    return (
        database.table("product_library")
        .select(
            "id,product_code,product_name,vehicle_compatibility,"
            "description,aliases,active,updated_at"
        )
        .limit(1000)
        .execute().data
        or []
    )


@st.cache_data(ttl=60, max_entries=256, show_spinner=False)
def _product_library_cached_assets(product_code, product_id):
    """Return every asset belonging to one product, including legacy rows.

    Product Library records created at different times may differ in product-code
    capitalization/punctuation or may contain only product_id. Therefore, exact
    product_code and product_id query results are always merged. A bounded legacy
    scan is then used to recover rows whose normalized code or storage-path root
    matches the selected product. Results are deduplicated and sorted once.
    """
    database = get_supabase_admin_client()
    asset_columns = (
        "id,product_id,product_code,asset_type,asset_subtype,original_filename,"
        "optimized_filename,content_type,storage_bucket,storage_path,"
        "storage_status,archive_status,archive_file_id,archive_web_url,created_at"
    )

    clean_code = str(product_code or "").strip()
    clean_id = str(product_id or "").strip()
    normalized_code = _product_library_normalize_code(clean_code)
    collected = []
    used_legacy_scan = False

    def add_rows(rows):
        for row in rows or []:
            if isinstance(row, dict):
                collected.append(row)

    # Always run and merge both indexed lookups. Previously the product_id query
    # was skipped as soon as any exact-code rows existed, which hid newer assets
    # saved under a differently cased/legacy product_code.
    if clean_code:
        add_rows(
            database.table("product_assets")
            .select(asset_columns)
            .eq("product_code", clean_code)
            .order("created_at", desc=False)
            .limit(500)
            .execute().data
            or []
        )

    if clean_id:
        add_rows(
            database.table("product_assets")
            .select(asset_columns)
            .eq("product_id", clean_id)
            .order("created_at", desc=False)
            .limit(500)
            .execute().data
            or []
        )

    # A normalized scan is still required because Supabase equality matching is
    # case-sensitive and older rows may have missing/incorrect product_id values.
    # Keep it bounded to protect performance.
    if normalized_code:
        all_assets = (
            database.table("product_assets")
            .select(asset_columns)
            .order("created_at", desc=False)
            .limit(5000)
            .execute().data
            or []
        )
        used_legacy_scan = True

        for asset in all_assets:
            asset_code = _product_library_normalize_code(asset.get("product_code"))
            asset_product_id = str(asset.get("product_id") or "").strip()
            storage_path = str(asset.get("storage_path") or "").strip().lstrip("/")
            path_root = _product_library_normalize_code(
                storage_path.split("/", 1)[0] if storage_path else ""
            )
            if (
                (asset_code and asset_code == normalized_code)
                or (clean_id and asset_product_id == clean_id)
                or (path_root and path_root == normalized_code)
            ):
                collected.append(asset)

    # Prefer the database id. For malformed legacy rows without id, use a stable
    # composite key so the same image is never rendered twice.
    deduplicated = {}
    for asset in collected:
        asset_id = str(asset.get("id") or "").strip()
        fallback_key = "|".join([
            str(asset.get("product_id") or "").strip(),
            _product_library_normalize_code(asset.get("product_code")),
            str(asset.get("storage_path") or "").strip(),
            str(asset.get("original_filename") or "").strip(),
        ])
        key = f"id:{asset_id}" if asset_id else f"legacy:{fallback_key}"
        deduplicated[key] = asset

    assets = list(deduplicated.values())
    assets.sort(key=lambda row: str(row.get("created_at") or ""))
    return assets, used_legacy_scan


def _product_library_clear_read_caches():
    """Clear Product Library read caches after any mutation."""
    _product_library_cached_products.clear()
    _product_library_cached_assets.clear()
    _product_library_dashboard_data.clear()


def _product_library_fact_lookup(prompt):
    """
    Resolve one authoritative Product Library record for normal product-fact queries.

    This lookup never loads images and never interrupts the existing vector-store
    flow. Ambiguous broad matches return no Product Library result so the normal
    workspace vector stores remain the fallback source.
    """
    if not _product_library_prompt_requests_facts(prompt):
        return None

    products = [
        product for product in (_product_library_cached_products() or [])
        if product.get("active") is not False
    ]
    ranked = sorted(
        (
            (_product_library_product_score(product, prompt), product)
            for product in products
        ),
        key=lambda item: (
            item[0],
            str(item[1].get("updated_at") or ""),
        ),
        reverse=True,
    )
    ranked = [item for item in ranked if item[0] > 0]
    if not ranked:
        return None

    top_score, top_product = ranked[0]
    exact_code_match = top_score >= 200

    # Require a meaningful match. Exact codes are decisive. Natural-language
    # compatibility queries need a stronger score than incidental token overlap.
    minimum_score = 12 if exact_code_match else 24
    if top_score < minimum_score:
        return None

    # Do not inject a possibly wrong structured record when two products are nearly
    # tied. In that case, preserve the existing vector-store answer flow.
    if not exact_code_match and len(ranked) > 1:
        second_score = ranked[1][0]
        if second_score >= max(minimum_score, top_score - 8):
            return None

    return {
        "product": top_product,
        "score": top_score,
        "source": "product_library_fact_lookup",
        "images": [],
        "assets": [],
        "requested_subtypes": [],
        "fact_only": True,
    }



def _product_library_explicit_product_matches(prompt, products):
    """Return products explicitly named in the current message.

    This check runs before remembered-product follow-up handling, so a command such
    as "front photo of 861-Pro" switches the active product instead of incorrectly
    applying the filter to the previous model.
    """
    raw_value = re.sub(r"\s+", " ", str(prompt or "")).strip().casefold()
    compact_value = _product_library_normalize_code(raw_value)
    if not raw_value or not compact_value:
        return []

    matches = []
    for product in products or []:
        code = str(product.get("product_code") or "").strip()
        aliases = product.get("aliases") or []
        if not isinstance(aliases, list):
            aliases = [aliases]

        identifiers = [code, *[str(alias or "").strip() for alias in aliases]]
        identifier_matches = []
        for identifier in identifiers:
            normalized = _product_library_normalize_code(identifier)
            if len(normalized) < 3:
                continue
            if normalized in compact_value:
                identifier_matches.append(len(normalized))

        if identifier_matches:
            matches.append((max(identifier_matches), product))

    if not matches:
        return []

    # Prefer the most specific code/alias. This prevents a base code such as 732
    # from competing with a longer explicit code such as 732Pro-S3.
    longest = max(length for length, _ in matches)
    deduplicated = {}
    for length, product in matches:
        if length != longest:
            continue
        key = str(product.get("id") or product.get("product_code") or "").strip()
        if key:
            deduplicated[key] = product
    return list(deduplicated.values())

def _product_library_chat_lookup(prompt, max_images=None):
    """
    Resolve Product Library photo requests.

    Exact product codes open immediately. Broad vehicle requests with multiple
    credible matches return a clarification list and remember those candidates,
    allowing the user to reply with a number or product code.
    """
    pending_result = _product_library_resolve_pending_selection(prompt)
    last_product = st.session_state.get("product_library_last_product")
    active_products = [
        product for product in (_product_library_cached_products() or [])
        if product.get("active") is not False
    ]
    explicit_products = _product_library_explicit_product_matches(
        prompt,
        active_products,
    )

    # An explicitly named model always replaces the remembered model, including
    # combined requests such as "front photo of 861-Pro".
    if len(explicit_products) == 1:
        st.session_state.pop("product_library_pending_candidates", None)
        product = explicit_products[0]
    elif len(explicit_products) > 1:
        st.session_state["product_library_pending_candidates"] = explicit_products[:8]
        st.session_state.pop("product_library_pending_filters", None)
        return {
            "clarification": True,
            "candidates": explicit_products[:8],
            "images": [],
        }
    # Support natural follow-ups such as "only parts" after a product gallery.
    # Reuse only the last verified Product Library product when the current
    # message does not explicitly name a different product.
    elif (
        not pending_result
        and _product_library_is_asset_refinement_followup(prompt)
        and isinstance(last_product, dict)
        and last_product.get("product_code")
    ):
        product = last_product
    elif pending_result:
        if pending_result.get("cancelled"):
            return {
                "cancelled": True,
                "images": [],
            }
        if pending_result.get("clarification"):
            return pending_result
        product = pending_result.get("product")
    else:
        if not _product_library_prompt_requests_images(prompt):
            return None

        ranked = sorted(
            (
                (_product_library_product_score(product, prompt), product)
                for product in active_products
            ),
            key=lambda item: (
                item[0],
                str(item[1].get("updated_at") or ""),
            ),
            reverse=True,
        )
        ranked = [item for item in ranked if item[0] > 0]
        if not ranked or ranked[0][0] < 12:
            return None

        top_score = ranked[0][0]
        exact_code_match = top_score >= 200

        # Keep candidates close to the best score. A broad vehicle/year query
        # can legitimately match multiple systems or screen sizes.
        candidate_floor = max(12, top_score - 12)
        candidates = [
            product
            for score, product in ranked
            if score >= candidate_floor
        ][:8]

        if not exact_code_match and len(candidates) > 1:
            st.session_state["product_library_pending_candidates"] = candidates
            st.session_state.pop("product_library_pending_filters", None)
            return {
                "clarification": True,
                "candidates": candidates,
                "images": [],
            }

        product = ranked[0][1]

    if isinstance(product, dict) and product.get("product_code"):
        st.session_state["product_library_last_product"] = dict(product)

    product_code = str(product.get("product_code") or "").strip()
    normalized_code = _product_library_normalize_code(product_code)
    product_id = str(product.get("id") or "").strip()

    assets, used_legacy_scan = _product_library_cached_assets(
        product_code,
        product_id,
    )

    def _is_display_image_asset(asset):
        storage_path = str(asset.get("storage_path") or "").strip()
        if not storage_path:
            return False

        content_type = str(asset.get("content_type") or "").strip().lower()
        optimized_name = str(
            asset.get("optimized_filename")
            or Path(storage_path).name
            or ""
        ).strip().lower()
        storage_status = str(
            asset.get("storage_status") or ""
        ).strip().lower()

        failed_statuses = {
            "failed", "error", "missing", "deleted", "unavailable", "removed"
        }
        return (
            content_type.startswith("image/")
            or optimized_name.endswith((".jpg", ".jpeg", ".png", ".webp"))
        ) and storage_status not in failed_statuses

    image_assets = [
        asset for asset in assets
        if _is_display_image_asset(asset)
    ]

    # A generic follow-up such as "photo" or "all" means restore every
    # available display image for the currently selected product. It must not be
    # narrowed by accidental words from the earlier request.
    all_photos_requested = _product_library_requests_all_photos(prompt)
    requested_subtypes = (
        [] if all_photos_requested
        else _product_library_requested_subtypes(prompt)
    )

    preferred_types = {
        "parts_photo",
        "product_photo",
        "parts",
        "photo",
        "product_photos",
    }
    preferred = [
        asset for asset in image_assets
        if str(asset.get("asset_type") or "").strip().lower()
        in preferred_types
    ]

    parts_only_requested = _product_library_parts_only_requested(prompt)
    if parts_only_requested:
        parts_assets = [
            asset for asset in image_assets
            if str(asset.get("asset_type") or "").strip().lower() == "parts_photo"
            or str(asset.get("asset_subtype") or "").strip().lower() == "accessories"
        ]
        candidate_assets = parts_assets
    else:
        candidate_assets = preferred or image_assets

    # By default, return every verified matching image. A caller may still pass an
    # explicit positive max_images value for a future constrained view, but the chat
    # gallery itself must not silently stop at six images.
    try:
        image_limit = int(max_images) if max_images is not None else None
    except (TypeError, ValueError):
        image_limit = None
    if image_limit is not None and image_limit <= 0:
        image_limit = None

    if requested_subtypes:
        ranked_assets = sorted(
            (
                (_product_library_asset_relevance(asset, requested_subtypes), asset)
                for asset in candidate_assets
            ),
            key=lambda item: (
                item[0],
                str(item[1].get("created_at") or ""),
            ),
            reverse=True,
        )
        relevant_assets = [asset for score, asset in ranked_assets if score >= 180]
        selected = (
            relevant_assets[:image_limit]
            if image_limit is not None
            else relevant_assets
        )
    elif all_photos_requested:
        # The user explicitly asked for all photos for the remembered model.
        selected = list(candidate_assets)
    else:
        selected = (
            candidate_assets[:image_limit]
            if image_limit is not None
            else list(candidate_assets)
        )

    images = []
    for asset in selected:
        image_source = _product_library_asset_data_url(asset)

        # The Manage Products page already uses this signed URL successfully,
        # so use it as a direct browser-display fallback.
        if not image_source:
            image_source = _product_library_signed_url(
                asset.get("storage_path"),
                expires=86400,
            )

        if image_source:
            images.append({
                "name": str(
                    asset.get("original_filename")
                    or asset.get("optimized_filename")
                    or "Product Library image"
                ),
                "data_url": image_source,
                "generated": False,
                "source": "product_library",
                "asset_type": str(asset.get("asset_type") or "other"),
                "asset_subtype": str(asset.get("asset_subtype") or ""),
                "storage_path": str(asset.get("storage_path") or ""),
                "content_type": str(asset.get("content_type") or "image/jpeg"),
                "archive_web_url": str(asset.get("archive_web_url") or ""),
            })

    diagnostic_log(
        "product_library_chat_lookup_result",
        product_code=product_code,
        normalized_code=normalized_code,
        matched_assets_found=len(assets),
        used_legacy_scan=used_legacy_scan,
        image_assets_found=len(image_assets),
        requested_subtypes=",".join(requested_subtypes),
        selected_assets=len(selected),
        images_loaded=len(images),
    )

    return {
        "product": product,
        "assets": selected,
        "images": images,
        "requested_subtypes": requested_subtypes,
    }

def _product_library_chat_context(lookup):
    if not isinstance(lookup, dict):
        return ""

    if lookup.get("cancelled"):
        return (
            "\n\nPRODUCT LIBRARY CLARIFICATION CANCELLED:\n"
            "Confirm briefly that the product-photo selection was cancelled."
        )

    if lookup.get("clarification"):
        candidates = lookup.get("candidates") or []
        candidate_lines = [
            f"{index}. {_product_library_candidate_label(product)}"
            for index, product in enumerate(candidates, start=1)
        ]
        invalid_note = (
            "The user's last selection was not valid. "
            if lookup.get("invalid_selection")
            else ""
        )
        return (
            "\n\nPRODUCT LIBRARY CLARIFICATION REQUIRED:\n"
            f"{invalid_note}"
            f"I found {len(candidates)} possible matching products.\n"
            + "\n".join(candidate_lines)
            + "\nAsk the user to reply with the number or product code. "
              "Do not select a product, show photos, or add unrelated technical "
              "details until the user confirms."
        )

    if not lookup.get("product"):
        return ""

    product = lookup["product"]
    asset_names = [
        _product_library_asset_heading(asset)
        for asset in lookup.get("assets") or []
    ]
    requested_subtypes = [
        PRODUCT_ASSET_SUBTYPE_LABELS.get(value, value.replace("_", " ").title())
        for value in (lookup.get("requested_subtypes") or [])
    ]
    fact_only = bool(lookup.get("fact_only"))
    compatibility = str(product.get("vehicle_compatibility") or "").strip()
    description = str(product.get("description") or "").strip()

    if fact_only:
        return (
            "\n\nVERIFIED PRODUCT LIBRARY FACT RESULT (server-side Supabase lookup):\n"
            f"Product code: {product.get('product_code')}\n"
            f"Product name: {product.get('product_name')}\n"
            f"Compatibility: {compatibility or 'Not specified'}\n"
            f"Description: {description or 'Not specified'}\n"
            "SOURCE PRIORITY RULES:\n"
            "- Treat Product Library product code, product name, aliases, and any "
            "explicitly populated compatibility or description facts as the current "
            "structured source of truth.\n"
            "- Continue using the workspace vector store search for missing details, "
            "procedures, troubleshooting, installation guidance, limitations, and "
            "other supporting knowledge.\n"
            "- If Compatibility is 'Not specified', do not interpret that as "
            "incompatible; use verified vector-store knowledge and clearly identify "
            "the supporting source.\n"
            "- If a vector-store result conflicts with an explicitly populated "
            "Product Library field, follow Product Library for that structured field "
            "and mention the conflict instead of guessing."
        )

    return (
        "\n\nVERIFIED PRODUCT LIBRARY RESULT (server-side Supabase lookup):\n"
        f"Product code: {product.get('product_code')}\n"
        f"Product name: {product.get('product_name')}\n"
        f"Compatibility: {compatibility or 'Not specified'}\n"
        f"Description: {description or 'Not specified'}\n"
        f"Requested asset detail: "
        f"{', '.join(requested_subtypes) if requested_subtypes else 'General product photos'}\n"
        f"Matching image files found: "
        f"{', '.join(asset_names) if asset_names else 'None'}\n"
        f"Images successfully loaded for chat display: "
        f"{len(lookup.get('images') or [])}\n"
        "Tell the user only what this verified record supports. If the "
        "loaded-image count is greater than zero, state that the matching "
        "photos are displayed below the answer. Do not say the app cannot "
        "display them. Continue using vector-store knowledge for missing "
        "non-image details."
    )



def _product_library_upsert_product(product_code, product_name, compatibility, description, aliases, active=True):
    payload = {
        "product_code": product_code,
        "product_name": product_name,
        "vehicle_compatibility": compatibility,
        "description": description,
        "aliases": aliases,
        "active": bool(active),
        "updated_by": str(st.session_state.get("username") or ""),
        "updated_at": datetime.now(timezone.utc).isoformat(),
    }
    existing = (
        supabase.table("product_library")
        .select("id")
        .eq("product_code", product_code)
        .limit(1)
        .execute()
        .data
        or []
    )
    if existing:
        result = (
            supabase.table("product_library")
            .update(payload)
            .eq("id", existing[0]["id"])
            .execute()
        )
        return (result.data or [existing[0]])[0]
    result = supabase.table("product_library").insert(payload).execute()
    return (result.data or [None])[0]


def _product_library_upload_asset(product, asset_type, uploaded_file, asset_subtype="other"):
    product_code = str(product.get("product_code") or "")
    product_id = product.get("id")
    clean_subtype = str(asset_subtype or "other").strip().lower()
    if clean_subtype not in _product_library_subtype_options(asset_type):
        clean_subtype = "other"
    filename = _product_library_safe_filename(uploaded_file.name)
    original = uploaded_file.getvalue()
    content_type = str(uploaded_file.type or "application/octet-stream")
    if len(original) > PRODUCT_LIBRARY_MAX_ORIGINAL_BYTES:
        raise RuntimeError(f"{filename} exceeds the 20 MB Product Library limit.")

    archive_status = "not_configured"
    archive_file_id = ""
    archive_web_url = ""
    if _product_library_google_configured():
        product_folder = _product_library_drive_create_folder(product_code, GOOGLE_DRIVE_ROOT_FOLDER_ID)
        category_folder = _product_library_drive_create_folder(
            PRODUCT_ASSET_LABELS.get(asset_type, "Other"), product_folder["id"]
        )
        subtype_folder = _product_library_drive_create_folder(
            PRODUCT_ASSET_SUBTYPE_LABELS.get(clean_subtype, "Other"),
            category_folder["id"],
        )
        drive_file = _product_library_drive_upload_bytes(
            filename, content_type, original, subtype_folder["id"]
        )
        archive_status = "available"
        archive_file_id = str(drive_file.get("id") or "")
        archive_web_url = str(drive_file.get("webViewLink") or "")

    optimized_filename = ""
    optimized_bytes = 0
    storage_path = ""
    storage_status = "not_applicable"
    if content_type.startswith("image/"):
        optimized, optimized_filename, optimized_type = _product_library_optimize_image(
            original, filename, PRODUCT_LIBRARY_DISPLAY_MAX_PX
        )
        digest = hashlib.sha256(original).hexdigest()[:16]
        storage_path = f"{product_code}/{asset_type}/{clean_subtype}/{digest}-{optimized_filename}"
        _product_library_storage_upload(storage_path, optimized, optimized_type)
        optimized_bytes = len(optimized)
        storage_status = "available"

    record = {
        "product_id": product_id,
        "product_code": product_code,
        "asset_type": asset_type,
        "asset_subtype": clean_subtype,
        "original_filename": filename,
        "original_bytes": len(original),
        "optimized_filename": optimized_filename,
        "optimized_bytes": optimized_bytes,
        "content_type": content_type,
        "storage_bucket": PRODUCT_LIBRARY_BUCKET if storage_path else "",
        "storage_path": storage_path,
        "storage_status": storage_status,
        "archive_provider": "google_drive" if _product_library_google_configured() else "none",
        "archive_status": archive_status,
        "archive_file_id": archive_file_id,
        "archive_web_url": archive_web_url,
        "uploaded_by": str(st.session_state.get("username") or ""),
    }
    result = supabase.table("product_assets").insert(record).execute()
    return (result.data or [record])[0]


@st.cache_data(ttl=30, show_spinner=False)
def _product_library_dashboard_data():
    products = supabase.table("product_library").select("id,active").execute().data or []
    assets = (
        supabase.table("product_assets")
        .select("id,optimized_bytes,storage_status,archive_status")
        .execute().data
        or []
    )
    return {
        "products": len(products),
        "active": sum(1 for row in products if row.get("active")),
        "assets": len(assets),
        "optimized_bytes": sum(int(row.get("optimized_bytes") or 0) for row in assets),
        "storage_missing": sum(1 for row in assets if row.get("storage_status") not in {"available", "not_applicable"}),
        "archive_missing": sum(1 for row in assets if row.get("archive_status") != "available"),
    }


def _product_library_format_bytes(value):
    size = float(value or 0)
    for unit in ("B", "KB", "MB", "GB", "TB"):
        if size < 1024 or unit == "TB":
            return f"{size:.1f} {unit}" if unit != "B" else f"{int(size)} B"
        size /= 1024


